-- Poems batch 318
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d116001d-113a-426e-8c06-0db5c24edb82','歸來引送王子立歸筠州','蘇軾','宋','宋诗','song-poetry','','[]','歸去來兮，世不汝求胡不歸。',271,'全唐诗/poet.song.46000.json','["歸去來兮，世不汝求胡不歸。", "洶北望之橫流兮，渺西顧之塵霏。", "紛野馬之决驟兮，幸余首之未鞿。", "出彭城而南騖兮，眷丘隴而增欷。", "亂清淮而俯鑒兮，驚昔容之是非。", "念東坡之遺老兮，輕千里而款余扉。", "共雪堂之清夜兮，攬明月之餘輝。", "曾雞黍之未熟兮，嘆空室之伊威。", "我挽袖而莫留兮，僕夫在門歌式微。", "歸去來兮，路渺渺其何極。", "將稅駕於何許兮，北江之南，南江之北。", "于此有人兮，儼峨峨其豐碩。", "孰居約而爾肥兮，非糠覈其何食。", "久抱一而不試兮，愈溫溫而自克。", "吾居世之荒浪兮，視昏昏而聽默默。", "非之子莫振吾過兮，久不見恐自賊。", "吾欲往而道無由兮，子何畏而不即。", "將以彼爲玉人兮，以子爲之璞也。"]'),
('b3aff07a-ffa3-4d36-aee5-817008423563','黄泥坂詞','蘇軾','宋','宋诗','song-poetry','','[]','出臨臯而東騖兮，並叢祠而北轉。',311,'全唐诗/poet.song.46000.json','["出臨臯而東騖兮，並叢祠而北轉。", "走雪堂之陂陀兮，歷黄泥之長坂。", "大江洶以左繚兮，渺雲濤之舒卷。", "草木層累而右附兮，蔚柯丘之葱蒨。", "余旦往而夕還兮，步徙倚而盤桓。", "雖信美而不可居兮，苟娛余于一眄。", "余幼好此奇服兮，襲前人之詭幻。", "老更變而自哂兮，悟驚俗之來患。", "釋寶璐而被繒絮兮，雜市人而無辨。", "路悠悠其莫往來兮，守一席而窮年。", "時游步而遠覽兮，路窮盡而旋反。", "朝嬉黄泥之白雲兮，暮宿雪堂之青烟。", "喜魚鳥之莫余驚兮，幸樵蘇之我嫚。", "初被酒以行歌兮，忽放杖而醉偃。", "草爲茵而塊爲枕兮，穆華堂之清宴。", "紛墜露之濕衣兮，升素月之團團。", "感父老之呼覺兮，恐牛羊之予踐。", "于是蹶然而起，起而歌曰。", "月明兮星稀，迎余往兮餞余歸。", "歲既宴兮草木腓，歸來歸來兮，黄泥不可以久嬉。"]'),
('eba9d794-3135-4596-a4dc-ff84cfc31a78','清溪詞','蘇軾','宋','宋诗','song-poetry','','[]','大江南兮九華西，泛秋浦兮亂清溪。',224,'全唐诗/poet.song.46000.json','["大江南兮九華西，泛秋浦兮亂清溪。", "水渺渺兮山無蹊，路重複兮居者迷。", "爛青紅兮粲高低，松十里兮稻千畦。", "山無人兮雲朝躋，靄濛濛兮渰凄凄。", "嘯林谷兮號水泥，走鼪鼯兮下鳧鷖。", "忽孤壘兮隠重堤，杳冥茫兮聞犬雞。", "鬰萬瓦兮鳥翼齊，浮軒楹兮飛棋枅。", "雁南歸兮寒蜩嘶，弄秋水兮挹玻璃。", "朝市合兮雜髦齯，挾簞瓢兮佩鋤犁。", "鳥獸散兮相扶携，隠驚雷兮騖長霓。", "望翠微兮古招提，掛木杪兮翔雲梯。", "若有人兮悵幽棲，石爲門兮雲爲閨。", "塊虛堂兮法喜妻，呼猿狙兮子鹿麛。", "我欲往兮奉杖藜，獨長嘯兮謝阮嵇。"]'),
('46ae4417-1f4b-4cbe-9b98-da87a7fc0ab1','上清詞','蘇軾','宋','宋诗','song-poetry','','[]','南山之幽，雲冥冥兮。',374,'全唐诗/poet.song.46000.json','["南山之幽，雲冥冥兮。", "孰居此者，帝側之神君。", "君胡爲兮山之幽，顧宮殿兮久淹留。", "又曷爲一朝去此而不顧兮，悲此空山之人也。", "來不可得而知兮，去固不可得而訊也。", "君之來兮天門空，從千騎兮駕飛龍。", "隸辰星兮役太歲，儼晝降兮雷隆隆。", "朝發軫兮帝庭，夕弭節兮山宮。", "懭有妖兮虐下土，精爲星兮氣爲虹。", "愛流血之滂沛兮，又嗜瘧癘與螟蟲。", "嘯盲風而涕淫雨兮，時又吐旱火之爞融。", "銜帝命以下討兮，建千仞之修鋒。", "乘飛霆而追逸景兮，歙砉掃滅而無蹤。", "忽崩播其來會兮，走海岳之神公。", "龍車獸鬼不知其數兮，旗纛晻靄而冥蒙。", "漸俯傴以旅進兮，鏘劍佩之相礱。", "司殺生之必信兮，知上帝之不汝容。", "既約束以反職兮，退戰慄而愈恭。", "澤充塞于四海兮，獨澹然其無功。", "君之去兮天門開，款閶闔兮朝玉臺。", "羣仙迎兮塞雲漢，儼前導兮紛後陪。", "歷玉階兮帝迎勞，君良苦兮馬豗頹。", "閔人世兮迫隘，陳下土兮帝所哀。", "返瓊宮之嵯峨兮，役萬靈之喧豗。"]'),
('b6e78e70-b12a-4ac3-9afb-4fb5ebe62cf8','山坡陀行','蘇軾','宋','宋诗','song-poetry','','[]','山坡陀兮下屬江，勢崖絕兮游波所蕩如頹牆。',307,'全唐诗/poet.song.46000.json','["山坡陀兮下屬江，勢崖絕兮游波所蕩如頹牆。", "松茀律兮百尺，旁枝虬葛藟之。", "上不見日兮下可依，吾曳杖兮吾僮以吾之書隨。", "藐余望兮水中汦，頎然而長者黄冠而羽衣。", "澣頤坦腹盤石箕坐兮，山亦有趾安不危，四無人兮可忘饑。", "仙人偓佺自言其居瑶之圃，一日一夜飛相往來不可數。", "使其開口言兮，豈惟河漢無極驚余心。", "默不言兮，蹇昭氏之不鼓琴。", "憺將翔兮山海，與日月兮長在。", "若有人兮夢中仇池我歸路，此非小有兮噫乎何以樂此而不去。", "昔余游於葛天兮，身非陶氏猶與偕。", "乘渺茫良未果兮，僕夫悲余馬懷。", "聊逍遥兮容與，晞余髮兮蘭之渚。", "余論世兮千載一人猶並時，余行詰曲兮欲知余者稀。", "峨峨洋洋余方樂兮，譬余繫舟於水魚潛鳥舉亦不知。", "何必每念輒得應余若響，坐有如此兮人子期。"]'),
('7d593b57-f282-4bd7-92aa-72a282869570','醉翁操','蘇軾','宋','宋诗','song-poetry','','[]','琅然，清圜。',111,'全唐诗/poet.song.46000.json','["琅然，清圜。", "誰彈，響空山。", "無言，惟翁醉中和其天。", "月明風露娟娟，人未眠。", "荷蕢過山前，曰有心也哉此賢。", "醉翁嘯咏，聲和流泉。", "醉翁去後，空有朝吟夜怨。", "山有時而童顛，水有時而回川。", "思翁無歲年，翁今爲飛仙。", "此意在人間，試聽徽外三兩絃。"]'),
('7df30e0c-f143-4da5-89ed-1e8402512734','次韵借觀睢陽五老圖','蘇軾','宋','宋诗','song-poetry','','[]','國老安榮心自閑，紫袍金带舊簪冠。',64,'全唐诗/poet.song.46000.json','["國老安榮心自閑，紫袍金带舊簪冠。", "星騎箕簸揚糠粃，斗掌權衡表漢桓。", "冬有愆陽嫌薄熱，夏多沴氣畏輕寒。", "頼得五賢清雅出，俾人敬慕肅容看。"]'),
('86a33b93-f205-4ec1-aae7-e0e8993ca8c5','題金山寺回文體','蘇軾','宋','宋诗','song-poetry','','[]','潮隨暗浪雪山傾，遠浦漁舟釣月明。',64,'全唐诗/poet.song.46000.json','["潮隨暗浪雪山傾，遠浦漁舟釣月明。", "橋對寺門松逕小，檻當泉眼石波清。", "迢迢綠樹江天曉，靄靄紅霞晚日晴。", "遥望四邊雲接水，碧峰千點數鷗輕。"]'),
('7497b44c-aef7-437d-9b7b-19e6b3b7d7d7','水月寺','蘇軾','宋','宋诗','song-poetry','','[]','千尺長松掛薜蘿，梯雲嶺上一聲歌。',32,'全唐诗/poet.song.46000.json','["千尺長松掛薜蘿，梯雲嶺上一聲歌。", "湖山深秀有何處，水月池中桂影多。"]'),
('629cd11d-3ba1-4fc7-8d2d-c83bc677bdc1','半月泉','蘇軾','宋','宋诗','song-poetry','','[]','請得一日假，來遊半月泉。',24,'全唐诗/poet.song.46000.json','["請得一日假，來遊半月泉。", "何人施大手，擘破水中天。"]'),
('dc536997-0322-4762-a56f-e369e8543a1d','遊何山','蘇軾','宋','宋诗','song-poetry','','[]','今日何山是勝遊，亂峰縈轉繞滄洲。',64,'全唐诗/poet.song.46000.json','["今日何山是勝遊，亂峰縈轉繞滄洲。", "雲含老樹明還滅，石礙飛泉咽復流。", "遍嶺煙霞迷俗客，一溪風雨送歸舟。", "自嗟塵土先衰老，底事孤僧亦白頭。"]'),
('2cfd6d81-86e0-4704-b8ca-c9dae07ba14f','自題臨文與可畫竹','蘇軾','宋','宋诗','song-poetry','','[]','石室先生清興動，落筆縱橫飛小鳳。',32,'全唐诗/poet.song.46000.json','["石室先生清興動，落筆縱橫飛小鳳。", "借君妙意寫篔簹，留與詩人發吟諷。"]'),
('556f5e32-9ace-4719-ada1-b8b6483aeb84','雙井白龍','蘇軾','宋','宋诗','song-poetry','','[]','巌泉未入井，蒙然冒沙石。',84,'全唐诗/poet.song.46000.json','["巌泉未入井，蒙然冒沙石。", "泉嫩石爲厭，石老生罅隙。", "異哉寸波中，露此橫海脊。", "先生酌泉笑，泉秀神龍蟄。", "舉手玉筯插，忽去銀釘擲。", "大身何時布，大翮翔霹靂。", "誰言鵬背大，更覺宇宙窄。"]'),
('64a59b74-ff87-4e92-9ab1-b687a1dd6dc2','瑞金東明觀','蘇軾','宋','宋诗','song-poetry','','[]','浮金最好溪南景，古木樓臺畫不成。',64,'全唐诗/poet.song.46000.json','["浮金最好溪南景，古木樓臺畫不成。", "天籟遠兼流水韵，雲璈常聽步虛聲。", "青鸞白鶴蟠空下，翠草玄芝匝地生。", "咫尺仙都隔塵世，門前車馬任縱橫。"]'),
('7543a277-02e3-4f49-ad2d-d63f76033b1a','題清淮樓','蘇軾','宋','宋诗','song-poetry','','[]','觀魚惠子臺蕪沒，夢蝶莊生冢木秋。',32,'全唐诗/poet.song.46000.json','["觀魚惠子臺蕪沒，夢蝶莊生冢木秋。", "惟有清淮供四望，年年依舊背城流。"]'),
('bdfe64fc-0d4b-4dd0-bfbb-192386e0381f','戲答佛印','蘇軾','宋','宋诗','song-poetry','','[]','遠公沽酒飲陶潛，佛印燒豬待子瞻。',32,'全唐诗/poet.song.46000.json','["遠公沽酒飲陶潛，佛印燒豬待子瞻。", "採得百花成蜜後，不知辛苦爲誰甜。"]'),
('05d46012-8560-4d35-a7b5-f01989e9a114','失題三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','木落沙明秋浦，雲卧烟淡瀟湘。',28,'全唐诗/poet.song.46000.json','["木落沙明秋浦，雲卧烟淡瀟湘。", "曾學扁舟范蠡，五湖深處鳴榔。"]'),
('1d3faa72-f3b0-41be-8f4b-6e2a6221174c','失題三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','望斷水雲千里，橫空一抹晴嵐。',28,'全唐诗/poet.song.46000.json','["望斷水雲千里，橫空一抹晴嵐。", "不見邯鄲歸路，夢中略到江南。"]'),
('b67b32d9-640a-4132-90f1-f8d5639abf5b','失題三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','公子只應見畫，此中我獨知津。',28,'全唐诗/poet.song.46000.json','["公子只應見畫，此中我獨知津。", "寫到水窮天杪，定非塵土間人。"]'),
('5b5d9636-d4e9-4e7b-8708-50b43ad11e7c','來鶴亭','蘇軾','宋','宋诗','song-poetry','','[]','鴻漸偏宜丹鳳南，冠霞帔月毿毿。',31,'全唐诗/poet.song.46000.json','["鴻漸偏宜丹鳳南，冠霞帔月毿毿。", "酒酣亭上來看舞，有客新名喚作耽。"]'),
('3ca25138-9c51-4421-86d3-e27f4e98f717','龍山補亡  其一','蘇軾','宋','宋诗','song-poetry','','[]','征西天府，重九令節。',120,'全唐诗/poet.song.46000.json','["征西天府，重九令節。", "駕言龍山，宴凱羣哲。", "壺歌雅奏，緩带輕帢。", "胡爲中觴，一笑粲發。", "楩楠競秀，榆柳獨脫。", "驥騄交騖，駑蹇先蹶。", "楚狂醉亂，隕帽莫覺。", "戎服囚首，枯顱茁髮。", "惟明將軍，度量豁達。", "容此下士，顛倒冠襪。", "宰夫揚觶，兕觥舉罰。", "請歌相鼠，以侑此爵。"]'),
('fa221293-8a23-408f-9f51-c263aef9c06f','龍山補亡  其二','蘇軾','宋','宋诗','song-poetry','','[]','吾聞君子，蹈常履素。',120,'全唐诗/poet.song.46000.json','["吾聞君子，蹈常履素。", "晦明風雨，不改其度。", "平生丘壑，散髮箕裾。", "墜車天全，顛沛何懼。", "腰適忘带，足適忘屨。", "不知有我，帽復奚數。", "流水莫繫，浮雲暫寓。", "飄然隨風，非去非取。", "我冠明月，佩服寶璐。", "不纓而結，不簪而附。", "歌詩甯擇，請飲相鼠。", "罰此陋人，俾出童羖。"]'),
('7d45f73c-29ef-439d-88be-e1ea61018cc8','牡丹','蘇軾','宋','宋诗','song-poetry','','[]','小檻徘徊日自斜，只愁春盡委泥沙。',32,'全唐诗/poet.song.46000.json','["小檻徘徊日自斜，只愁春盡委泥沙。", "丹青欲寫傾城色，世上今無楊子華。"]'),
('54627ec9-f038-4583-9cbf-ccb5a4be0a0d','西湖壽星院明遠堂','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十年不向此凭欄，景象依然一望間。',64,'全唐诗/poet.song.46000.json','["十年不向此凭欄，景象依然一望間。", "龍蜃吐雲天入水，樓臺倒影日銜山。", "僧於僻寺難爲隠，人在扁舟未是閑。", "孤鶴似尋和靖宅，盤空飛去復飛還。"]'),
('c01f4d89-1ebc-439a-810a-663054dde5c3','牡丹和韵','蘇軾','宋','宋诗','song-poetry','','[]','光風爲花好，奕奕弄清溫。',48,'全唐诗/poet.song.46000.json','["光風爲花好，奕奕弄清溫。", "撩理鶑情趣，留連蝶夢魂。", "飲酣浮倒暈，舞倦怯新翻。", "水竹傍□意，明紅似故園。"]'),
('e6207079-929c-4fa0-bd34-ccceb3cdc811','慈雲四景 甘露泉','蘇軾','宋','宋诗','song-poetry','','[]','階下有龍潭，一泓寒且碧。',24,'全唐诗/poet.song.46000.json','["階下有龍潭，一泓寒且碧。", "不須撫兩掌，流出仙人液。"]'),
('65723eb0-60b6-4d52-ab70-6519deb56a27','慈雲四景 白雲居','蘇軾','宋','宋诗','song-poetry','','[]','禪居何所有，戶牖白雲分。',24,'全唐诗/poet.song.46000.json','["禪居何所有，戶牖白雲分。", "直待譚玄後，相隨花雨紛。"]'),
('72592102-0f2e-472a-bc8c-8cf06e1423eb','慈雲四景 娑羅樹','蘇軾','宋','宋诗','song-poetry','','[]','誰從五竺國，分得一枝來。',24,'全唐诗/poet.song.46000.json','["誰從五竺國，分得一枝來。", "秀出重樓外，專除世上埃。"]'),
('db494364-2276-4414-95fb-025560b897d2','慈雲四景 鸚鵡院','蘇軾','宋','宋诗','song-poetry','','[]','古院楓篁裏，寥寥隔市喧。',24,'全唐诗/poet.song.46000.json','["古院楓篁裏，寥寥隔市喧。", "仙禽發異響，驚起老僧禪。"]'),
