('9373139c-26f3-4026-acff-4e12b58fc65d','存目  其九一','蘇軾','宋','宋诗','song-poetry','','[]','詩題：贈山谷子首句：黄童三尺世無雙。',18,'全唐诗/poet.song.46000.json','["詩題：贈山谷子首句：黄童三尺世無雙。"]'),
('66efcaff-fd1e-428d-91e1-71d450f73680','存目  其九二','蘇軾','宋','宋诗','song-poetry','','[]','詩題：答晁以道索書首句：閱世真難記。',18,'全唐诗/poet.song.46000.json','["詩題：答晁以道索書首句：閱世真難記。"]'),
('c11b4b87-a527-4e3f-afa5-ffaa40799b5a','存目  其九三','蘇軾','宋','宋诗','song-poetry','','[]','詩題：謝都事惠米首句：平生忍慾今忍貧。',19,'全唐诗/poet.song.46000.json','["詩題：謝都事惠米首句：平生忍慾今忍貧。"]'),
('e94739e9-44b2-453d-b384-c7631fe9a10f','存目  其九四','蘇軾','宋','宋诗','song-poetry','','[]','詩題：和南都趙少師首句：富貴功名已兩忘。',20,'全唐诗/poet.song.46000.json','["詩題：和南都趙少師首句：富貴功名已兩忘。"]'),
('3f79a08c-4527-4537-9a6d-95a8401bcd32','存目  其九五','蘇軾','宋','宋诗','song-poetry','','[]','詩題：寄汝陰少師首句：得時行道善知終。',19,'全唐诗/poet.song.46000.json','["詩題：寄汝陰少師首句：得時行道善知終。"]'),
('911e3a4d-2d2d-4654-a9d0-9585247a15f4','紫騮馬','張舜民','宋','宋诗','song-poetry','','[]','紫騮馬，白面郎。',96,'全唐诗/poet.song.46000.json','["紫騮馬，白面郎。", "紅銀鞍勒青油韁，左牽黄犬右擎蒼。", "朝從灞陵獵，暮宿投平康。", "使酒不滿意，按劍叱天狼。", "今年明年一如此，後年不覺髮成霜。", "扶肩策杖出門行，抱子弄孫樓上坐。", "忽然涕淚滿衣襟，爲見驊騮面前過。"]'),
('471d01c5-e54c-40ea-a86b-07a8e7e75f21','關山月','張舜民','宋','宋诗','song-poetry','','[]','明月生海上，裴回照邊城。',56,'全唐诗/poet.song.46000.json','["明月生海上，裴回照邊城。", "中夜關山靜，但聞流水聲。", "征人看月思鄉泣，夜久衣單難獨立。", "錦字佳人怨不歸，開幃更感飛螢入。"]'),
('0260bd74-6da2-4c91-8fbd-6cd48fb5efa6','桃李花  其一','張舜民','宋','宋诗','song-poetry','','[]','紅白桃李花，馨香滿芳草。',72,'全唐诗/poet.song.46000.json','["紅白桃李花，馨香滿芳草。", "開時人少年，落處人已老。", "風雨半夜來，飄揚滿官道。", "行客爲歎息，不忍便除掃。", "猶有兩三枝，香色晚更好。", "把酒將奈何，攀折恨不早。"]'),
('2ba96c59-3bd8-4106-a97a-d7ee34050ed8','桃李花  其二','張舜民','宋','宋诗','song-poetry','','[]','花如桃李人如玉，終日看花看不足。',64,'全唐诗/poet.song.46000.json','["花如桃李人如玉，終日看花看不足。", "萬年枝上囀春風，七絲弦上調新曲。", "寶馬嘶風車擊轂，東市鬬鷄西市鞠。", "但得長留臉上紅，莫辭貴買尊中醁。"]'),
('d41a40b1-4577-4eed-8d1c-193f7ed57e04','來日大難','張舜民','宋','宋诗','song-poetry','','[]','去日滔滔似易得，來日藐藐若大難。',96,'全唐诗/poet.song.46000.json','["去日滔滔似易得，來日藐藐若大難。", "一日且作一日調，百年莫作百年看。", "晉侯竟爾見新麥，楚王更要食熊蹯。", "勿輕白髮翁，勿恃青楊質。", "物壯則老矣，其壽不可必。", "嵇叔夜，郭景純，今般人物如何人，皇天何不留逡巡。"]'),
('12f79aef-4938-4039-9453-bd97a3c35861','君馬黄','張舜民','宋','宋诗','song-poetry','','[]','君馬良，乘乘黄。',124,'全唐诗/poet.song.46000.json','["君馬良，乘乘黄。", "僕臣御，守法度。", "乍可三驅失前禽，不可一朝爲詭遇。", "假使四牡，項領無害。", "六轡如組，周旋中規，折旋中矩。", "聽和鸞之聲，遵康莊之路。", "馬不駭輿，君子安處。", "如欲登九折之險，走羊腸之阻。", "蒙犯霜露，跌踢風雨。", "雖使造父再生，王良復出，予亦未知其如何爾。"]'),
('275f64da-3c32-44ae-b4a8-ab6140e8a0a6','大雪行','張舜民','宋','宋诗','song-poetry','','[]','曉辭洛水濱，暮宿河之涘。',108,'全唐诗/poet.song.46000.json','["曉辭洛水濱，暮宿河之涘。", "四野漫漫不見人，竟日止能行數里。", "渾然天地爲一色，渭水南北復何似。", "五陵鷹犬爭合圍，十宅管弦初熱耳。", "連宵耿耿照鬢髮，迎馬點衣猶未已。", "但得來年春麥熟，暫困泥塗復何恥。", "農夫南畝未厭多，却入長安作泥滓。"]'),
('2059c84d-216e-4d17-b777-61025cb7d12c','邯鄲少年','張舜民','宋','宋诗','song-poetry','','[]','邯鄲全盛時，人物自都雅。',72,'全唐诗/poet.song.46000.json','["邯鄲全盛時，人物自都雅。", "更得幽并兒，豪氣陰相假。", "生求趙王劍，千金不論價。", "力購燕國姝，臨高起亭榭。", "使酒叢臺上，夜獵西陵下。", "聞說五陵兒，臂鷹馳犬馬。"]'),
('81ceb79b-34ce-432e-b130-10d1cac43723','試院感懷','張舜民','宋','宋诗','song-poetry','','[]','朱戶當晝扃，霜簾達夜懸。',204,'全唐诗/poet.song.46000.json','["朱戶當晝扃，霜簾達夜懸。", "沈沈造廣庭，皞皞接衆賢。", "疏莛叩洪鐘，短綆汲深淵。", "始知學不迨，內顧多歉然。", "憶昔居上庠，忝出流輩前。", "賦就千金直，詩成萬口傳。", "荀楊迥接迹，班馬思比肩。", "一從苟干祿，永謝英俊躔。", "折腰府縣中，餬口道路邊。", "世俗多見輕，義士誰哀憐。", "憔悴有今日，光輝思昔年。", "今茲睹秋闈，猶欲爭相先。", "枯魚傍江湖，疲馬憶薊燕。", "凉風拂翠幙，隴月向人圓。", "物景近中秋，客意孤綿綿。", "裴回望清光，欲攬不得全。", "永懷懽樂時，把酒謝嬋娟。"]'),
('dab2a4fc-45d1-427e-af46-74c04e647c89','鯨魚','張舜民','宋','宋诗','song-poetry','','[]','東海十日風，巨浪碎山谷。',144,'全唐诗/poet.song.46000.json','["東海十日風，巨浪碎山谷。", "長鯨跨十尋，宛轉在平陸。", "雷火從天來，砉然刳兩目。", "肌膚煮作油，骨節分爲屋。", "腥羶百里內，戶戶至厭足。", "我聞海上人，明珠可作燭。", "鯨魚復何罪，海若一何酷。", "從欲讒風伯，大鈞問不告。", "躊躕復歎息，歸咎當溟瀆。", "託形天地閒，獨爾有含蓄。", "大者不能容，小者又何益。", "却羨蝦魚輩，安然保家族。"]'),
('9f33e05e-6352-4e0a-8d4c-7945ba98fde8','東武二首  其一','張舜民','宋','宋诗','song-poetry','','[]','小白奬周室，夷吾致其君。',48,'全唐诗/poet.song.46000.json','["小白奬周室，夷吾致其君。", "各竭當時力，未免後儒言。", "駿馬日千里，壯士舉百鈞。", "更欲加勉策，折髀與摧轅。"]'),
('9bd5baab-6abb-409c-a388-68a1eb4d0ebf','東武二首  其二','張舜民','宋','宋诗','song-poetry','','[]','景公登牛山，俯闞臨邑區。',168,'全唐诗/poet.song.46000.json','["景公登牛山，俯闞臨邑區。", "耕耘被廣野，軒冕充脩衢。", "鬬雞走狗馬，擊筑吹笙竽。", "魚鹽來海岱，桑柘入青徐。", "饒樂曾無敵，棄背復何如。", "公乃歎而泣，顧謂諸大夫。", "安得千萬年，長有此國都。", "大夫助公泣，獻壽猶欷歔。", "晏子斂袂笑，笑此君臣愚。", "世事如輪環，曾不借須臾。", "前此十數公，今已成丘墟。", "胡不長守此，乃與子孫居。", "始知富貴者，喜受庸人諛。", "豈獨當時笑，後世亦揶揄。"]'),
('ac15be35-b18b-401d-af1c-573d4050a150','山陽二首  其一','張舜民','宋','宋诗','song-poetry','','[]','山陽水陸衝，樂餌人所赴。',48,'全唐诗/poet.song.46000.json','["山陽水陸衝，樂餌人所赴。", "寂寞先生門，車輪不少駐。", "賢哉彼二公，綽有尚賢風。", "恨不生羽翼，嘯歌樽酒中。"]'),
('b0e00db5-77fa-4477-b6d0-e0f30cf33249','山陽二首  其二','張舜民','宋','宋诗','song-poetry','','[]','古人急於仕，每擇分所安。',48,'全唐诗/poet.song.46000.json','["古人急於仕，每擇分所安。", "願爲趙魏老，不作滕薛官。", "今人不量力，臨老當繁難。", "少見詠淇澳，甚多歌伐檀。"]'),
('fc0e829f-f56a-45b4-a4e6-33ce19abfed4','淮口阻雨','張舜民','宋','宋诗','song-poetry','','[]','旱久不得雨，既雨不肯休。',84,'全唐诗/poet.song.46000.json','["旱久不得雨，既雨不肯休。", "沄沄汴河水，初合淮河流。", "北來何處客，暫此駐扁舟。", "中有投荒人，萬里趨炎洲。", "聽水夜不眠，觀水朝亦愁。", "呼風捲重陰，放出赤日頭。", "捨舟出平地，走馬復西遊。"]'),
('4faea78f-9db7-4fdf-ac0b-3a4b8226794d','天爵山','張舜民','宋','宋诗','song-poetry','','[]','耕者志於食，否則餒繼之。',60,'全唐诗/poet.song.46000.json','["耕者志於食，否則餒繼之。", "學者志於道，一爲好爵縻。", "本自不營利，間或與利期。", "朝日入而處，暮日仰而思。", "浮雲蔽蔀屋，見前當自知。"]'),
('7a159bb2-9a8d-4b72-b0ed-eefe89094300','李侯新齋植松竹聊爲雜言','張舜民','宋','宋诗','song-poetry','','[]','嘗聞君子居，一日顧必葺。',108,'全唐诗/poet.song.46000.json','["嘗聞君子居，一日顧必葺。", "李侯作新齋，制度皆自給。", "軒楹如肺腑，豁達可出入。", "取竹渭水湄，移松隴山隰。", "歲寒遠相依，勁節久孤立。", "栽培豈無法，根著至今濕。", "清風在目前，獨我得多挹。", "歸壤共無涯，往日不可及。", "惟憂屬後人，長伴邊聲急。"]'),
('8699cd69-967a-4431-a91e-7dad01bf5bed','送葉伸出使河北','張舜民','宋','宋诗','song-poetry','','[]','君今使河北，幾日渡黄河。',120,'全唐诗/poet.song.46000.json','["君今使河北，幾日渡黄河。", "脫身出臺省，杖節犯風波。", "東南耆舊中，如君能幾何。", "何人把袂留，顧我餞則那。", "燕趙多佳人，善舞體婆娑。", "不學白紵詞，能唱瓠子歌。", "歌罷令翁愁，井竈宅黿鼉。", "安得佐禹才，干旄飾五紽。", "與君並駕驅，坐使民氣和。", "揮汗强援筆，矢辭愧不多。"]'),
('5f346fd7-3239-41f6-818a-6b674ebfef54','汧陽感事','張舜民','宋','宋诗','song-poetry','','[]','人誰無婚姻，我則分鮮薄。',132,'全唐诗/poet.song.46000.json','["人誰無婚姻，我則分鮮薄。", "即今頭已白，不識外家樂。", "再過汧陽縣，心境何寂寞。", "當時退食地，東軒俯層壑。", "華屋變山丘，九原寧可作。", "空存遺愛樹，枝葉幾榮落。", "正如遼東歸，但見舊城郭。", "堂堂想其儀，物物皆如昨。", "眼看北來雁，身是南飛鵲。", "霜風掃隃麋，晚翠斂吳嶽。", "臨行更踟躕，灑淚徧南閣。"]'),
('e3647f9d-cbda-4bd5-a909-452e695add27','思善堂','張舜民','宋','宋诗','song-poetry','','[]','春風長萬物，棘子猶卷然。',48,'全唐诗/poet.song.46000.json','["春風長萬物，棘子猶卷然。", "及至華實稠，已悲霜露先。", "功隨四時去，不待三牲全。", "所以陟屺人，設身常捨旃。"]'),
('f55a0118-c5d0-4ab5-bf0c-187bba006895','鄉人言','張舜民','宋','宋诗','song-poetry','','[]','郴江有奇石，似牛伏岸側。',240,'全唐诗/poet.song.46000.json','["郴江有奇石，似牛伏岸側。", "鄉人久相傳，過者有顛覆。", "我與鄉人謀，鑿去可勿留。", "祇消一日力，得弭千歲憂。", "鄉人顧我笑，官必有闇拙。", "大者不能圖，小者安能說。", "方今民間事，頗有急於石。", "當官貴居事，能不閑採拾。", "我有本多田，今乃身無居。", "雖有兒女輩，售人爲婢奴。", "破家不足恡，所恨骨肉離。", "官今將骨肉，好去將何之。", "我雖有田里，亦聞官念此。", "念此不能爲，何用居官爾。", "乃指江中石，此物如有神。", "不覆廉善士，獨傾貪虐人。", "官今幸過此，行李都無害。", "將我言日思，勿爲貧賤懈。", "我聞鄉人言，背顙俱汗流。", "欲問破家因，恐爲明者羞。"]'),
('460b2c3e-616f-47d0-b531-93fee327c5fb','送羅正之年兄出使二浙','張舜民','宋','宋诗','song-poetry','','[]','玉麈助清談，金貂飾高位。',288,'全唐诗/poet.song.46000.json','["玉麈助清談，金貂飾高位。", "二物已殺身，無剝生民利。", "君爲使者官，猶作農夫事。", "隨軒載畚插，一心惟度地。", "惟梁及齊岱，潢汙變滯穗。", "玉食反無魚，黄牛如象貴。", "凡人畏辛苦，君處乃樂易。", "富哉太伯墟，吳越之委積。", "二年苦昏墊，竈臼成蛙肆。", "一日死百人，官司但熟視。", "不獲乃命君，物議已爲遲。", "君其尚勉旃，副彼朝廷意。", "若爲濬涇洪，可得露城市。", "誅其姑息人，戢彼因循吏。", "死者不可招，存者如何置。", "赴海與壑鄰，實繫君之智。", "君家本天台，立身頗勤勩。", "一生在州縣，晚歲稱憲使。", "南人重衣錦，今爾實自致。", "弭節拜墳墓，椎牛設鄉遂。", "翁媼上籬觀，揮零復嗟喟。", "咸曰羅家兒，今日乃如是。", "伊予出西北，仕路每相值。", "交代又同年，莫予論事契。"]'),
('24d9e115-d4eb-4840-a8be-6de1eba3f500','送薛昌朝赴太原幕府','張舜民','宋','宋诗','song-poetry','','[]','去國重爲客，送君還復歸。',148,'全唐诗/poet.song.46000.json','["去國重爲客，送君還復歸。", "天寒雨細光景促，且就東城寺中宿。", "寺當蒲坂望屋廬，日暮無由辨喬木。", "既已唯諾難自由，雖欲一日安可留。", "吾輩事勢不大殊，此際興味復何如，歸來愁坐獨嗟吁。", "畢竟豈如村野老，或爾富民城郭居。", "雨暘寒燠都不與，親戚滿眼身不孤。", "乃知平生走薄官，正似癡牛引重車。", "險夷繚絡不知止，祇得終年困道塗。"]'),
('1d8fc5ff-133c-4736-9f70-c9db25dc89c6','贈奉議沈遼','張舜民','宋','宋诗','song-poetry','','[]','鳬脛天生短，鶴脛本來長。',300,'全唐诗/poet.song.46000.json','["鳬脛天生短，鶴脛本來長。", "一朝有客欲斷續，二物無地逃悲傷。", "吾徒曾匪鳬鶴匹，又取聖賢爲學術。", "解將軒冕等浮雲，寧免儻來并執一。", "夫君擢秀居東南，代以文詞起簪紱。", "錚錚官業素有聞，更號能書居第一。", "平生意氣少防閑，一跌落在江湖間。", "幾年轉徙無家室，惟與樵漁爲往還。", "醉吟未免寫胸臆，健筆依舊飛雲烟。", "遠俗僻陋多不識，都城一帖沽萬錢。", "今朝我過齊山下，邀我陟降遊二山。", "羨君卜築思意盡，今古氣象羅目前。", "佛留九頂千株石，天賜清溪一水灣。", "自拾薪枝給朝夕，不與城郭通交關。", "親友一切皆謝絕，惟許子馳來問安。", "人生涉世多憂喜，不用昭昭明物理。", "少小辛苦卜一廛，如今老大無居止。", "遷流方從五嶺去，敢望生還復經此。", "萬一君恩縱北歸，與君左右爲鄰里。"]'),
('bd5f121d-eb09-4bef-a490-1e5764cbcfbc','還李彀士雄卷','張舜民','宋','宋诗','song-poetry','','[]','河汾之會，韓晉之津。',252,'全唐诗/poet.song.47000.json','["河汾之會，韓晉之津。", "在昔王馬今何人，青衫木笏排風塵。", "面如桃花髭如銀，長篇大字妙入神。", "關輔後輩誰等倫，四方仕宦足邅迍。", "歸老閿鄉玉澗濱，雲爲友兮山爲鄰。", "森森綠槊萬霜筠，汩汩清漣飛兩輪。", "亭上何所見，荆山早暮來相親。", "齋中何所有，新舊歌詩千百首。", "細大搜羅萬象勞，放開日月東西走。", "世上兒女徒紛紛，作者須教歸老手。", "君不見古往今來富貴人，燦燦金章懸紫綬。", "金珠初入寵方深，骨肉未消名已朽。", "又不見李杜死來三百年，至今仰望如星斗。", "一聯一句挂齒牙，便同金石垂長久。", "乃知皇天造萬物，獨於吾輩偏加厚。", "還翁詩卷翁細思，豈是生平都不偶。"]'),
('c69becca-a322-43f3-901c-2da02f5ab60b','禪僧福公寄惠牧牛圖答以問牛歌','張舜民','宋','宋诗','song-poetry','','[]','訶訶訶，棲巌老法師，寄我牧牛頌。',124,'全唐诗/poet.song.47000.json','["訶訶訶，棲巌老法師，寄我牧牛頌。", "我是人間百歲人，今朝却作嬰兒弄。", "堪笑其間有一牛，滿身變白尾猶黑。", "想君不是上上根，教人費盡閒心力。", "我昔有一牛，其毛元自白。", "如今牛已無，欲求不可得。", "蓑笠與鞭繩，同時皆棄擲。", "身心無住著，冷坐溪邊石。", "却問山中人，閒尋牧牛客。"]'),
('f654ef9a-c7d0-4294-8ca7-959627ea55bd','書節孝先生事實於先生詩編之後','張舜民','宋','宋诗','song-poetry','','[]','古人往矣名空存，爾來冠带誰其倫。',304,'全唐诗/poet.song.47000.json','["古人往矣名空存，爾來冠带誰其倫。", "語言淵騫行盜跖，俯仰不愧何繽繽。", "先生道義完且潔，去彼取此非今人。", "事親豈但綵衣戲，刻木省定長悲辛。", "拋官却掃醉經史，胸中無復留纖塵。", "履穿袍敝突不墨，辭幣與粟甘清貧。", "自從秀髮到白首，造次於是非一晨。", "當知有昊憫澆散，先生故出拔斯民。", "嗟余稟賦雖不敏，管窺偶幸知所因。", "講聞先生亦已久，云爲輒以書諸紳。", "朅來廣陵兩閱歲，所得比舊尤加親。", "此編雅什盈數百，覃思成誦驚余神。", "恍如聽樂周太廟，黄鐘大呂皦且純。", "又如典瑞出圭璧，璀璨溢目非玞珉。", "偉哉固足信萬一，彷彿想見容彬彬。", "吾皇圖治急遺逸，空谷相望推蒲輪。", "先生高卧焉得遂，細札匪日頒嚴闉。", "重慚韁鎖脫無計，灑掃猶阻致此身。", "願言師法不少懈，異日有立逃湮淪。"]'),
('8f981b3e-346f-4404-9050-e4f6ce2825a7','跋百之詩畫','張舜民','宋','宋诗','song-poetry','','[]','詩是無形畫，畫是有形詩。',66,'全唐诗/poet.song.47000.json','["詩是無形畫，畫是有形詩。", "丹青不知老將至，李陵蘇武真吾師。", "太平本學治禮樂，猶有暇日能臨池。", "區中孰最奇，龐眉皓首苟住著，安得一區我安之。"]'),
('0a321406-dfdc-46fc-89d5-f1570375c1d3','京兆安汾叟赴辟臨洮幕府南舒李君自畫陽關圖并詩以送行浮休居士爲繼其後','張舜民','宋','宋诗','song-poetry','','[]','古人送行贈以言，李君送人兼以畫。',384,'全唐诗/poet.song.47000.json','["古人送行贈以言，李君送人兼以畫。", "自寫陽關萬里情，奉送安西從辟者。", "澄心古紙白如銀，筆墨輕清意蕭灑。", "短亭離筵列歌舞，亭亭諠諠簇車馬。", "溪邊一叟靜垂綸，橋畔俄逢兩負薪。", "掣臂蒼鷹隨獵犬，聳耳駏馿扶隻輪。", "長安陌上多豪俠，正值春風二三月。", "分明朝雨浥輕塵，客舍青青柳色新。", "主人舉杯苦勸客，道是西征無故人。", "殷勤一曲歌者闋，歌者背淚霑羅巾。", "酒闌童僕各辭親，結束韜縢意氣振。", "稚子牽衣老人哭，道上行客皆酸辛。", "惟有溪邊釣魚叟，寂寞投竿如不聞。", "李君此畫何容易，畫出漁樵有深意。", "爲道世間離別人，若箇不因名與利。", "紅蓮幕府盡奇才，家近南山紫翠堆。", "烜赫朱門當巷陌，潺潺流水遶亭臺。", "當軒怪石人稀見，夾道長松手自栽。", "靜鎖園林鶑對語，密穿堂戶燕驚迴。", "試問主翁在何所，近向安西幕府開。", "歌舞教成頭已白，功名未立老相催。", "西山東國不我與，造父王良安在哉。", "已卜買田箕嶺下，更看築室潁河隈。", "憑君傳語王摩詰，畫箇陶潜歸去來。"]'),
('a8691751-8873-4a8d-97f3-07aac97e9d95','打麥','張舜民','宋','宋诗','song-poetry','','[]','打麥打麥，彭彭魄魄。',182,'全唐诗/poet.song.47000.json','["打麥打麥，彭彭魄魄。", "聲在山南應山北，四月太陽出東北。", "纔離海嶠麥尚青，轉到天心麥已熟。", "鶡旦催人夜不眠，竹雞叫雨雲如墨。", "大婦腰鐮出，小婦具筐逐。", "上壠先捋青，下壠已成束。", "田家以苦乃爲樂，敢憚頭枯面焦黑。", "貴人薦廟已嘗新，酒醴雍容會所親。", "曲終厭飫勞童僕，豈信田家未入脣。", "盡將精好輸公賦，次把升斗求市人。", "麥秋正急又秧禾，豐歲自少凶歲多，田家辛苦可奈何。", "將此打麥詞，兼作插禾歌。"]'),
('9671eeac-0a76-449b-b0d6-4bddcb519706','梅子','張舜民','宋','宋诗','song-poetry','','[]','月破冥冥雨，枝摇閃閃黄。',48,'全唐诗/poet.song.47000.json','["月破冥冥雨，枝摇閃閃黄。", "口中先水出，衣上带花香。", "肺疾須拚醉，牙疏不耐嘗。", "調羹無復用，山谷日傾筐。"]'),
('0d57bbaa-5d52-47c8-9c57-63cc85aec7dd','巌花','張舜民','宋','宋诗','song-poetry','','[]','託根何太遠，得地亦相宜。',48,'全唐诗/poet.song.47000.json','["託根何太遠，得地亦相宜。", "土石生爲偶，紅香想自知。", "風英將片片，雨實漸離離。", "戍客思攀折，無何歷處危。"]'),
('4f071c13-d0af-47e3-aec6-873fa98f3515','矴齋獨坐懷兄弟','張舜民','宋','宋诗','song-poetry','','[]','並橋冰乍泮，隔岸柳初黄。',48,'全唐诗/poet.song.47000.json','["並橋冰乍泮，隔岸柳初黄。", "河上春猶淺，天涯日漸長。", "平時好行樂，往事入思量。", "最恨三年別，應添兩鬢霜。"]'),
('a6052035-e4c1-4a79-a695-24767a97d741','東行別矴齋','張舜民','宋','宋诗','song-poetry','','[]','宴坐豈不好，有誰强爾行。',48,'全唐诗/poet.song.47000.json','["宴坐豈不好，有誰强爾行。", "山川不改色，兒女各爲情。", "岸隔霜林意，齋空夜水聲。", "虛傳少陵叟，一室過平生。"]'),
('40ad948e-2174-46c4-9d8c-dd70ea9789b4','秋日書懷','張舜民','宋','宋诗','song-poetry','','[]','凉風起天末，何物動人愁。',48,'全唐诗/poet.song.47000.json','["凉風起天末，何物動人愁。", "一室關河暮，三年草木秋。", "高文誰弔屈，晚節漫依劉。", "獨怪瀼西叟，巴江得久留。"]'),
('2ba8504d-4cc3-4114-9a3a-bd033a00e233','秋暮書懷  其一','張舜民','宋','宋诗','song-poetry','','[]','秋日平凉客，棲遲泮水間。',48,'全唐诗/poet.song.47000.json','["秋日平凉客，棲遲泮水間。", "家貧思得祿，性懶要長閒。", "欹枕時聞雁，登城忽見山。", "征西舊時將，大半髮毛斑。"]'),
('d550b23d-faec-497a-96ff-0d6918669f1e','秋暮書懷  其二','張舜民','宋','宋诗','song-poetry','','[]','客舍無前後，分明似一舟。',48,'全唐诗/poet.song.47000.json','["客舍無前後，分明似一舟。", "瓶罌生計小，兒女長年憂。", "餬口身將老，謀歸歲聿周。", "布衣今復敝，莫問黑貂裘。"]'),
('5eec7f8f-5124-4dc3-af3d-629cf4ae5d40','秋暮書懷  其三','張舜民','宋','宋诗','song-poetry','','[]','憶昔曾遊處，俄經二十年。',48,'全唐诗/poet.song.47000.json','["憶昔曾遊處，俄經二十年。", "重來人不識，獨想事依然。", "北海知劉備，荆州小仲宣。", "如何騎駿馬，徼倖學開邊。"]'),
('8ef89dfd-e3f2-4da6-9b92-6c7d0525bd9b','秋暮書懷  其四','張舜民','宋','宋诗','song-poetry','','[]','濯濯荒山麓，娟娟孤女祠。',48,'全唐诗/poet.song.47000.json','["濯濯荒山麓，娟娟孤女祠。", "曉泉開寶鏡，秋月畫蛾眉。", "拾翠來涇汭，行雲過北池。", "猶勝青冢魄，埋恨九原悲。"]'),
('7d3c37dc-7cf8-49ca-ad83-3e89ec778b8d','秋暮書懷  其五','張舜民','宋','宋诗','song-poetry','','[]','旅鬢莖莖白，霜梨葉葉紅。',48,'全唐诗/poet.song.47000.json','["旅鬢莖莖白，霜梨葉葉紅。", "可憐非類者，同落有涯中。", "萬物齊爲馬，勞生獨轉蓬。", "此行江海外，便作狎鷗翁。"]'),
('8aa49779-b420-47da-b324-8fabafbe7e25','秋暮書懷  其六','張舜民','宋','宋诗','song-poetry','','[]','再到崆峒寺，題名尚宛然。',48,'全唐诗/poet.song.47000.json','["再到崆峒寺，題名尚宛然。", "存亡如昨日，筋力想當年。", "禍福歸玄鸐，晨昏聽杜鵑。", "此間無虎豹，好著養生編。"]'),
('df3c2833-4f51-4dc3-b9e1-82be087f58b7','秋暮書懷  其七','張舜民','宋','宋诗','song-poetry','','[]','節物推移速，登臨感慨多。',48,'全唐诗/poet.song.47000.json','["節物推移速，登臨感慨多。", "寒雲飛隴首，殘葉下朝那。", "代北慚歸馬，洮西尚凱歌。", "惟憐鏖戰骨，寂寞掩山阿。"]'),
('96be4d21-124a-4fa6-a224-370d40a580f1','秋暮書懷  其八','張舜民','宋','宋诗','song-poetry','','[]','冶谷鴉仍亂，空同日欲曛。',48,'全唐诗/poet.song.47000.json','["冶谷鴉仍亂，空同日欲曛。", "關河圍絕壁，鼓角壯中軍。", "自納和戎策，還停草檄文。", "征西好規矩，後世見忠勤。"]'),
('f1f537dc-dbcf-441c-ab53-6d6d5346a744','秋暮書懷  其九','張舜民','宋','宋诗','song-poetry','','[]','愛靜無由靜，思歸不得歸。',48,'全唐诗/poet.song.47000.json','["愛靜無由靜，思歸不得歸。", "干時虛碌碌，懷往迥依依。", "菊酒還吹帽，玄霜未授衣。", "知他蘧伯玉，曾悟少年非。"]'),
('3c0d033f-2793-4dc3-b38b-7706bc503a46','登大岯','張舜民','宋','宋诗','song-poetry','','[]','東郡韓延壽，黎陽李魏公。',48,'全唐诗/poet.song.47000.json','["東郡韓延壽，黎陽李魏公。", "一時推豈弟，累代想英雄。", "草木芳菲外，山河感慨中。", "但逢川上客，不見狎鷗翁。"]'),
('b44874e5-6d51-434f-beb9-49f263abb05d','離山陽','張舜民','宋','宋诗','song-poetry','','[]','日日東南去，空勞北望魂。',48,'全唐诗/poet.song.47000.json','["日日東南去，空勞北望魂。", "孤帆轉城角，返照入船門。", "强飯甘魚菜，隨方學語言。", "蛙聲不忍聽，爲似故山村。"]'),
('45fe6783-26e3-4f0a-8eaa-58766e0d8826','八月十四日清谿堂望月','張舜民','宋','宋诗','song-poetry','','[]','客路三湘遠，天風八月清。',48,'全唐诗/poet.song.47000.json','["客路三湘遠，天風八月清。", "雲間雖掩映，水底已分明。", "且對當年影，休吟萬古情。", "喜君方向滿，照我過江城。"]'),
('0c7099ba-3854-4578-a929-b23751e3b704','郴州送許叔獻員外赴道州','張舜民','宋','宋诗','song-poetry','','[]','嶺下爲遷客，人中得老成。',48,'全唐诗/poet.song.47000.json','["嶺下爲遷客，人中得老成。", "傳經漢丞相，授講魯諸生。", "五斗青衫色，三湘白髮莖。", "話言猶未盡，要作道州行。"]'),
('c6830892-2fc3-4d43-af3b-3a09f6ec4acf','順陽  其一','張舜民','宋','宋诗','song-poetry','','[]','已免均房險，寬平喜博山。',48,'全唐诗/poet.song.47000.json','["已免均房險，寬平喜博山。", "園林皆掩映，風俗自安閒。", "麻麥三春暮，人烟百里環。", "吾行半天下，難得此江關。"]'),
('cb85aef9-358f-487b-931e-fa8cfcbe4477','順陽  其二','張舜民','宋','宋诗','song-poetry','','[]','隠隠來山遠，茫茫去路平。',48,'全唐诗/poet.song.47000.json','["隠隠來山遠，茫茫去路平。", "舟車楚北戶，城塚漢南京。", "小杏沾花摘，春醪對雨傾。", "士民留我住，强作少陵行。"]'),
('46b01b05-0458-4513-b7c8-a8117a131dc0','鞏州首陽鋪鳥鼠同穴','張舜民','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','本是巢居物，那容鼠穴中。',48,'全唐诗/poet.song.47000.json','["本是巢居物，那容鼠穴中。", "既言無牝牡，何用有雌雄。", "山節曾居蔡，長江網得鴻。", "誰能窮物理，目送渭波東。"]'),
('7c3c0222-7c9a-49a0-9733-cf297d760b50','送鮑經句赴辟洮東幕府','張舜民','宋','宋诗','song-poetry','','[]','平昔通家子，今爲幕府賓。',48,'全唐诗/poet.song.47000.json','["平昔通家子，今爲幕府賓。", "宦遊知幾日，器業已成人。", "隴右從戎客，燕南老病身。", "軍中想多暇，莫惜寄書頻。"]'),
('f95ab68c-171a-43b3-a342-dcd89f00100e','體之推官侍親出使聊書短篇以浼行色','張舜民','宋','宋诗','song-poetry','','[]','遊梁并困洛，誰是故人情。',48,'全唐诗/poet.song.47000.json','["遊梁并困洛，誰是故人情。", "未盡環中說，俄成劍外行。", "路遥詩篋重，雪映綵衣明。", "預想東歸日，相逢指渭城。"]'),
('eb6c967e-fb9d-4b86-a800-d0f1e48d7e01','過同州遇雪贈毌清臣','張舜民','宋','宋诗','song-poetry','','[]','左輔沙如水，長春柳未勻。',48,'全唐诗/poet.song.47000.json','["左輔沙如水，長春柳未勻。", "精神迎刺史，景物爲行人。", "羃䍥梁山外，飄流洛水濱。", "十年門下客，依舊困泥塵。"]'),
('db857778-caac-42da-a81d-675644a8a8e9','花時對雪','張舜民','宋','宋诗','song-poetry','','[]','急霰飄零際，羣芳爛熳中。',48,'全唐诗/poet.song.47000.json','["急霰飄零際，羣芳爛熳中。", "半開先逐水，未落已隨風。", "兵渡金陵破，塵來繡嶺空。", "誰能勞樽酒，暫使客顔紅。"]'),
('7a4c4066-6181-4b9e-ae08-20f27ec44417','西宮致齋貽裴著作','張舜民','宋','宋诗','song-poetry','','[]','西出都門外，塵埃撲馬鞍。',48,'全唐诗/poet.song.47000.json','["西出都門外，塵埃撲馬鞍。", "人家事寒食，星雨仰祠官。", "日永鶑千囀，庭閒竹數竿。", "惟憐隔齋禁，不得共清懽。"]'),
('ddaac9cc-7e9f-4d08-9161-16ab006e905e','南衙寺會宿王鮑二同年','張舜民','宋','宋诗','song-poetry','','[]','徧走長城塞，歸由舜阪頭。',48,'全唐诗/poet.song.47000.json','["徧走長城塞，歸由舜阪頭。", "榜中千里駿，天外二星流。", "花月仍寒雨，關河逼寺樓。", "寧知十年後，此地並衾裯。"]'),
('64dfb847-82ed-4b5a-aeb7-a40732e458e9','組以時果供饋予以酒爲報','張舜民','宋','宋诗','song-poetry','','[]','饉歲無時果，秦人饜草茶。',48,'全唐诗/poet.song.47000.json','["饉歲無時果，秦人饜草茶。", "開奩驚見李，對客喜浮瓜。", "爲乏瓊瑶報，聊稱旨酒嘉。", "中郎不憂老，有女可傳家。"]'),
('f7ca6a3e-6cfd-469c-bc7a-cb0fbe0e767b','哀虢縣令猶子箅  其一','張舜民','宋','宋诗','song-poetry','','[]','匍匐岐山下，三呼已過時。',48,'全唐诗/poet.song.47000.json','["匍匐岐山下，三呼已過時。", "臧孫雖有後，伯道竟無兒。", "自是終身痛，空留一縣悲。", "老人休雨淚，轉面即逢伊。"]'),
('e6f032c2-83ae-42f4-bfe1-eaccf670fed0','哀虢縣令猶子箅  其二','張舜民','宋','宋诗','song-poetry','','[]','送別言猶在，來書墨尚溫。',48,'全唐诗/poet.song.47000.json','["送別言猶在，來書墨尚溫。", "安知咫尺地，便有死生分。", "已負秋山約，猶傳魯史文。", "魂兮今有託，將祔伯兄墳。"]'),
('00ad7abd-16dd-4ba0-8c3a-c97e174862dd','蘇子瞻哀辭','張舜民','宋','宋诗','song-poetry','','[]','石與人俱貶，人亡石尚存。',48,'全唐诗/poet.song.47000.json','["石與人俱貶，人亡石尚存。", "却憐堅重質，不減浪花痕。", "滿酌中山酒，重添丈八盆。", "公兮不歸北，萬里一招魂。"]'),
('da2d9b2d-795c-4ebd-9ed0-3848498271a0','佚老堂爲陶敏宣德題','張舜民','宋','宋诗','song-poetry','','[]','未老剛稱老，言休即便休。',48,'全唐诗/poet.song.47000.json','["未老剛稱老，言休即便休。", "潯陽真有後，彭澤善貽謀。", "隠几悲殘漏，回頭見急流。", "便須移醉石，偃卧北窗幽。"]'),
('ea499888-8bae-4f3a-99b6-dbce879ef28a','杜鵑','張舜民','宋','宋诗','song-poetry','','[]','飛伏終難見，空摶似老烏。',48,'全唐诗/poet.song.47000.json','["飛伏終難見，空摶似老烏。", "一身隨變化，故國任丘墟。", "簇簇花如血，聲聲怨不枯。", "春山情更好，何必夜相呼。"]'),
('394bb2d8-0325-406f-93d7-439d62f9d173','食楊梅荔枝思去年','張舜民','宋','宋诗','song-poetry','','[]','楊梅味已酸，荔子色能丹。',48,'全唐诗/poet.song.47000.json','["楊梅味已酸，荔子色能丹。", "火齊驪龍脫，江綃玉露團。", "謫居深不負，沈醉亦何難。", "今歲無人剝，吁嗟任滿盤。"]'),
('aa21a7d8-b3e9-48b5-bc0d-22b4ab75561f','山果','張舜民','宋','宋诗','song-poetry','','[]','煮酒堆山果，新茶下粉團。',48,'全唐诗/poet.song.47000.json','["煮酒堆山果，新茶下粉團。", "似梅嫌足核，如蜜少加酸。", "公子傾金彈，行人漏蠟丸。", "吾鄉元不識，歸日畫圖看。"]'),
('59399fa0-4d02-4f38-a0b1-cf3ffa518102','宣赦','張舜民','宋','宋诗','song-poetry','','[]','擊鼓填街道，傳聲過水濱。',48,'全唐诗/poet.song.47000.json','["擊鼓填街道，傳聲過水濱。", "國嚴三歲祀，恩洗萬方春。", "舟檝隨南斗，衣冠拱北辰。", "嶺南并嶺北，多少望歸人。"]'),
('5c1656ed-11f0-4c08-ae78-a9019091ba44','秋日燕山道中','張舜民','宋','宋诗','song-poetry','','[]','燕山秋更好，況復值新晴。',120,'全唐诗/poet.song.47000.json','["燕山秋更好，況復值新晴。", "一徑幽花鬧，千巌晚瀑明。", "寺危迂路入，水漫信船行。", "嘗栗皺初破，開梨頰未頳。", "松蘿扶斗上，劍戟插沙平。", "秦趙封疆密，岷峨氣象清。", "五龍丹桂盡，萬馬蹛林橫。", "韞玉人時得，埋錢事可驚。", "畫圖傳輞水，醉倒戀增城。", "爲報南歸客，應須自作程。"]'),
('0efb5725-6dbb-4f56-bac2-df1b1da00ec6','和趙大監雪','張舜民','宋','宋诗','song-poetry','','[]','臘雪稱爲瑞，初春又不同。',120,'全唐诗/poet.song.47000.json','["臘雪稱爲瑞，初春又不同。", "月藏燈市底，雲泛綵山中。", "灑面猶堪數，連宵勢莫窮。", "催花縈小檻，引絮舞低空。", "三逕從誰掃，千門倏自通。", "褵褷消酒力，料峭却東風。", "闊壅平戎幕，孤撐訪戴篷。", "豈期麟趾客，並舍虎門東。", "郢國歌難和，梁園賦易工。", "何人知帝力，鼓腹頌清衷。"]'),
('bbae2b4c-ac8c-407c-81d0-bae2e283f941','東湖春日','張舜民','宋','宋诗','song-poetry','','[]','湖外紅花閒白花，湖邊遊女駐香車。',64,'全唐诗/poet.song.47000.json','["湖外紅花閒白花，湖邊遊女駐香車。", "鞦韆對起花陰亂，蹴鞠孤高柳带斜。", "無數小魚真得所，一雙新燕宿誰家。", "故園風景還如此，極目飛魂逐暮鴉。"]'),
('28c62a0e-5f98-4260-aff2-837bc1167435','所寓開利寺小池有四色蓮花青黄白紅紅者千葉皆北土所未見者也惜其遐陬有此異卉','張舜民','宋','宋诗','song-poetry','','[]','深山草木自幽奇，四色荷花世所稀。',64,'全唐诗/poet.song.47000.json','["深山草木自幽奇，四色荷花世所稀。", "孤獨園中瞻佛眼，凝祥池上捧天衣。", "白公沒後禪林在，王儉歸來幕府非。", "水冷風高人不到，却憐鷗鳥日相依。"]'),
('e8feddf7-d7c5-4b70-9876-e3c5f23527fd','王氏松齋詩','張舜民','宋','宋诗','song-poetry','','[]','人傳半隠在龍門，天啟松齋遇遠孫。',64,'全唐诗/poet.song.47000.json','["人傳半隠在龍門，天啟松齋遇遠孫。", "水石蔽虧包廢寺，版圖磨滅指鄰村。", "如將綠野還裴度，不見潜溪付李藩。", "壁土未乾三易主，洛陽城裏有名園。"]'),
('02e99c95-f3a6-4787-834e-8d35afb65ff0','題融師松齋','張舜民','宋','宋诗','song-poetry','','[]','未解子荆流可枕，冷笑陶令琴無弦。',64,'全唐诗/poet.song.47000.json','["未解子荆流可枕，冷笑陶令琴無弦。", "臨流有耳安用洗，續弦得膠還自煎。", "不禁巢邊黄口鬧，不作竿上鮎魚緣。", "但欲移床倚西壁，共師飽聽松風眠。"]'),
('5e801d81-00f2-4322-9245-1e8d5362299c','鄰居張民師友孝齋','張舜民','宋','宋诗','song-poetry','','[]','歲晚何人念孔懷，北齋風景似南齋。',64,'全唐诗/poet.song.47000.json','["歲晚何人念孔懷，北齋風景似南齋。", "夜寒幾借陽城被，歸興徒穿杜子鞋。", "烏鳥爭巢時墜屋，叢萱得雨亂侵階。", "閉門朗諷閒居賦，一任紅塵漲六街。"]'),
('ff1823b0-1b76-4702-bc82-befb8fe4f880','妙蓮閣','張舜民','宋','宋诗','song-poetry','','[]','休論雪竇與雲峰，且看天台劍戟叢。',64,'全唐诗/poet.song.47000.json','["休論雪竇與雲峰，且看天台劍戟叢。", "萬水千山來閣上，一花六葉現池中。", "誰將色界填空界，不離香風席祖風。", "有底妙蓮談不盡，却成賦筆與興翁。"]'),
('ec2c8925-ea35-4281-aabc-08887a30b905','叢臺','張舜民','宋','宋诗','song-poetry','','[]','荆棘芃芃百尺堆，路人云此是叢臺。',64,'全唐诗/poet.song.47000.json','["荆棘芃芃百尺堆，路人云此是叢臺。", "雨中漳浦明還滅，門外青山去又來。", "歌嘯且從今日樂，是非誰管後人哀。", "靚妝炫服尋爲土，不似昆明塹劫灰。"]'),
('408ce2cf-a9fa-409e-9b91-98019316846e','送鄭平叔司勳之陝二首  其一','張舜民','宋','宋诗','song-poetry','','[]','憶昔垂髫里閈間，披雲常睹一峰巑。',64,'全唐诗/poet.song.47000.json','["憶昔垂髫里閈間，披雲常睹一峰巑。", "青衫白髮經憂患，珥筆含香最歲寒。", "夢寐依稀留北省，家山迤邐近長安。", "下車已接櫻桃會，走馬西歸趁一盤。"]'),
('a15e8628-4ffd-490d-8588-3a66b5e13a57','送鄭平叔司勳之陝二首  其二','張舜民','宋','宋诗','song-poetry','','[]','憧憧大道兩京來，千騎東方最上才。',64,'全唐诗/poet.song.47000.json','["憧憧大道兩京來，千騎東方最上才。", "豈有甘棠存故國，空餘河水繞行臺。", "松筠寂寂徵君宅，簫鼓匆匆過客杯。", "九陌風塵歸未得，不知青眼爲誰開。"]'),
('9f453fcf-7cca-41af-8d04-5d63530963d9','孫賁知衢州去疑冢以其所得雙石作堂乞詩','張舜民','宋','宋诗','song-poetry','','[]','芝蘭雖好忌當門，何況庭前惡土墩。',64,'全唐诗/poet.song.47000.json','["芝蘭雖好忌當門，何況庭前惡土墩。", "畚鍤才興雙劍出，狐狸盡去老松蹲。", "百年守冢真堪笑，一日開軒亦可尊。", "安得擲從天外去，成都石筍至今存。"]'),
('e03b236a-ca30-44a4-a1fe-a459bc1fb756','送比部孫郎中將漕二浙','張舜民','宋','宋诗','song-poetry','','[]','前朝使節擁朱軒，乃是君家小狀元。',64,'全唐诗/poet.song.47000.json','["前朝使節擁朱軒，乃是君家小狀元。", "不獨官資如令祖，更將學術付賢孫。", "上供旋搗新禾米，行部時驚舊水痕。", "遊徧天台便歸好，喬松翠竹滿青門。"]'),
('48eefa24-3003-4b35-a9a1-93de1d643c59','送鞠十二朝散將漕二浙  其一','張舜民','宋','宋诗','song-poetry','','[]','關塞烟塵二十秋，適持使節海山頭。',64,'全唐诗/poet.song.47000.json','["關塞烟塵二十秋，適持使節海山頭。", "行衙到處皆如寺，按部經年不離舟。", "公舉所知當勿枉，上供易足更何求。", "若論安便無加此，祇恐旁求第一流。"]'),
('9c0e586c-7a59-45fa-a502-4ffddf697f06','送鞠十二朝散將漕二浙  其二','張舜民','宋','宋诗','song-poetry','','[]','聞說長安苦戴星，公家無補祇勞形。',64,'全唐诗/poet.song.47000.json','["聞說長安苦戴星，公家無補祇勞形。", "每思肥羜心先寫，今見淮山眼自青。", "豈乏尋常將漕輓，好留人物爲朝廷。", "四明久已無狂客，欲問天工乞箳篂。"]'),
('dc4b6e66-7d90-452d-97e7-1d5ab837586d','送何子溫提刑奉使江東','張舜民','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','奉使江東知幾春，此行重駕赤車輪。',64,'全唐诗/poet.song.47000.json','["奉使江東知幾春，此行重駕赤車輪。", "青綾故被留歸我，白髮祠郎便乞親。", "老大豈堪愁桂玉，秋風依舊長鱸蓴。", "宦途出處何須較，且與廬山作主人。"]'),
('b4483acc-e8ae-496e-a839-f0f2bc0269fd','螢','張舜民','宋','宋诗','song-poetry','','[]','江皋螢火故煇煇，仍解穿簾夜點衣。',64,'全唐诗/poet.song.47000.json','["江皋螢火故煇煇，仍解穿簾夜點衣。", "但取見時增意思，莫嫌生處太卑微。", "月明敢向星中亂，天黑偏能雨裏飛。", "今日分明知我去，何年漂泊照吾歸。"]'),
('4fae167b-42e1-4ff9-83aa-65a41a646b2c','秋日陪陝守成伯閣老過魏清逸草堂詩以誌之','張舜民','宋','宋诗','song-poetry','','[]','何處登臨散鬰陶，草堂依約在東郊。',64,'全唐诗/poet.song.47000.json','["何處登臨散鬰陶，草堂依約在東郊。", "籠中凡鳥迎新網，天外冥鴻委舊巢。", "山色蘢葱煇綵旆，田歌嘔軋雜鳴鐃。", "青編雖有知音絕，可是無人學解嘲。"]'),
('cafb4100-d4e0-4cb2-a215-a41a2a629266','夜聞劉宮苑舟中琵琶詩','張舜民','宋','宋诗','song-poetry','','[]','繫舟江岸兩相聞，弦索嘈嘈恍未分。',64,'全唐诗/poet.song.47000.json','["繫舟江岸兩相聞，弦索嘈嘈恍未分。", "不得長安水邊見，却於湓浦夜深聞。", "窮愁似影長隨我，樂事如年不負君。", "會意檀槽求一醉，世間榮辱任紛紛。"]'),
('f9cbe9cf-5eb0-467f-b967-134f2e621f33','長沙遇雪贈何待制二首  其一','張舜民','宋','宋诗','song-poetry','','[]','初過湖南正慘悽，朔風邊雪遠相隨。',64,'全唐诗/poet.song.47000.json','["初過湖南正慘悽，朔風邊雪遠相隨。", "林欺橘柚看零落，岸拆蒹葭倚倒垂。", "可是輞川真入畫，須教梁苑徧題詩。", "莫言北客都無有，且與湘人當土宜。"]'),
('cb1f7c1f-a632-4f71-a65c-0a12565af449','長沙遇雪贈何待制二首  其二','張舜民','宋','宋诗','song-poetry','','[]','由來地氣本無天，致感中和報有年。',64,'全唐诗/poet.song.47000.json','["由來地氣本無天，致感中和報有年。", "拂檻穿簾初學舞，縈風带雨不成團。", "清光併入書仙府，寒色偏留逐客船。", "老杜題詩曾有乞，漂零今昔路人憐。"]'),
('06ee0bf5-3360-4c61-bda7-fdd8cc5add24','和同使鄭內藏見貽之作','張舜民','宋','宋诗','song-poetry','','[]','仗節傳呼出紫宸，燕南薊北望車塵。',64,'全唐诗/poet.song.47000.json','["仗節傳呼出紫宸，燕南薊北望車塵。", "身爲五郡循良守，家是三朝宿衛臣。", "對榻夢魂思共得，據鞍吟嘯喜相親。", "驛亭處處逢花發，疑是春光解送人。"]'),
('7be14fad-57a3-464a-8317-9022b661d936','梁才甫自湖南移使廣西移使廣東自廣東復移湖外三年之間周歷四路今者北還已越郴嶺道次作詩見寄渴於會遇謹用賡和','張舜民','宋','宋诗','song-poetry','','[]','天際雲帆百尺開，廣西移去廣東回。',64,'全唐诗/poet.song.47000.json','["天際雲帆百尺開，廣西移去廣東回。", "未成老大歸朝計，且喜平安出嶺來。", "竹馬共迎新使節，松齋暗鎖舊莓苔。", "回思託蔭無多日，早至瀟湘欲重陪。"]'),
('0ac14cb8-6a45-46a2-b0d5-0e1f3d871143','同劉貢甫學士登石鼓合江亭一首','張舜民','宋','宋诗','song-poetry','','[]','乘興俄成石鼓游，可堪摇落楚江秋。',64,'全唐诗/poet.song.47000.json','["乘興俄成石鼓游，可堪摇落楚江秋。", "巌中名字今何在，亭下瀟湘古亦愁。", "萬里再驚金馬客，一家重上木蘭舟。", "却令二水知人意，合勢相邀向北流。"]'),
('43855b98-923d-42c3-9946-954132a89efe','舟行湘岸見早梅盛開','張舜民','宋','宋诗','song-poetry','','[]','江上籬邊見早梅，天寒地暖數枝開。',64,'全唐诗/poet.song.47000.json','["江上籬邊見早梅，天寒地暖數枝開。", "爲憐北客漂流遠，偷報東君信息回。", "香氣輕於新釀熟，襟懷重似故人來。", "舟中莫問無兼有，急急呼兒貰酒杯。"]'),
('e151e5e5-a46e-48d9-bb6a-8133b066b7f0','再過黄州蘇子瞻東坡雪堂因書即事題於武昌王叟齋扉','張舜民','宋','宋诗','song-poetry','','[]','欹帆側柂嶺邊歸，重過東坡叩竹扉。',64,'全唐诗/poet.song.47000.json','["欹帆側柂嶺邊歸，重過東坡叩竹扉。", "床坐凝塵風自掃，江山無主燕空飛。", "門前桃李添新逕，井畔梧桐長舊圍。", "好在江南王釣叟，爲君時復曬漁衣。"]'),
('10fb6f79-ed71-4446-adf9-ea3a81489011','灑然堂','張舜民','宋','宋诗','song-poetry','','[]','何必徜徉水石間，聽君言語已孱顔。',64,'全唐诗/poet.song.47000.json','["何必徜徉水石間，聽君言語已孱顔。", "三湘盡處猶逢竹，五嶺回時却見山。", "吏案總教如雁進，靈源我且似鷗閒。", "天邊猿鶴皆相識，惟欠携筇日往還。"]'),
('222f1e6d-0a5e-486e-a925-cd46acdd5cd1','壬戌孫覽右司同年以詩見寄用韵和酬','張舜民','宋','宋诗','song-poetry','','[]','孫郎卧省正當年，曾奏嘉謀玉扆邊。',64,'全唐诗/poet.song.47000.json','["孫郎卧省正當年，曾奏嘉謀玉扆邊。", "事契且論龍虎榜，行藏休問孝廉船。", "從軍脫略矜橫槊，禦魅遷流喜執鞭。", "莫怪子雲知遇晚，勒銘終欲上燕然。"]'),
('679d1f07-1874-447c-98e8-d4ebd58f6b1f','過山陽有懷','張舜民','宋','宋诗','song-poetry','','[]','山陽過處苦匆匆，想見平生水陸衝。',64,'全唐诗/poet.song.47000.json','["山陽過處苦匆匆，想見平生水陸衝。", "但有酒杯浮綠蟻，却無賦筆寫游龍。", "江湖風浪三千里，京國鶑花一萬重。", "他日君恩容北首，故人能作復從容。"]'),
('3b995737-8b59-4537-b43e-d51c3797d7e3','書薛紹彭詩編','張舜民','宋','宋诗','song-poetry','','[]','白楊宿草幾離披，忽對遺編動永思。',64,'全唐诗/poet.song.47000.json','["白楊宿草幾離披，忽對遺編動永思。", "棠棣先凋空浩歎，圖書不展已多時。", "豈惟獨負遊山約，何意重看送我詩。", "今日山翁悲復喜，薛家門裏有孤兒。"]'),
('bb027ff6-8ffd-44b8-a474-713a0c00b699','凌虛臺','張舜民','宋','宋诗','song-poetry','','[]','岐山四合與臺平，半露園林葉未成。',64,'全唐诗/poet.song.47000.json','["岐山四合與臺平，半露園林葉未成。", "是處芳菲皆可惜，晚來風雨太無情。", "山川不改秦雲色，宮室長懸隴水聲。", "惟有故園終不見，倉庚黄鳥向人鳴。"]'),
('bcd14326-3a51-49aa-9932-723db27f940b','原州贈王補之洛苑同年','張舜民','宋','宋诗','song-poetry','','[]','汴上相從又幾星，尚淹符竹守臨涇。',64,'全唐诗/poet.song.47000.json','["汴上相從又幾星，尚淹符竹守臨涇。", "不須怪我頭添白，且喜逢君眼暫青。", "舊任再游空寂寞，同年屈數半凋零。", "何當展盡平邊策，圖使秦民得敉寧。"]'),
('a7811184-8075-48ae-8439-cea3ac7435be','送章質夫同年','張舜民','宋','宋诗','song-poetry','','[]','同年事契最知名，衆謂朝廷得老成。',64,'全唐诗/poet.song.47000.json','["同年事契最知名，衆謂朝廷得老成。", "感慨共論平昔事，蹉跎還累故人情。", "節旄落盡髭仍黑，髀肉消殘寵未驚。", "若過函關須北望，皚然依復俟河清。"]'),
('093f4b0c-b7bd-4941-b451-677bc328fb02','九日和檢法登高之作','張舜民','宋','宋诗','song-poetry','','[]','重陽何處可登臨，獨有條山可共尋。',64,'全唐诗/poet.song.47000.json','["重陽何處可登臨，獨有條山可共尋。", "世上幾人能到此，樽前萬事莫相侵。", "溪風獵獵時吹帽，菊蕊紛紛易滿襟。", "莫爲嘉辰頻索醉，也須隨分惜光陰。"]'),
('93eb845d-3a00-468d-9e24-b11eb0bf6f75','和人歲暮書懷','張舜民','宋','宋诗','song-poetry','','[]','星回律變數將終，二十年前此邑中。',64,'全唐诗/poet.song.47000.json','["星回律變數將終，二十年前此邑中。", "天令尚隨新歲改，人顔那得舊時紅。", "家無妻妾仍多難，腹有詩書可屢空。", "莫笑鄭人欺子産，到頭留得惠民功。"]'),
('16e92a9a-fbc9-43e2-a484-b8f408a0b3b2','至瀛州小雪貽蔣穎叔','張舜民','宋','宋诗','song-poetry','','[]','梁苑瑶池醉夢闌，忽隨北客度燕山。',64,'全唐诗/poet.song.47000.json','["梁苑瑶池醉夢闌，忽隨北客度燕山。", "馬頭點綴飛才密，日脚微明意尚慳。", "疏布久拋南海上，貂裘初襲兩河間。", "好留幕府陪樽俎，剛被行人不放閒。"]'),
('d0e3793a-713d-407d-ac37-e48450dc04ef','十月十九日諸講官晨趨邇英前夕初雪沾洽尋有旨權住講一日既而同子開內翰正夫侍郎元功舍人少竚資善一飫而出諸公嘉其景而被上恩乃謂衰薄不可無作聊書長句深愧斐然','張舜民','宋','宋诗','song-poetry','','[]','西風拔地夜飄霙，天惠臚傳講暫停。',64,'全唐诗/poet.song.47000.json','["西風拔地夜飄霙，天惠臚傳講暫停。", "病眼昏花逋讀史，高談快論阻橫經。", "御溝容與冰初合，苑柳扶疏葉未零。", "可是太平占上瑞，衰才殊不解丹青。"]'),
('58e10154-121a-4987-84df-3faae6cc3a63','部役書懷','張舜民','宋','宋诗','song-poetry','','[]','近市銅章泊近郊，炯無塵慮挂秋毫。',64,'全唐诗/poet.song.47000.json','["近市銅章泊近郊，炯無塵慮挂秋毫。", "含宏品彙知天大，照鑒容光仰日高。", "市舍柔桑圍幄幙，弄風新麥泛波濤。", "巷歌野哭應聽取，珍重吾家製錦刀。"]'),
('444306f6-1c73-408b-972e-d4fc4c2593a6','還卷答徐長官','張舜民','宋','宋诗','song-poetry','','[]','才士生平多薄命，文章自昔少知音。',64,'全唐诗/poet.song.47000.json','["才士生平多薄命，文章自昔少知音。", "增添行李妨爲客，搜攪肝腸枉用心。", "高閣書存終覆瓿，長門賦麗偶遺金。", "雲臺幸有功名望，何必孜孜泥古今。"]'),
('26f28248-26f8-417e-b180-016ba5c06941','和答還卷','張舜民','宋','宋诗','song-poetry','','[]','屈宋功成道不傳，後來雞犬各登仙。',64,'全唐诗/poet.song.47000.json','["屈宋功成道不傳，後來雞犬各登仙。", "留連光景隨時俗，盜竊聲名至暮年。", "陷沒李陵因北伐，漂流杜甫爲南遷。", "耒陽郴口今吾在，誰與誅茅屋數椽。"]'),
('a1688972-4775-43ba-bad2-cb65bf7bce20','和陳憲車蠟梅','張舜民','宋','宋诗','song-poetry','','[]','黄宮暖律暗相催，臘後春前見蠟梅。',64,'全唐诗/poet.song.47000.json','["黄宮暖律暗相催，臘後春前見蠟梅。", "青帝不知無蝶至，黄花先賞有蜂來。", "風飄嫩蕊添鶑羽，雪駕寒香入酒杯。", "盡道此花居第一，如何更有百花開。"]'),
('11b2854b-d04b-43a9-95e7-c93e14ba4a5d','秋晚三首  其一','張舜民','宋','宋诗','song-poetry','','[]','久雨秋深對晚晴，近山昏黑遠山明。',64,'全唐诗/poet.song.47000.json','["久雨秋深對晚晴，近山昏黑遠山明。", "灘頭艇子排行繫，水底魚兒作隊行。", "衰柳带風猶喜舞，殘蟬送日尚能鳴。", "角冠藜杖何爲者，獨向溪邊忘姓名。"]'),
('f0effbf3-09c4-468e-8211-f2b185bbe3ec','秋晚三首  其二','張舜民','宋','宋诗','song-poetry','','[]','官事私憂總不論，每于樓上到黄昏。',64,'全唐诗/poet.song.47000.json','["官事私憂總不論，每于樓上到黄昏。", "江城日暮須吹角，野寺僧歸自掩門。", "秋晚山川多草木，年豐場圃足雞豚。", "人生幾有淵明樂，稚子迎門酒滿樽。"]'),
('c8cc768a-06df-401c-97c5-5f1547d9c62a','秋晚三首  其三','張舜民','宋','宋诗','song-poetry','','[]','誰把霜林染得紅，更栽綠竹與長松。',64,'全唐诗/poet.song.47000.json','["誰把霜林染得紅，更栽綠竹與長松。", "家家白酒連宵醉，處處新禾徹夜舂。", "半落園林懸橘柚，低回門巷映芙蓉。", "沙鷗性在終難狎，祇解沙頭印脚蹤。"]'),
('5bab51ea-eba9-40a1-aa67-e536fb6d39c0','裴綸著作見期行日延宿所居既至裴已行因書寄此','張舜民','宋','宋诗','song-poetry','','[]','都城人事日烹煎，跳出都門意已仙。',64,'全唐诗/poet.song.47000.json','["都城人事日烹煎，跳出都門意已仙。", "摩詰舊聞空一室，祖生何事忽先鞭。", "塵埃馬上同看月，絺綌風中共聽蟬。", "我復西還君北去，箕山潁水自蕭然。"]'),
('4b6ddd3f-e793-4f8a-a3d1-9ac06563f780','送辛著作罷榮河','張舜民','宋','宋诗','song-poetry','','[]','常笑三閭老大夫，枉將憔悴付江魚。',64,'全唐诗/poet.song.47000.json','["常笑三閭老大夫，枉將憔悴付江魚。", "爲儒須較身名重，入仕先將喜慍除。", "莫顧他門堪炙手，且教我腹可回車。", "此行愧乏瓊瑶贈，聊比詩人一束芻。"]'),
('0b32fce6-42ae-48d8-9b16-3d6393b1dedc','題三水縣舍左幾著作','張舜民','宋','宋诗','song-poetry','','[]','還鄉去日正遲遲，枉道相過慰所思。',64,'全唐诗/poet.song.47000.json','["還鄉去日正遲遲，枉道相過慰所思。", "歷國聘君良自苦，敝衣懷組欲誰欺。", "白楊葉上三更雨，黄菊風前一酒巵。", "莫道相逢是容易，與君頭鬢各絲絲。"]'),
('a72c5f1a-415f-4bf8-99e7-dc40fb4fd871','中宮致齋','張舜民','宋','宋诗','song-poetry','','[]','重重絳闕隠琳房，落絮飛花日正長。',64,'全唐诗/poet.song.47000.json','["重重絳闕隠琳房，落絮飛花日正長。", "著作未諳青鎖闥，祠官還伴紫微郎。", "林藏鵯鴂隨鶑囀，風引酴醾助酒香。", "十載京城倦遊客，不知身世在何鄉。"]'),
('45697960-b51b-49f2-a18a-c580b9609e3a','呂子固小女哀辭','張舜民','宋','宋诗','song-poetry','','[]','伯道無兒可典刑，中郎有女最聰明。',64,'全唐诗/poet.song.47000.json','["伯道無兒可典刑，中郎有女最聰明。", "季拏却返商山葬，阿軟空留洛下情。", "令祖六男皆磊落，名孫一女又凋零。", "茫茫此理終難問，忍聽人間哭子聲。"]'),
('a266333f-0fde-4957-92d4-17b6edd740a9','雙松堂','張舜民','宋','宋诗','song-poetry','','[]','歎息前人布政優，手栽松竹助清幽。',64,'全唐诗/poet.song.47000.json','["歎息前人布政優，手栽松竹助清幽。", "當年撥土人何在，今日捎雲勢未休。", "直幹幾排雷雨怒，細聲常伴管弦愁。", "若爲喚起王摩詰，畫箇浮休倚白頭。"]'),
('cb10c910-e0e5-4b29-99f7-d097b1119cc1','賜資治通鑑呈范淳父學士','張舜民','宋','宋诗','song-poetry','','[]','通鑑初成賜近臣，不遺疏賤布恩均。',64,'全唐诗/poet.song.47000.json','["通鑑初成賜近臣，不遺疏賤布恩均。", "我投淮水五千里，君滯周南二十春。", "東觀汗青身是夢，西宮削稿事如新。", "細思當日修書者，祇有三人今一人。"]'),
('545d4514-634b-49fe-ab24-8bcb102ade17','鄧正字宅見劉明復所畫麓山秋景','張舜民','宋','宋诗','song-poetry','','[]','洛陽才子見長沙，自識中丹鬢未華。',64,'全唐诗/poet.song.47000.json','["洛陽才子見長沙，自識中丹鬢未華。", "文武才全皆不試，丹青筆妙更誰加。", "老杉列在堂皇上，小景將歸學士家。", "我有故山常自寫，免教魂夢落天涯。"]'),
('7bf1fcb8-3ac3-474d-abd8-bbd613a260c0','感時事戲作','張舜民','宋','宋诗','song-poetry','','[]','少年辛苦校蟲魚，晚歲雕蟲恥壯夫。',64,'全唐诗/poet.song.47000.json','["少年辛苦校蟲魚，晚歲雕蟲恥壯夫。", "自是諸生猶習氣，果然紫詔盡驅除。", "酒間李賀皆投筆，地下班揚亦引車。", "惟有少陵頑鈍叟，靜中吟撚白髭鬚。"]'),
('1a147d3b-b2dc-4c10-ae6f-7d009c088d2a','真州儀真觀','張舜民','宋','宋诗','song-poetry','','[]','聞說仙鄉接瀨鄉，閒遊詩侶禮虛皇。',64,'全唐诗/poet.song.47000.json','["聞說仙鄉接瀨鄉，閒遊詩侶禮虛皇。", "三潮寶派通胥浦，萬葉靈杉蔽蜀岡。", "天地杳冥供寫像，江山迴合助靈祥。", "五雲送入蓬萊島，留與人間作道場。"]'),
('68b7c446-fade-44fb-8a3f-cc76084e1812','離真州','張舜民','宋','宋诗','song-poetry','','[]','日日北風吹上水，年年客思攪新秋。',64,'全唐诗/poet.song.47000.json','["日日北風吹上水，年年客思攪新秋。", "山長水遠連三楚，物態人情又一州。", "隔岸晚峰如見揖，竝船孤鶩似相留。", "因知景略非前達，身後猶須具十牛。"]'),
('03185f70-acdf-432c-9f41-a9aad768329d','和喻明仲馬上吹笛','張舜民','宋','宋诗','song-poetry','','[]','越客思歸黯不平，閒持長笛寫秦聲。',64,'全唐诗/poet.song.47000.json','["越客思歸黯不平，閒持長笛寫秦聲。", "羨君氣海如斯壯，博我詞鋒莫敢爭。", "江上梅花開又落，隴頭流水咽還驚。", "豈知不寐鰥魚眼，獨坐山堂對月明。"]'),
('52190ae4-3e96-4421-91a6-93d1b4b1265c','題木居士','張舜民','宋','宋诗','song-poetry','','[]','波穿火透本無奇，初見潮州刺史詩。',64,'全唐诗/poet.song.47000.json','["波穿火透本無奇，初見潮州刺史詩。", "當日老翁終不免，後來居士欲奚爲。", "山中雷雨誰宜主，水底蛟龍睡不知。", "若使天年俱自遂，如今已復長孫枝。"]'),
('0638ccd6-f03b-4d7c-96c7-1d7e3dbae582','月臺','張舜民','宋','宋诗','song-poetry','','[]','明月光常滿，使君罇屢開。',24,'全唐诗/poet.song.47000.json','["明月光常滿，使君罇屢開。", "何須待月上，日暮便登臺。"]'),
('13462a78-1831-46c6-a26f-c66f457c90c1','宴橋上','張舜民','宋','宋诗','song-poetry','','[]','橋上置杯盤，可容十客坐。',24,'全唐诗/poet.song.47000.json','["橋上置杯盤，可容十客坐。", "遊人撐小艇，却從橋下過。"]'),
('efddb22e-f129-4ad6-8e04-f8386b548b35','吳山堂','張舜民','宋','宋诗','song-poetry','','[]','楚客對吳山，歸心常自苦。',24,'全唐诗/poet.song.47000.json','["楚客對吳山，歸心常自苦。", "守土切須防，半夜俱飛去。"]'),
('5f28a351-39c6-4a74-b976-79ece32dfab0','嶽麓寺  其一','張舜民','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','初投旱海戈，忽整瀟湘枻。',24,'全唐诗/poet.song.47000.json','["初投旱海戈，忽整瀟湘枻。", "彭蠡鏡中行，洞庭天外倚。"]'),
('3f3c895f-1ba3-428b-a070-0bab369db9db','嶽麓寺  其二','張舜民','宋','宋诗','song-poetry','','[]','携杖溪邊聽，抱琴臺上坐。',24,'全唐诗/poet.song.47000.json','["携杖溪邊聽，抱琴臺上坐。", "我喜見江山，江山愁見我。"]'),
('d6b73ceb-1bd4-420a-b5f6-a233f9996507','卧治齋詩','張舜民','宋','宋诗','song-poetry','','[]','爲治固有術，公卧有人立。',24,'全唐诗/poet.song.47000.json','["爲治固有術，公卧有人立。", "直須緊閉關，勿使龐公入。"]'),
('df996706-b6e4-4042-9ffe-51137871e4a4','濟川堂','張舜民','宋','宋诗','song-poetry','','[]','河流便當城，峻嶺借爲屏。',24,'全唐诗/poet.song.47000.json','["河流便當城，峻嶺借爲屏。", "疑在金山寺，憑欄看北泠。"]'),
('89182550-ad80-46cf-982e-2389c97a5edc','爲圃','張舜民','宋','宋诗','song-poetry','','[]','前人厭膏粱，志欲服賤事。',24,'全唐诗/poet.song.47000.json','["前人厭膏粱，志欲服賤事。", "若論區別功，爲圃亦不易。"]'),
('2f3b965d-5571-42ff-b3d9-fe8d1eadb507','過魏文貞公舊莊','張舜民','宋','宋诗','song-poetry','','[]','破屋居人少，柴門春草長。',24,'全唐诗/poet.song.47000.json','["破屋居人少，柴門春草長。", "兒童不識字，耕稼鄭公莊。"]'),
('aaf3cf5e-7069-45b4-afb7-7a3239a38a50','邠詩人張谷齊物先生馳名京師四方晚隠於終南山黄池谷陝右多畫爲醉仙因贈繪者','張舜民','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','能吟解飲張夫子，醉卧黄池谷口風。',32,'全唐诗/poet.song.47000.json','["能吟解飲張夫子，醉卧黄池谷口風。", "天地至寬容不得，勞君收拾畫圖中。"]'),
('1c30514f-731e-4718-92b5-95ebdf7c2ca4','長干寺同劉宮苑浴  其一','張舜民','宋','宋诗','song-poetry','','[]','人看浴出如枯木，我自無心類死灰。',32,'全唐诗/poet.song.47000.json','["人看浴出如枯木，我自無心類死灰。", "在處秋風吹鬢髮，不堪更上雨花臺。"]'),
('c9d32e9e-5956-431e-8da5-294a4234d333','長干寺同劉宮苑浴  其二','張舜民','宋','宋诗','song-poetry','','[]','未知何處是吾廬，南北悠悠意所如。',32,'全唐诗/poet.song.47000.json','["未知何處是吾廬，南北悠悠意所如。", "不愛渭川千畝竹，與君江上卜新居。"]'),
('4d87fb4a-6a2c-4cfe-b35f-8abcbd4793ec','繡鶴竹','張舜民','宋','宋诗','song-poetry','','[]','好客精神來萬里，此君風格聳雙枝。',32,'全唐诗/poet.song.47000.json','["好客精神來萬里，此君風格聳雙枝。", "丹青絕筆真難得，不似佳人粉錦時。"]'),
('c7c41abb-82bc-4336-a0de-5730be1c274e','弔太白','張舜民','宋','宋诗','song-poetry','','[]','采石山頭秋月明，姑孰堂下秋水清。',32,'全唐诗/poet.song.47000.json','["采石山頭秋月明，姑孰堂下秋水清。", "可恨世人皆捉月，如何偏解溺先生。"]'),
('1c2fbc2b-acd5-4702-be10-829b5abbb44a','登樓','張舜民','宋','宋诗','song-poetry','','[]','繁華蓋盡一時間，烟雨濛濛氣象閒。',32,'全唐诗/poet.song.47000.json','["繁華蓋盡一時間，烟雨濛濛氣象閒。", "今日登臨何所似，慈恩塔上望南山。"]'),
('5899ff38-5ddf-4a8e-8d2f-4f49b18ea207','起桅','張舜民','宋','宋诗','song-poetry','','[]','百尺危檣一尺烏，一夫擊鼓百夫呼。',32,'全唐诗/poet.song.47000.json','["百尺危檣一尺烏，一夫擊鼓百夫呼。", "何似北人將遠適，呼童秣馬與膏車。"]'),
('e3424526-a3f1-45e6-a385-3e268c066a9a','元豐癸亥秋季赴官郴嶺艤舟樊口與潘彥明范亨父以小艇過吉陽寺是日大風雨雪','張舜民','宋','宋诗','song-poetry','','[]','江上秋風九日寒，故人樽酒暫相歡。',32,'全唐诗/poet.song.47000.json','["江上秋風九日寒，故人樽酒暫相歡。", "如何塞北無窮雪，却坐樊山竹萬竿。"]'),
('800c7b03-e39e-45bb-927c-98b65198769d','下灘二絕句  其一','張舜民','宋','宋诗','song-poetry','','[]','下得寒灘水漫流，山平水遠更清幽。',32,'全唐诗/poet.song.47000.json','["下得寒灘水漫流，山平水遠更清幽。", "幾何舟楫隨風去，唯有漁人得自由。"]'),
('2c1273aa-5216-430b-93cc-8c6c9190d1f5','下灘二絕句  其二','張舜民','宋','宋诗','song-poetry','','[]','江風淅淅似相催，綠竹丹楓去又來。',32,'全唐诗/poet.song.47000.json','["江風淅淅似相催，綠竹丹楓去又來。", "任使雲帆能破浪，不知歸客已心灰。"]'),
('f87c5272-7181-4414-ba10-e02008199ed8','望子嶺梅花方開用黄道韵','張舜民','宋','宋诗','song-poetry','','[]','木海亭前花似錦，嶺頭梅蘂怯風沙。',32,'全唐诗/poet.song.47000.json','["木海亭前花似錦，嶺頭梅蘂怯風沙。", "正如隠者歸幽谷，鶴版徵書未到家。"]'),
('729ba2de-52ea-4f7d-9f40-60d869282639','杜城茅齋二首  其一','張舜民','宋','宋诗','song-poetry','','[]','已分長招湘水魂，安知却返杜陵村。',32,'全唐诗/poet.song.47000.json','["已分長招湘水魂，安知却返杜陵村。", "陸居無屋舟無水，坐看南山飛白雲。"]'),
('855e895f-2319-4f3f-ad75-fc4ba3a33265','杜城茅齋二首  其二','張舜民','宋','宋诗','song-poetry','','[]','多謝村人亮素貧，牆垣雖設不關門。',32,'全唐诗/poet.song.47000.json','["多謝村人亮素貧，牆垣雖設不關門。", "一杯藜粥茅亭上，卧看南山飛白雲。"]'),
('0f481055-2940-4d00-b405-df5e2144e99b','均州南川春日三首  其一','張舜民','宋','宋诗','song-poetry','','[]','水墨屏風遠近開，人烟隠映水環回。',32,'全唐诗/poet.song.47000.json','["水墨屏風遠近開，人烟隠映水環回。", "何人學得愚公術，故意移將灞滻來。"]'),
