('0b8bae89-28fa-4151-9a25-37395d5c5dd4','九日','張舜民','宋','宋诗','song-poetry','','[]','一見黄花只自羞，蕭然短髮不禁秋。',32,'全唐诗/poet.song.47000.json','["一見黄花只自羞，蕭然短髮不禁秋。", "誰人爲整烏紗帽，獨倚西風滿眼愁。"]'),
('d3d6ab7c-5342-4022-8cb9-cd219d636791','酴醾','張舜民','宋','宋诗','song-poetry','','[]','冰肌雪艷映殘春，燠日薰風入四鄰。',32,'全唐诗/poet.song.47000.json','["冰肌雪艷映殘春，燠日薰風入四鄰。", "任是主人能愛惜，也拚一半與遊人。"]'),
('12b4fd2e-6bdb-4a52-85c4-9562c36c4c72','真珠花','張舜民','宋','宋诗','song-poetry','','[]','風中的皪月中看，解作人間五月寒。',32,'全唐诗/poet.song.47000.json','["風中的皪月中看，解作人間五月寒。", "一似漢宮梳洗了，玉瓏璁壓翠雲冠。"]'),
('063b4e8b-9dfe-416a-91c4-efcaf1c14fed','上潁昌韓少師丞相兄弟','張舜民','宋','宋诗','song-poetry','','[]','五福猶來萃一門，歲寒方始見松筠。',64,'全唐诗/poet.song.47000.json','["五福猶來萃一門，歲寒方始見松筠。", "白頭再喜逢知己，青眼重開爲故人。", "當日八龍同孝友，于今二阮卜比鄰。", "莫年不作三湘客，猶欲生還一吐茵。"]'),
('3714fe8e-e7aa-4fe4-99ef-8d8faac69f20','北歸再過洞庭','張舜民','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我家本住長安陌，涇渭交流出坐隅。',32,'全唐诗/poet.song.47000.json','["我家本住長安陌，涇渭交流出坐隅。", "須信宦遊皆有地，十年四過洞庭湖。"]'),
('973141de-33a0-4ad9-b30f-26a9f02dc922','東湖晚眺','張舜民','宋','宋诗','song-poetry','','[]','白鷺雙飛過女牆，兩行高柳正斜陽。',32,'全唐诗/poet.song.47000.json','["白鷺雙飛過女牆，兩行高柳正斜陽。", "荷花滿眼都無主，闇裏風飄入袖香。"]'),
('908660a8-0a2a-4f74-8154-e075d829a29b','和邠倅王正夫大夫遊西湖','張舜民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨過花開一郡忙，紫微山影照湖光。',64,'全唐诗/poet.song.47000.json','["雨過花開一郡忙，紫微山影照湖光。", "東風不費舟船力，暖日能添羅綺香。", "已拚今朝須盡醉，預愁明日又辭鄉。", "飽聞馮翊無花草，唯有城頭至樂堂。"]'),
('08ceda5d-0cf8-470a-963e-d538edfb668a','北湖集句','張舜民','宋','宋诗','song-poetry','','[]','北湖泛空明，移舟泊滄渚。',144,'全唐诗/poet.song.47000.json','["北湖泛空明，移舟泊滄渚。", "篙師暗理楫，宛轉到深處。", "回流抱絕巘，長烟曳輕素。", "山明望松雪，湖闇兼雲霧。", "遥風送管弦，白日無塵土。", "皎鏡含虛碧，瘴烟跕飛羽。", "高冢空纍纍，昔時卿相墓。", "郴州頗凉冷，滄洲有奇趣。", "逐客久憔悴，世途多禮數。", "孤影空相隨，不知從此去。", "終朝對樽酒，况復天景暮。", "樂罷不無悲，却尋故鄉路。"]'),
('1523de04-8022-4ff6-9f26-0033dc3d676f','南歸早發柳湖','張舜民','宋','宋诗','song-poetry','','[]','殘月光中强攬衣，欲隨烏鵲向南飛。',32,'全唐诗/poet.song.47000.json','["殘月光中强攬衣，欲隨烏鵲向南飛。", "無端客夢難收拾，落在西城晚不歸。"]'),
('cd833cb6-e54f-4e17-b702-1570210f5abc','送吳都曹還蕪湖','張舜民','宋','宋诗','song-poetry','','[]','柳嶺相從歲屢遷，南湖同泛又經年。',64,'全唐诗/poet.song.47000.json','["柳嶺相從歲屢遷，南湖同泛又經年。", "齋前怪石曾爲枕，門外長楊憶繫船。", "白酒一壺賢聖樂，古書千卷弟兄傳。", "九衢塵土忙如火，握手相看思黯然。"]'),
('b4c5eb10-4bd5-4a3a-afec-3bcee0e9506f','城上烏','張舜民','宋','宋诗','song-poetry','','[]','城上烏，山頭月，幾點殘星滅不滅，營中角聲鳴咽咽。',72,'全唐诗/poet.song.47000.json','["城上烏，山頭月，幾點殘星滅不滅，營中角聲鳴咽咽。", "戰馬嘶，征人發，堂上雙親垂白髮，閨中少婦年二八。", "爺牽衣，兒抱膝，東鄰西鄰哭聲一，道上行客腸斷絕。"]'),
('95c3a724-dbb2-4b3a-b393-c8cb74bc4a6a','贈杜山人','張舜民','宋','宋诗','song-poetry','','[]','才疏性懶一微官，終日沉埋塵土間。',32,'全唐诗/poet.song.47000.json','["才疏性懶一微官，終日沉埋塵土間。", "安得便爲歸去計，共君吟詠伴君閑。"]'),
('1887e545-b030-4114-862a-b8d9d4ce622d','長盤嶺遇張復鄉人','張舜民','宋','宋诗','song-poetry','','[]','馬頭已匝三千里，故國輕拋二十年。',32,'全唐诗/poet.song.47000.json','["馬頭已匝三千里，故國輕拋二十年。", "一片青山雙鬢白，長盤嶺下見鄉人。"]'),
('a5db6db3-13ea-49ce-893e-6cb8a7c3d83b','望行人  其一','張舜民','宋','宋诗','song-poetry','','[]','望行人，行人在何所。',52,'全唐诗/poet.song.47000.json','["望行人，行人在何所。", "燕雁不齊飛，參商竟相阻。", "別以三秋爲久，生以百歲爲期。", "不如還家對親戚，浮名浮利徒爾爲。"]'),
('ce9ace6c-1f5d-47cd-86b6-6f88eabfd685','望行人  其二','張舜民','宋','宋诗','song-poetry','','[]','登高恨不高，望遠恨不見。',48,'全唐诗/poet.song.47000.json','["登高恨不高，望遠恨不見。", "不見遠征人，但見青山晚。", "今歲雁空回，明年燕又來。", "燕雁無憑訊，何用上高臺。"]'),
('7d389aac-267b-4459-aa8e-6c030fbda2d7','胡無人','張舜民','宋','宋诗','song-poetry','','[]','洛陽一少年，善達古今事。',56,'全唐诗/poet.song.47000.json','["洛陽一少年，善達古今事。", "意欲隳單于，慨然陳五餌。", "當時長安以爲笑，今日施行獲其利。", "信哉敢謂胡無人，歲歲叩關來請吏。"]'),
('2818aff8-fbe6-435e-a77a-94ddf62a4b90','黄陵題詠','張舜民','宋','宋诗','song-poetry','','[]','簫韶不返九疑愁，雙鳳追思楚水秋。',64,'全唐诗/poet.song.47000.json','["簫韶不返九疑愁，雙鳳追思楚水秋。", "褘翟飄摇摧畫壁，珮環零落掛簾鈎。", "春深蘭芷供香案，日暮烏鳶送客舟。", "自是江湖清絕處，後人憔悴寫離憂。"]'),
('f29365ae-4adc-4350-952a-e85d137abf8e','南嶽','張舜民','宋','宋诗','song-poetry','','["\u8861\u5c71"]','它國西南隅，亙地岣嶁外。',36,'全唐诗/poet.song.47000.json','["它國西南隅，亙地岣嶁外。", "奇峰七十二，主客雅相對。", "轍在想虔游，銘知知禹會。"]'),
('a1d3c056-def0-4a59-a126-cc14a78bfe05','邠守李中散取鄉人謝事者三人繪像邠學號三友堂予己記之復徵詩','張舜民','宋','宋诗','song-poetry','','[]','出仕歸來義兩全，真從髫齓至華顛。',64,'全唐诗/poet.song.47000.json','["出仕歸來義兩全，真從髫齓至華顛。", "儒冠繪像爲三友，龜佩相輝是四賢。", "莫與後生論損益，且於見世作神仙。", "東都九老誇榮貴，未比南豳德行先。"]'),
('9669ba8b-0383-42b7-b2f6-2b6d84fee7ea','復拜朝散郎','張舜民','宋','宋诗','song-poetry','','[]','曾爲朝散已多時，起廢皇恩許再爲。',64,'全唐诗/poet.song.47000.json','["曾爲朝散已多時，起廢皇恩許再爲。", "學得子文無慍色，笑他白老强題詩。", "雖無妄想追前境，猶有貪心刻後期。", "祇向今冬求致仕，要將恩澤與孫兒。"]'),
('e951da5e-b53d-4d38-9fcd-bf0260ea706d','送孫積中兄待次吳興','張舜民','宋','宋诗','song-poetry','','[]','驊騮不惜換舟行，人到歸時意氣生。',64,'全唐诗/poet.song.47000.json','["驊騮不惜換舟行，人到歸時意氣生。", "五馬未來迎使節，四弦何事作離聲。", "焚黄此去榮歸里，垂老相看老兄弟。", "來歲北來如訪我，寄書頻到利陵城。"]'),
('0ef07b20-9c73-4e60-b249-6e4306545f80','送人出城同過周少府贈行者','張舜民','宋','宋诗','song-poetry','','[]','欲解舟維岸，將行客倚欄。',48,'全唐诗/poet.song.47000.json','["欲解舟維岸，將行客倚欄。", "主人誇意厚，親起具盤飧。", "溪柳低含雨，山桃重怯寒。", "何時浮小艇，同訪橘洲灘。"]'),
('4fa492c5-782d-4311-8321-d006d504e6a4','送孫積中同年赴任陝府','張舜民','宋','宋诗','song-poetry','','[]','劭農使者嶺南回，上佐題輿陝道開。',64,'全唐诗/poet.song.47000.json','["劭農使者嶺南回，上佐題輿陝道開。", "河水已隨浮世去，條山應喜故人來。", "雨摧苦筍催羹臛，風颭櫻桃落酒杯。", "我欲函關更西去，不知令尹肯相陪。"]'),
('863b5700-cb31-4529-9664-829409830e11','題豆館','張舜民','宋','宋诗','song-poetry','','[]','關頭日落薄衣襟，又對叢蘆擁鼻吟。',32,'全唐诗/poet.song.47000.json','["關頭日落薄衣襟，又對叢蘆擁鼻吟。", "塵土十年纏馬足，只憑雙鬢照歸心。"]'),
('fbfe520c-3c9f-4aa4-b891-175444800999','度秦嶺','張舜民','宋','宋诗','song-poetry','','[]','狗日去中山，春盡抵馮翊。',288,'全唐诗/poet.song.47000.json','["狗日去中山，春盡抵馮翊。", "閏晦適石城，發軫蒙再謫。", "有姪佐晉陰，所幸在肘腋。", "兒女本天愛，未免各分北。", "同行五六口，出關已登陟。", "捨去兩京道，右手入大谷。", "入谷路崎嶇，少前屢顛躓。", "秦嶺生所聞，今日乃相識。", "一舍躡其跌，兩舍跨其脊。", "東井聞水聲，南箕觀簸析。", "西歷華山小，北瞰黄河赤。", "大荔信毫末，中條真拳石。", "終夜聽猿啼，白晝履虎跡。", "俯仰天地間，浩然爲一色。", "是時甫中元，寒凍地欲坼。", "婢僕急榆火，腹背互熏炙。", "輾轉竟號呼，良久各蘇息。", "其南差濔迤，稍降已溫液。", "及至洛水濱，揮汗復疇昔。", "乃知高卑殊，能使氣令易。", "商於固善地，又且近鄉國。", "感涕荷君恩，死生寧有極。", "凡人歷艱險，乃心方驚策。", "常使處燕安，政如懷鴆毒。"]'),
('2e55af72-dccd-4acf-aaf8-a819143260ef','鶻嶺','張舜民','宋','宋诗','song-poetry','','[]','度險仍逢雪，艱危頃步中。',48,'全唐诗/poet.song.47000.json','["度險仍逢雪，艱危頃步中。", "鶻飛猶自苦，人足故難通。", "九折羊腸外，三休箭筈東。", "西南望天柱，聊復慰途窮。"]'),
('a85c6d5e-7de5-452c-b4df-f7a1ce57adfd','丞相寵示白羊御酒之作','張舜民','宋','宋诗','song-poetry','','[]','進酒彤闈盞未乾，春懷元老在長安。',64,'全唐诗/poet.song.47000.json','["進酒彤闈盞未乾，春懷元老在長安。", "雙壺猶带崤山雪，一酌能消塞北寒。", "好是弟兄同受賜，更邀賓客共交歡。", "逡巡若遇頭綱品，感激方明壯士肝。"]'),
('bc52b0bf-39ed-4dbd-994c-975a14ca6afd','徐剛中醴陵少府於山中尋出一洞有銘曰虬淵自然六室奇怪求詩以紀之醴陵多丁氏令威之後云','張舜民','宋','宋诗','song-poetry','','[]','重重翠篠蔽溪灣，石爛松枯不記年。',64,'全唐诗/poet.song.47000.json','["重重翠篠蔽溪灣，石爛松枯不記年。", "但見桃花浮綠水，有時獨鶴下青田。", "自然六室流鍾乳，別隠三階出洞天。", "身在故鄉人不識，秪應徐令是丁仙。"]'),
('87a203a0-a7da-4a96-9877-4e4b56948ea9','庚辰歲仲夏沖照處士王筌子真自渭上游三茅是時業趨召京師分袂於永城聊寫長言同浼行色','張舜民','宋','宋诗','song-poetry','','[]','君爲天下都散漢，我是人間大丈夫。',64,'全唐诗/poet.song.47000.json','["君爲天下都散漢，我是人間大丈夫。", "君往茅山住巌嶺，我乘汴水入京都。", "翩翩雲鶴驚飆馭，汩汩塵埃滿客裾。", "祇看此行皆可見，不須開口說賢愚。"]'),
('ac52b515-3099-45f3-a923-1cacc602f776','贈鄰居陳煥處士','張舜民','宋','宋诗','song-poetry','','[]','福唐陳處士，與我對門居。',48,'全唐诗/poet.song.47000.json','["福唐陳處士，與我對門居。", "生死一爐藥，塵埃數篋書。", "但知尊有酒，莫歎食無魚。", "若論浮生事，浮生事總虛。"]'),
('3f5c8df0-ad4a-47e8-ba49-85823286a2b3','宿盧巌寺','張舜民','宋','宋诗','song-poetry','','[]','先生事業老空谷，弟子幾多作絳紗。',64,'全唐诗/poet.song.47000.json','["先生事業老空谷，弟子幾多作絳紗。", "鶴板當年來上國，碧巌今日屬僧家。", "松風生籟延虛室，瀑水噴珠綴鮮花。", "我有故山歸未得，年年魂夢繞天涯。"]'),
('6bfdce9e-bea6-4b31-bfcd-aef1b10680f9','十二月二十五日行次渭原走寄熙帥范巽之','張舜民','宋','宋诗','song-poetry','','[]','凍雲積雪黯洮泯，晏歲軺車晤過秦。',64,'全唐诗/poet.song.47000.json','["凍雲積雪黯洮泯，晏歲軺車晤過秦。", "夾道清渠翻白浪，遶山鐵馬走黄塵。", "歸鴻裊裊寧無信，塞柳依依欲弄春。", "今夕帳中拚一醉，同年賢帥是鄉人。"]'),
('b5b56b83-1a41-4e4c-b7f1-04377ae53b51','元夕端居感事四絕句  其一','張舜民','宋','宋诗','song-poetry','','[]','鳳樓南畔綵爲山，百戲年年奉帝筵。',32,'全唐诗/poet.song.47000.json','["鳳樓南畔綵爲山，百戲年年奉帝筵。", "不獨侍臣偏賜酒，當時一國夢鈞天。"]'),
('0cd6d49e-543d-48a8-b3a1-76e509175d13','元夕端居感事四絕句  其二','張舜民','宋','宋诗','song-poetry','','[]','十二門開如沸羹，燈光月色逐人行。',32,'全唐诗/poet.song.47000.json','["十二門開如沸羹，燈光月色逐人行。", "春城無處無歌舞，一曲未終天又明。"]'),
('2d45ab3e-f7f5-4ee9-afae-8f0afaf712f7','元夕端居感事四絕句  其三','張舜民','宋','宋诗','song-poetry','','[]','珠簾當面見玲瓏，白鶴仙人上下通。',32,'全唐诗/poet.song.47000.json','["珠簾當面見玲瓏，白鶴仙人上下通。", "夜半蕊珠重命宴，鳴鞘聲落九霄中。"]'),
('a6651c9c-3593-4494-84b5-800ca9c7bbe4','元夕端居感事四絕句  其四','張舜民','宋','宋诗','song-poetry','','[]','何事今宵動所思，此歡常與少年期。',32,'全唐诗/poet.song.47000.json','["何事今宵動所思，此歡常與少年期。", "莫疑杜甫吟兼哭，爲憶開元最盛時。"]'),
('96ac0e7e-2246-4bd9-a983-c34bbd8c3a48','五王廟','張舜民','宋','宋诗','song-poetry','','[]','清汴河邊五君子，身遏橫流同日死。',81,'全唐诗/poet.song.47000.json','["清汴河邊五君子，身遏橫流同日死。", "火炎曾是及池魚，世變安能顧妻子。", "百尺高城不足憑，日月所照惟孤誠。", "當其殺身際，肯念身後名。", "嗚呼，伯夷既死孔子不復生，身後是非誰與評。"]'),
('4bae7f95-a72c-4f78-9a32-bef44b08af4b','龜山寺','張舜民','宋','宋诗','song-poetry','','[]','白塔摇摇波浪間，幾多舟楫望禪關。',64,'全唐诗/poet.song.47000.json','["白塔摇摇波浪間，幾多舟楫望禪關。", "天邊幡影因心動，堂上潮音到海還。", "我拔一毛猶自苦，師除雙臂信如閒。", "中流莫怪頻回首，直到江南始見山。"]'),
('439b7265-c095-403c-8559-74b8916136b4','行運河辛大觀先行以此走寄','張舜民','宋','宋诗','song-poetry','','[]','同下龜山時，舟行篙參差。',180,'全唐诗/poet.song.47000.json','["同下龜山時，舟行篙參差。", "夜投洪澤口，訪問失所之。", "不應一日力，解至淮陰祠。", "長淮自風浪，竟夕起憂疑。", "旦日坐閘中，聽水忘朝饑。", "清泠見雜詠，蓊密聞群咿。", "就柳喜高蔭，避橋嫌窄卑。", "凉風吹水面，襟袖不假披。", "新螯與老鮭，登俎輒無遺。", "飽食却思睡，睡起復何爲。", "稍厭理文字，惟思弄孫兒。", "尚有數舟酒，獨酌非所宜。", "好話不得吐，兩日舌如茨。", "舟行雖云樂，先後不可期。", "爭如鞍馬間，吟嘯長追隨。"]'),
('c379c83c-8485-4b82-af5b-3bc0de3e3274','題狠石','張舜民','宋','宋诗','song-poetry','','[]','江北江南一道兵，匆匆據石各論情。',32,'全唐诗/poet.song.47000.json','["江北江南一道兵，匆匆據石各論情。", "功成與爾遊滄海，此語當初是至誠。"]'),
('085941f9-6503-4e33-896f-a119fae15dd8','舟次金山貽了元','張舜民','宋','宋诗','song-poetry','','[]','何年靈鷲鳥，飛落大江心。',48,'全唐诗/poet.song.47000.json','["何年靈鷲鳥，飛落大江心。", "石壁雖難轉，風波不易禁。", "樓臺分左右，日月見浮沉。", "便欲歸休庇，長嗟世累深。"]'),
('24b3067c-69a4-4776-9bc6-fbecccfff927','與張琬同年飲于龍興寺所居','張舜民','宋','宋诗','song-poetry','','[]','臺城風物已凄凄，牢落行人邂逅齊。',64,'全唐诗/poet.song.47000.json','["臺城風物已凄凄，牢落行人邂逅齊。", "秉燭相看如夢寐，片帆回首又東西。", "依依團扇秋仍好，脈脈青娥恨却低。", "一曲琵琶無限意，時時閒客思都迷。"]'),
('a219c548-867a-4494-8409-82e772f4fb87','舊聞臺城辱井石上有胭脂淚痕久未之信今見之似是淋漓塗抹之迹失笑不已因成此句','張舜民','宋','宋诗','song-poetry','','[]','平居已無奈，倉卒故難任。',48,'全唐诗/poet.song.47000.json','["平居已無奈，倉卒故難任。", "井上痕猶淺，水中痕更深。", "問鰲何至此，下石爾甘心。", "不及馬嵬襪，猶能致萬金。"]'),
('18ef0461-b534-4ac4-a836-b586d4cde570','扳子磯','張舜民','宋','宋诗','song-poetry','','[]','石上紅花低照水，山頭翠篠細含烟。',32,'全唐诗/poet.song.47000.json','["石上紅花低照水，山頭翠篠細含烟。", "天生一本徐熙畫，祇欠鷓鴣相對眠。"]'),
('03fa5ce6-2dde-41b5-9a89-eabd1b602343','池州弄水亭','張舜民','宋','宋诗','song-poetry','','[]','清溪望處思悠悠，不獨今人古亦愁。',64,'全唐诗/poet.song.47000.json','["清溪望處思悠悠，不獨今人古亦愁。", "借爾碧波明似鏡，照予白髮瑩如鷗。", "江山自美騷人宅，鐃鼓常催過客舟。", "惟有角聲吹不斷，斜陽橫起九峰樓。"]'),
('d0335213-9597-47ae-9593-f340a3dd97da','八月十五日夜清溪舟次','張舜民','宋','宋诗','song-poetry','','[]','清溪水底月團團，因見中秋憶去年。',64,'全唐诗/poet.song.47000.json','["清溪水底月團團，因見中秋憶去年。", "旱海五更霜透甲，郴江萬里桂隨船。", "昔看故國光常滿，今望天涯勢似偏。", "只恐姮娥應笑我，還將只影對嬋娟。"]'),
('d527fe93-db2b-4ff1-abf5-f12c8fad6768','行次晚洲','張舜民','宋','宋诗','song-poetry','','[]','臈月遭霖雨，孤舟艤暮灘。',48,'全唐诗/poet.song.47000.json','["臈月遭霖雨，孤舟艤暮灘。", "數聲歸雁斷，半嶺野梅殘。", "無復論偕老，何時展急難。", "江湖卧周歲，此夕最難安。"]'),
('c232d3ed-a957-4e8f-97c0-8c9f7bbe0ae7','黄陵廟','張舜民','宋','宋诗','song-poetry','','[]','青草仍殘照，黄陵一望中。',48,'全唐诗/poet.song.47000.json','["青草仍殘照，黄陵一望中。", "壁書遷客淚，簾卷過湖風。", "斑竹痕猶淺，蒼梧恨莫窮。", "年年秋水上，瑶瑟伴驚鴻。"]'),
('647cedb1-fb2b-4a79-9961-06fb060857ff','客有示余王逢原詩編者因成短韵逢原廣陵人死年二十八歲','張舜民','宋','宋诗','song-poetry','','[]','古人深恨不同時，雖得同時不識之。',32,'全唐诗/poet.song.47000.json','["古人深恨不同時，雖得同時不識之。", "獨把遺編想風質，皇天何負十年期。"]'),
('bd18288c-1d2d-472f-978d-08937511c660','和孫莘老題召伯斗野亭','張舜民','宋','宋诗','song-poetry','','[]','我登甘棠埭，所向殊未平。',120,'全唐诗/poet.song.47000.json','["我登甘棠埭，所向殊未平。", "舟行汙池中，頓失江湖青。", "蛙聲亂僧唄，鴟吻赫市甍。", "意同伯喈死，苟與衛士傾。", "開池種白蓮，壘石擬三生。", "猶淹南斗墟，終遠北斗城。", "設我紫藕供，報之白茅烹。", "三年猿鶴友，萬里秦梵行。", "秋風隴首至，落日淮南明。", "寄言懷土士，慎勿慕官榮。"]'),
('18e48a74-f9b8-403f-9608-be32124334c5','詠長安興廢地','張舜民','宋','宋诗','song-poetry','','[]','憶昔開元全盛日，漢苑隋宮已黍離。',32,'全唐诗/poet.song.47000.json','["憶昔開元全盛日，漢苑隋宮已黍離。", "覆轍由來皆在說，今人還起古人悲。"]'),
('acc3644c-3bc6-4abf-ae40-4f742c463dee','次長蘆','張舜民','宋','宋诗','song-poetry','','[]','炎荒往返正三年，重過長蘆古寺前。',32,'全唐诗/poet.song.47000.json','["炎荒往返正三年，重過長蘆古寺前。", "萬里風波行欲盡，停撓南望一潸然。"]'),
('b6f2c5a2-74d7-4592-9a76-ca734e2770cc','郴州','張舜民','宋','宋诗','song-poetry','','[]','橘井蘇仙宅，茶經陸羽泉。',24,'全唐诗/poet.song.47000.json','["橘井蘇仙宅，茶經陸羽泉。", "萬峰團雉堞，二水匯城𤲬。"]'),
('9820cfb2-5bd7-4813-8ba1-bbe4140c2259','送李傑出帥湖南乞由邵陽拜松楸上可其請','張舜民','宋','宋诗','song-poetry','','[]','春來汴水带冰流，先送湖南第一州。',48,'全唐诗/poet.song.47000.json','["春來汴水带冰流，先送湖南第一州。", "舊置義莊賙族黨，新持使節拜松楸。", "清湘樓晚暉金上，明月池開衣錦遊。"]'),
('54f67335-b4b7-483a-910d-83d654889025','詩一首','張舜民','宋','宋诗','song-poetry','','[]','千載浪名金馬客，一宵沉醉石城樓。',32,'全唐诗/poet.song.47000.json','["千載浪名金馬客，一宵沉醉石城樓。", "郢人休唱陽春曲，白盡湖南刺史頭。"]'),
('9437254f-5933-46e7-963e-dd0de27f8e6b','別房州','張舜民','宋','宋诗','song-poetry','','[]','有客嘗談解散川，偶因晴景到山前。',64,'全唐诗/poet.song.47000.json','["有客嘗談解散川，偶因晴景到山前。", "溪流似景清無底，石壁如門翠插天。", "夜氣結成三洞雨，春渠飲盡一州田。", "臨行始覺房陵好，更欲遲留住一年。"]'),
('28daa812-a8a5-44f5-8f7c-b6b392a0f2ad','梅花','張舜民','宋','宋诗','song-poetry','','[]','綠梢紅萼雖能畫，素艷清香不易吟。',32,'全唐诗/poet.song.47000.json','["綠梢紅萼雖能畫，素艷清香不易吟。", "亂土無人逢驛使，江城有笛任君吹。"]'),
('a6929a8a-a45b-4203-972d-28e1bd830f12','牡丹','張舜民','宋','宋诗','song-poetry','','[]','去年岐路遇春殘，滿院笙歌賞牡丹。',32,'全唐诗/poet.song.47000.json','["去年岐路遇春殘，滿院笙歌賞牡丹。", "今歲杜陵千萬朵，却垂衰淚灑闌干。"]'),
('06591564-6b4b-40f0-9d49-222c6ddb0b61','梨花','張舜民','宋','宋诗','song-poetry','','[]','青女朝來冷透肌，殘春小雨更霏微。',32,'全唐诗/poet.song.47000.json','["青女朝來冷透肌，殘春小雨更霏微。", "流鶑怪底事來往，爲擲金梭織玉衣。"]'),
('df7c1aea-73b0-413e-a69b-1b9448f6ac9a','木香花  其一','張舜民','宋','宋诗','song-poetry','','[]','庭前一架已離披，莫折長枝折短枝。',32,'全唐诗/poet.song.47000.json','["庭前一架已離披，莫折長枝折短枝。", "要待明年春盡後，臨風三嗅寄相思。"]'),
('de27a473-c0c8-431e-b7d0-647f70b40ac3','木香花  其二','張舜民','宋','宋诗','song-poetry','','[]','廣寒宮闕月樓臺，露裏移根月裏栽。',32,'全唐诗/poet.song.47000.json','["廣寒宮闕月樓臺，露裏移根月裏栽。", "品格雖同香氣俗，如何却共牡丹開。"]'),
('d608f04c-95af-47ea-8715-80fa03086368','柳花','張舜民','宋','宋诗','song-poetry','','[]','隨風墜露事輕儇，巧占人間欲夏天。',64,'全唐诗/poet.song.47000.json','["隨風墜露事輕儇，巧占人間欲夏天。", "只恐障空飛似雪，從教糝徑白於綿。", "未央宮暖粘歌袖，揚子江清惱客船。", "老去强看愁底事，昏花滿眼意茫然。"]'),
('e87d3558-0036-449c-a3f0-f9d3be6527af','真珠花','張舜民','宋','宋诗','song-poetry','','[]','千璣萬琲照庭除，細雨斜風拂座隅。',32,'全唐诗/poet.song.47000.json','["千璣萬琲照庭除，細雨斜風拂座隅。", "莫道長安貧似磬，緣階繞砌盡真珠。"]'),
('6a3b7840-9fe9-47c4-a424-38b2b3315c60','荔枝','張舜民','宋','宋诗','song-poetry','','[]','柳江六月水如湯，江邊荔枝紅且黄。',32,'全唐诗/poet.song.47000.json','["柳江六月水如湯，江邊荔枝紅且黄。", "摘時須是带枝葉，滿盤璀璨堆琳瑯。"]'),
('769755ae-feac-411c-87b3-47a800bc28cc','木瓜  其一','張舜民','宋','宋诗','song-poetry','','[]','商州楚地戶，宛在江漢偏。',72,'全唐诗/poet.song.47000.json','["商州楚地戶，宛在江漢偏。", "草木已漸包，果實尤可憐。", "木瓜大如拳，橙橘家家懸。", "隔崖有宿葉，黄紫凝霜烟。", "高秋萬嶂出，一望通鄖川。", "都邑雖僻陋，來者多名賢。"]'),
('9ecb719b-20b5-4644-b69d-a8b74c0282b9','木瓜  其二','張舜民','宋','宋诗','song-poetry','','[]','古言疾癘由卑濕，木實能醫見藥書。',32,'全唐诗/poet.song.47000.json','["古言疾癘由卑濕，木實能醫見藥書。", "有力與人銷患難，無心望爾報瓊琚。"]'),
('a7db46b9-6e27-4cf0-b55d-aa0bf721cdc1','櫻桃','張舜民','宋','宋诗','song-poetry','','[]','雲陽初獻滿筠籠，黄蠟新衣色半紅。',32,'全唐诗/poet.song.47000.json','["雲陽初獻滿筠籠，黄蠟新衣色半紅。", "今日嶺邊空對酒，偷將淚眼望秦中。"]'),
('0e4864e8-366d-414b-bec1-888d2aaefc4f','石楠','張舜民','宋','宋诗','song-poetry','','[]','六代喬楠二百齡，分柯中有異枝生。',32,'全唐诗/poet.song.47000.json','["六代喬楠二百齡，分柯中有異枝生。", "孤根自合藏幽處，瑞子何期應太平。"]'),
('19a23a58-3305-482e-b390-8e28c0fe9f89','靈壽木','張舜民','宋','宋诗','song-poetry','','[]','曲木天然性，叨名席上珍。',48,'全唐诗/poet.song.47000.json','["曲木天然性，叨名席上珍。", "節高工礙手，倚壁快扶人。", "莫問西來意，終爲竈下薪。", "他時俘頡利，拜賜敢忘身。"]'),
('ab7b0ee9-bf96-466a-9455-9df516dd34d2','山藥','張舜民','宋','宋诗','song-poetry','','[]','人無本則憂，物以地爲貴。',24,'全唐诗/poet.song.47000.json','["人無本則憂，物以地爲貴。", "如何山芋輩，天下稱宋衛。"]'),
('08f26061-8457-4d5f-aefd-2c4518275f43','送龐舅大夫','張舜民','宋','宋诗','song-poetry','','[]','外家門館未應疏，舅氏多能作大夫。',64,'全唐诗/poet.song.47000.json','["外家門館未應疏，舅氏多能作大夫。", "才命淹回猶半刺，舟船繚繞向三吳。", "興公自有遊山賦，鄭老寧無過海圖。", "去國長年宜自愛，不須頻叩步兵厨。"]'),
('1c15cd4c-190a-4023-af81-fd723d421c3c','移岳州去房陵道中見海棠','張舜民','宋','宋诗','song-poetry','','[]','馬息山前見海棠，群仙會處錦屏張。',32,'全唐诗/poet.song.47000.json','["馬息山前見海棠，群仙會處錦屏張。", "天寒日晚行人絕，自落自開還自香。"]'),
('8eea8354-7ab1-4f8d-b917-d9d743fbc680','秋','張舜民','宋','宋诗','song-poetry','','[]','急雨收殘暑，西風吹暮蟬。',24,'全唐诗/poet.song.47000.json','["急雨收殘暑，西風吹暮蟬。", "烟浮水空闊，露洗月華圓。"]'),
('122672e9-ad5b-4927-a409-fddd77be0d9a','取里語以己語足成二絕  其一','張舜民','宋','宋诗','song-poetry','','[]','世間多少不平事，却被同州看華山。',32,'全唐诗/poet.song.47000.json','["世間多少不平事，却被同州看華山。", "我到左馮今幾月，何嘗見得華山顔。"]'),
('2bc638b6-ad08-4b00-a6a4-b25e5ee14a0f','取里語以己語足成二絕  其二','張舜民','宋','宋诗','song-poetry','','[]','三春不識桃李面，四月無鶑但老鴉。',32,'全唐诗/poet.song.47000.json','["三春不識桃李面，四月無鶑但老鴉。", "誰料浮休癡處士，下車先看牡丹花。"]'),
('2327e49e-c5e3-4be3-adf6-7b8040eece58','呂子固挽詞','張舜民','宋','宋诗','song-poetry','','[]','大塊分勞逸，唯君獨不均。',48,'全唐诗/poet.song.47000.json','["大塊分勞逸，唯君獨不均。", "險夷安若性，金石想爲人。", "萬卷書奚託，重泉恨莫伸。", "誰知丞相子，天地一窮民。"]'),
('be2f2854-48f8-47af-b005-59ae0779dbba','道中聞蛙聲','張舜民','宋','宋诗','song-poetry','','[]','一夜蛙聲不暫停，近如相和遠如爭。',32,'全唐诗/poet.song.47000.json','["一夜蛙聲不暫停，近如相和遠如爭。", "信知不爲官私事，應恨疏螢徹夜明。"]'),
('21dc9074-7ef6-4864-9775-1ed9b7c38c72','扇詩','張舜民','宋','宋诗','song-poetry','','[]','扇子解招風，本要熱時用。',24,'全唐诗/poet.song.47000.json','["扇子解招風，本要熱時用。", "秋來掛壁間，却被風吹動。"]'),
('a332cbb4-a85f-4e70-bcfd-d3a88447f347','送葉公義叟求宮祠歸吳下','張舜民','宋','宋诗','song-poetry','','[]','把還使節請祠真，便作吳江漸退身。',64,'全唐诗/poet.song.47000.json','["把還使節請祠真，便作吳江漸退身。", "憑軾幾州沾惠愛，歸裝一味是清貧。", "相思欲控琴高鯉，卜宅須邀李子鄰。", "不是薦章論再起，朝廷自重老成人。"]'),
('a4c81e6c-8ac6-4fcf-9dd1-f568dbb4cbed','漁父','張舜民','宋','宋诗','song-poetry','','[]','家住耒江邊，門前碧水連。',48,'全唐诗/poet.song.47000.json','["家住耒江邊，門前碧水連。", "小舟勝養馬，大罟當耕田。", "保甲元無籍，青苗不著錢。", "桃源在何處，此地有神仙。"]'),
('48a3a07f-4965-46c5-90ce-1c67957d9ddf','百舌','張舜民','宋','宋诗','song-poetry','','[]','學盡百禽語，終無自己聲。',24,'全唐诗/poet.song.47000.json','["學盡百禽語，終無自己聲。", "深山喬木底，緘口過平生。"]'),
('529f0651-dcf4-44cd-a431-62dbba003e5f','題王侍禁壁','張舜民','宋','宋诗','song-poetry','','[]','怪底臨江有竹籬，便將江水當爲池。',64,'全唐诗/poet.song.47000.json','["怪底臨江有竹籬，便將江水當爲池。", "心隨鷗鳥沈浮去，眼看風波起滅時。", "我有矴齋新作記，人傳畫舫舊題詩。", "君恩幾許生歸北，與我閒人把釣絲。"]'),
('ee1f75a0-bc1a-4a6a-9884-92db90b5958f','溫泉','張舜民','宋','宋诗','song-poetry','','[]','岧嶢華清宮，下有溫泉水。',144,'全唐诗/poet.song.47000.json','["岧嶢華清宮，下有溫泉水。", "繡嶺絡千門，玉蓮噴九蕊。", "第一名御湯，第二沐妃子。", "從上傍諸王，最下列衛士。", "淙淙三十六，枝分或櫛比。", "每年十月初，仙杖常依此。", "樓頭羯鼓停，殿上霓裳委。", "塵垢三百年，行人與閭里。", "忽驚郴嶺下，和暖雅相似。", "祇是遠長安，不當人眼底。", "皇天宅萬物，得地即爲美。", "幸免與興亡，往來常止止。"]'),
('9603a3f2-c321-4b48-bf99-d744cfb66558','愈泉','張舜民','宋','宋诗','song-poetry','','[]','有泉出城闉，尾大如車輻。',48,'全唐诗/poet.song.47000.json','["有泉出城闉，尾大如車輻。", "飲之能愈疾，此語聞郴俗。", "直疑白藥根，浸漬幽巌腹。", "靈迹浪遐方，神功施比屋。"]'),
('907fd259-5351-4ce8-8866-a727c625bf66','焦君以錦雞爲贈文彩可愛性復馴狎終日爲家貓所困因遂挈還仍嗣短句','張舜民','宋','宋诗','song-poetry','','[]','魯恭感物性能馴，因把華蟲贈里仁。',64,'全唐诗/poet.song.47000.json','["魯恭感物性能馴，因把華蟲贈里仁。", "雖有文章堪悅目，却無言語解謀身。", "只愁貓犬常窺汝，胡不山林遠避人。", "好在舊籠還舊主，便當歸放澗之濱。"]'),
('c625fa1e-a538-4b97-9765-c6b6e755cfeb','句  其一','張舜民','宋','宋诗','song-poetry','','[]','萬里秋風吹鬢髮，百年人事倚欄干。',32,'全唐诗/poet.song.47000.json','["萬里秋風吹鬢髮，百年人事倚欄干。", "知他落日能多少，偏照淮南幾處山。"]'),
('89bbfb04-a34f-4828-ba25-5070482aef43','句  其二','張舜民','宋','宋诗','song-poetry','','[]','李白尋仙持玉杖，庾公對月踞胡床。',16,'全唐诗/poet.song.47000.json','["李白尋仙持玉杖，庾公對月踞胡床。"]'),
('eaecbc2c-733a-4b0a-a3c3-27613053810d','句  其三','張舜民','宋','宋诗','song-poetry','','[]','樓上康廬紫翠環，檻前湓浦轉清灣。',32,'全唐诗/poet.song.47000.json','["樓上康廬紫翠環，檻前湓浦轉清灣。", "帆開三楚蒼茫外，路入雙林窅靄間。"]'),
('cfe9d537-418a-4c87-bcf5-8aa06a4a11c9','句  其四','張舜民','宋','宋诗','song-poetry','','[]','山長水遠連三楚，物態人情又一州。',16,'全唐诗/poet.song.47000.json','["山長水遠連三楚，物態人情又一州。"]'),
('29ce734b-6fd9-4a08-a2db-5d9d8a8ef5b3','句  其五','張舜民','宋','宋诗','song-poetry','','[]','義帝凭祠宇，梅真隠市廛。',12,'全唐诗/poet.song.47000.json','["義帝凭祠宇，梅真隠市廛。"]'),
