('c4653ff7-ac2b-4dce-bab1-b46521a3b726','齊山僧舍','王鞏','宋','宋诗','song-poetry','','[]','竹密通幽境，橫橋逐澗斜。',48,'全唐诗/poet.song.47000.json','["竹密通幽境，橫橋逐澗斜。", "陰崖聳珪壁，古蔓引龍蛇。", "寺僻虛僧磬，亭荒足兔罝。", "紫微今不見，著意採黄花。"]'),
('988b7084-2df3-4901-8170-0e59807916e0','全州捲煙閣','王鞏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江縈村若練带，晴岫插天如畫屏。',48,'全唐诗/poet.song.47000.json','["長江縈村若練带，晴岫插天如畫屏。", "山青水秀兩奇絕，道人對此開禪扃。", "紅塵一點飛不到，舉手高可摩天星。"]'),
('196e45b7-798b-4771-9990-f857a3568948','湘山','王鞏','宋','宋诗','song-poetry','','[]','半嶺風吹草木香，落階花雨送春忙。',64,'全唐诗/poet.song.47000.json','["半嶺風吹草木香，落階花雨送春忙。", "從師遠借雲庵卧，還我平生午枕凉。", "蓮社緇黄常得伴，鹿門妻子亦相將。", "化身欲似河東柳，更向山頭望故鄉。"]'),
('713c8851-8857-4dc0-b1cc-5229d9b65001','寄桂州張諫議和永叔','王鞏','宋','宋诗','song-poetry','','[]','桂林太守幾時行，泛汴桃花浪已騰。',64,'全唐诗/poet.song.47000.json','["桂林太守幾時行，泛汴桃花浪已騰。", "目極雲陰低遠樹，夜寒風急亂春燈。", "巢鳴翡翠愁無限，水宿鴛鴦冷不勝。", "陽朔山前好峰嶺，爲公憐愛萬千層。"]'),
('d98103e7-976d-4934-b13a-10eaf20d0efb','欣欣亭','王鞏','宋','宋诗','song-poetry','','[]','清湘北郭崇崗路，松竹年來定幾圍。',32,'全唐诗/poet.song.47000.json','["清湘北郭崇崗路，松竹年來定幾圍。", "我亦臨淮築新宅，與君萬里對柴扉。"]'),
('b1302705-f63c-41dd-9a3b-028a93c10f85','句','王鞏','宋','宋诗','song-poetry','','[]','春漬苔紋沿石塔，月含松韵雜琴聲。',16,'全唐诗/poet.song.47000.json','["春漬苔紋沿石塔，月含松韵雜琴聲。"]'),
('16a09068-aeaa-43ce-ba59-e4b773edc8c7','句','童傳','宋','宋诗','song-poetry','','[]','古來風義遺才少，近世公卿薦士稀。',16,'全唐诗/poet.song.47000.json','["古來風義遺才少，近世公卿薦士稀。"]'),
('244208ce-b6e2-4b0f-a08e-e8a84f93ec0e','句','愈上人','宋','宋诗','song-poetry','','[]','閑伴孤雲自在飛。',8,'全唐诗/poet.song.47000.json','["閑伴孤雲自在飛。"]'),
