('330c243d-81b3-4373-afaf-a045c846087a','句','王蘧','宋','宋诗','song-poetry','','[]','繡裳畫衮雲垂地。',8,'全唐诗/poet.song.47000.json','["繡裳畫衮雲垂地。"]'),
('cf2f4d79-36bc-4dfb-88d4-d9e7e5bab19c','和子瞻學士遊祖塔院','釋來復','宋','宋诗','song-poetry','','[]','金沙泉湧雪濤香，灑作醍醐大地凉。',64,'全唐诗/poet.song.47000.json','["金沙泉湧雪濤香，灑作醍醐大地凉。", "倒侵九天河影白，遥通百谷海聲長。", "僧來汲月歸靈石，人到尋源宿上方。", "欲著茶經校奇品，山瓢留待羽仙嘗。"]'),
('d3706f52-9d9d-4f17-89b1-d1ef1ed7d9f1','和東坡','釋知慎','宋','宋诗','song-poetry','','[]','東軒長老未相逢，已見黄州一信通。',32,'全唐诗/poet.song.47000.json','["東軒長老未相逢，已見黄州一信通。", "何必揚眉資目擊，須知千里事同風。"]'),
('8bcdbd17-e1ad-4cf5-a997-5ff5b0556379','冬至祀先有感','趙仲修','宋','宋诗','song-poetry','','[]','井臼辛勤又一年，仗誰齎恨到重泉。',64,'全唐诗/poet.song.47000.json','["井臼辛勤又一年，仗誰齎恨到重泉。", "離騷空紀高陽後，藍縷過如蚡冒前。", "終亦有人分鼠璞，只今無俸置豚肩。", "男兒七尺鬚如戟，獨掩蓬蒿掃紙錢。"]'),
('a4732d51-4263-454d-baef-cd50a95ec0f0','車武子宅','王齊愈','宋','宋诗','song-poetry','','[]','儒生骨朽名猶在，高塚相望已亂真。',32,'全唐诗/poet.song.47000.json','["儒生骨朽名猶在，高塚相望已亂真。", "只認夜深螢聚處，便應泉下讀書人。"]'),
('689ba77c-102c-45c2-b1df-830c72b0f11a','竹浦漁歸','石汝礪','宋','宋诗','song-poetry','','[]','釣罷收綸日既殘，扁舟一葉解登灣。',64,'全唐诗/poet.song.47000.json','["釣罷收綸日既殘，扁舟一葉解登灣。", "長歌欸乃乘風去，鳴櫓咿啞趁月還。", "翡翠躍飛紅蓼內，鴛鴦驚起白蘋間。", "奔馳馬足車塵者，回首煙波羨爾閒。"]'),
('8ab65765-c8bf-40fb-9c0b-2f7b9cdb4eb4','頌','崔閑','宋','宋诗','song-poetry','','[]','每與本坡心印傳，雪堂終日悟琅然。',32,'全唐诗/poet.song.47000.json','["每與本坡心印傳，雪堂終日悟琅然。", "七弦高掛揮無用，明月當天一點圓。"]'),
('ed0349df-f36b-4430-a1db-4a65c0f128ce','潤州','釋仲殊','宋','宋诗','song-poetry','','[]','北固樓前一笛風，斷雲飛出建昌宮。',32,'全唐诗/poet.song.47000.json','["北固樓前一笛風，斷雲飛出建昌宮。", "江南二月多芳草，春在濛濛細雨中。"]'),
('a10d6b3a-98ff-49a2-a92d-7bfc14f4f7b6','題李伯時支遁相馬圖','釋仲殊','宋','宋诗','song-poetry','','[]','月窟精神不受羈，白雲野老太支離。',32,'全唐诗/poet.song.47000.json','["月窟精神不受羈，白雲野老太支離。", "當時若也無人識，駿骨靈心各自知。"]'),
('2a63c29e-6991-4bd7-80b3-5b7ae9c37001','訪子通','釋仲殊','宋','宋诗','song-poetry','','[]','多年不見玉川翁，今日相逢小榭東。',32,'全唐诗/poet.song.47000.json','["多年不見玉川翁，今日相逢小榭東。", "依舊清凉無長物，只餘松檜養秋風。"]'),
('ef76c41a-cf8b-44f5-947b-99ecd0fb76dd','黄左丞席上作','釋仲殊','宋','宋诗','song-poetry','','[]','瑞麟香暖玉芙蓉，畫蠟凝輝到曉紅。',64,'全唐诗/poet.song.47000.json','["瑞麟香暖玉芙蓉，畫蠟凝輝到曉紅。", "數點漏移衙仗北，一番雨滴甲樓東。", "夢遊黄闕鸞巢外，身卧彤幃虎帳中。", "報道譙門初日上，起來簾幕杏花風。"]'),
('c97cc6b5-c36b-4d60-bbd9-f626667ad374','題玉泉','釋仲殊','宋','宋诗','song-poetry','','[]','分出瑶池萬怪驚，崑墟引落最高層。',64,'全唐诗/poet.song.47000.json','["分出瑶池萬怪驚，崑墟引落最高層。", "十分清是泉中玉，一漱寒生齒下冰。", "浄照更無雲影雜，素光疑有露華凝。", "莫教明月從中現，澈底無心伴老僧。"]'),
('1c2862c5-499a-40f8-a643-6e173a9138ca','京口懷古  其一','釋仲殊','宋','宋诗','song-poetry','','[]','北顧橫江盡，東南第一州。',24,'全唐诗/poet.song.47000.json','["北顧橫江盡，東南第一州。", "六朝都在望，回首倦登樓。"]'),
('8a6439f1-ee4c-4ef1-8921-6fdc78a6c643','京口懷古  其二','釋仲殊','宋','宋诗','song-poetry','','[]','一昨丹陽王氣銷，盡將豪侈謝塵囂。',64,'全唐诗/poet.song.47000.json','["一昨丹陽王氣銷，盡將豪侈謝塵囂。", "衣冠不復宗唐代，父老猶能道晉朝。", "萬歲樓邊誰唱月，千秋橋上自吹簫。", "青山不與興亡事，只共垂楊伴海潮。"]'),
('f71cd159-4140-4f65-872d-2cda88d48ea6','題洞虛觀','釋仲殊','宋','宋诗','song-poetry','','[]','古觀多松檜，幽奇近暮秋。',48,'全唐诗/poet.song.47000.json','["古觀多松檜，幽奇近暮秋。", "坐看新月上，閒見斷雲愁。", "野思同花鳥，鄉情隔島洲。", "輕寒披鶴氅，隠几自搔頭。"]'),
('eb8ca959-8097-4249-ae3e-48954071b28b','荷花','釋仲殊','宋','宋诗','song-poetry','','[]','水中仙子並紅腮，一點芳心兩處開。',32,'全唐诗/poet.song.47000.json','["水中仙子並紅腮，一點芳心兩處開。", "想是鴛鴦頭白死，雙魂化作好花來。"]'),
('c707a72f-706e-480b-aed0-6f8440d7efe1','破山光明庵','釋仲殊','宋','宋诗','song-poetry','','[]','身是光明幢，語是光明經。',48,'全唐诗/poet.song.47000.json','["身是光明幢，語是光明經。", "光明聚不散，妙有成真形。", "示現三界前，何勞問丹青。", "坐斷龍鬬山，寶月孤亭亭。"]'),
('1bdc8392-2d93-45d7-ae6b-f65490e8ad28','望湖亭','釋仲殊','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','凝華浮藻五雲間，下壓凌虛萬象閑。',32,'全唐诗/poet.song.47000.json','["凝華浮藻五雲間，下壓凌虛萬象閑。", "湖水際天天欲盡，落霞照出洞庭山。"]'),
('cfdd71c7-509b-40e4-b6d1-961eaddce6b0','中峰','釋仲殊','宋','宋诗','song-poetry','','[]','聚遠最高亭，登臨喜倍增。',48,'全唐诗/poet.song.47000.json','["聚遠最高亭，登臨喜倍增。", "貪陪青眼客，不見白頭僧。", "閉戶三十載，壓雲千萬層。", "龍珠彈落處，一點白蓮燈。"]'),
('7020333e-ef50-496a-b33e-f8ae7f617aa1','題翠麓亭','釋仲殊','宋','宋诗','song-poetry','','[]','素虬盤屈走靈泉，槲葉塗紅作畫船。',128,'全唐诗/poet.song.47000.json','["素虬盤屈走靈泉，槲葉塗紅作畫船。", "幡轉玉繩光影旋，杯銜金鏡酒痕圓。", "篆形綵字方傳世，星落光纏忽下天。", "遠想螭蟠殊未若，小圖河曲宛依然。", "緩浮松釀環雲際，不動蘭橈到席邊。", "上巳浮恩非此日，山陰盛事掩多年。", "從歡未省向尊俎，屢酒何嘗議聖賢。", "翰墨主人今獨步，雙鵝應復降飛仙。"]'),
('002fc0c1-1cf2-4dfe-a504-0dbde1cc3085','題君山洗心堂','釋仲殊','宋','宋诗','song-poetry','','[]','朝隨初日上烟沙，極望淮南不見涯。',32,'全唐诗/poet.song.47000.json','["朝隨初日上烟沙，極望淮南不見涯。", "今日江東寒食節，春閒桃李自開花。"]'),
('bdb1be84-b193-4430-b51d-e324b702020e','句  其一','釋仲殊','宋','宋诗','song-poetry','','[]','凉生宮殿不因秋。',8,'全唐诗/poet.song.47000.json','["凉生宮殿不因秋。"]'),
('8c214720-dd39-4adb-a953-8332f3460ffb','句  其二','釋仲殊','宋','宋诗','song-poetry','','[]','霽色澄千里，潮聲带兩州。',12,'全唐诗/poet.song.47000.json','["霽色澄千里，潮聲带兩州。"]'),
('1fb26645-c2ac-4d4e-b183-e797640fd45d','句  其三','釋仲殊','宋','宋诗','song-poetry','','[]','天長地久大悠悠，爾既無心我亦休。',16,'全唐诗/poet.song.47000.json','["天長地久大悠悠，爾既無心我亦休。"]'),
('d8d1b0cc-3fec-41dc-953c-cd5e97256ca4','句  其四','釋仲殊','宋','宋诗','song-poetry','','[]','海門礙日山雙聳，江北迎人樹幾行。',16,'全唐诗/poet.song.47000.json','["海門礙日山雙聳，江北迎人樹幾行。"]'),
('428f6245-490d-4ad6-8e23-dc9044c994f9','箴仲殊','孚禪師','宋','宋诗','song-poetry','','[]','大道久凌遲，正風還陊隳。',204,'全唐诗/poet.song.47000.json','["大道久凌遲，正風還陊隳。", "無人整頹綱，目亂空傷悲。", "卓有出世士，蔚爲人天師。", "文章通造化，動與王公知。", "囊括十洲香，名翼四海馳。", "肆意放山水，灑脫無羈縻。", "雲輕三事衲，瓶錫天下之。", "詩曲相間作，百紙頃刻爲。", "藻思洪泉瀉，翰墨清且奇。", "惜哉大手筆，胡爲幽柔詞。", "願師持此才，奮起革澆漓。", "騖彼東山嵩，圖祖進豐碑。", "再續輔教編，高步凌丹墀。", "它日僧史上，萬世爲蓍龜。", "迦葉聞琴舞，終被習氣隨。", "伊予浮薄人，贈言增忸怩。", "倘能循我言，佛日重光離。"]'),
('c14ef07e-7c9f-4043-8352-6dd9abfed071','山光寺','釋法芝','宋','宋诗','song-poetry','','[]','扁舟乘興到山光，古寺臨流勝氣藏。',32,'全唐诗/poet.song.47000.json','["扁舟乘興到山光，古寺臨流勝氣藏。", "慚愧南風知我意，吹將草木作天香。"]'),
('206a9043-a5e5-4e24-965a-c9bd9486558d','句','釋法芝','宋','宋诗','song-poetry','','[]','淡游聊得慰孤悶，誰問當年寄老心。',16,'全唐诗/poet.song.47000.json','["淡游聊得慰孤悶，誰問當年寄老心。"]'),
('c495035a-5c19-4098-a387-d8ed7e2c67a9','超果教院見遠亭','李甲','宋','宋诗','song-poetry','','[]','高僧欲縱目，橋上建橫亭。',48,'全唐诗/poet.song.47000.json','["高僧欲縱目，橋上建橫亭。", "野水茫茫白，羣山點點青。", "客帆風送葉，漁火夜遺星，看盡朝昏景。", "天涯一畫屏。"]'),
('50d407e9-73cb-40ea-854b-6275e71a307d','題竹和東坡韵','李甲','宋','宋诗','song-poetry','','[]','翠葉彤竿已占先，湘雲千疊勢爭翻。',32,'全唐诗/poet.song.47000.json','["翠葉彤竿已占先，湘雲千疊勢爭翻。", "野夫不識天人面，知是虞皇第幾元。"]'),
('76bb480e-bea9-49b8-b03d-0a230f8bcf39','題畫','李甲','宋','宋诗','song-poetry','','[]','誰潑烟雲六尺綃，寒山秋樹晚蕭蕭。',32,'全唐诗/poet.song.47000.json','["誰潑烟雲六尺綃，寒山秋樹晚蕭蕭。", "十年來往吳淞口，錯認溪南舊板橋。"]'),
('b0434883-e1c6-4e57-8216-cb0e514155a2','醉眠亭','李行中','宋','宋诗','song-poetry','','[]','檐低檻曲莫嫌隘，地僻草深宜晝眠。',64,'全唐诗/poet.song.47000.json','["檐低檻曲莫嫌隘，地僻草深宜晝眠。", "代枕暮憑溪上石，當簾時借屋頭烟。", "倦遊拂壁畫山逕，貪醉解衣還酒錢。", "一水近通西浦路，客來猶可棹漁船。"]'),
('0f05b129-2358-435b-ba31-3449b87860f2','寄韓憲仲廷評','李行中','宋','宋诗','song-poetry','','[]','野徑荒亭草沒腰，一眠聊以永今朝。',64,'全唐诗/poet.song.47000.json','["野徑荒亭草沒腰，一眠聊以永今朝。", "放懷不管人間事，破夢時間夜半潮。", "玉柱劉叉詩未厭，金龜李白酒難招。", "知君有意尋安道，咫尺何時動畫橈。"]'),
('f02c07e4-16fd-464a-9b42-8d2bc2918caa','趙明叔太博未識醉眠亭先貺佳篇','李行中','宋','宋诗','song-poetry','','[]','要認荒亭路不賒，浦西橋北對漁家。',64,'全唐诗/poet.song.47000.json','["要認荒亭路不賒，浦西橋北對漁家。", "窗嫌日曝新栽竹，蔬占畦長未種花。", "壁上客來堆醉墨，籬根潮過積寒沙。", "被人誤號陶潛宅，也學門前五柳遮。"]'),
('4989ac69-77f3-4a88-b849-f5783dab43fe','讀顔魯公碑','李行中','宋','宋诗','song-poetry','','[]','平生肝膽衛長城，至死圖回色不驚。',32,'全唐诗/poet.song.47000.json','["平生肝膽衛長城，至死圖回色不驚。", "世俗不知忠義大，百年空有好書名。"]'),
('7779d398-8671-4c41-b86b-c30668cc6d0e','賦佳人嗅梅圖','李行中','宋','宋诗','song-poetry','','[]','蠶眉鴉鬢縷金衣，折得梅花第幾枝。',32,'全唐诗/poet.song.47000.json','["蠶眉鴉鬢縷金衣，折得梅花第幾枝。", "嗅盡餘香不回面，思量何事立多時。"]'),
('f2f7c4fb-eeaf-45ef-be65-f6cc620608cb','江上逢晁適道','崔子方','宋','宋诗','song-poetry','','[]','渺渺連江雨，微微到面風。',48,'全唐诗/poet.song.47000.json','["渺渺連江雨，微微到面風。", "主人留一餉，佳士得相逢。", "會面嗟何晚，論詩許有功。", "君家好兄弟，更覺此心同。"]'),
('711d4ad0-ceaa-49c5-abe6-f71af884cfd1','句','崔子方','宋','宋诗','song-poetry','','[]','白日行空闊，青燈耿夜闌。',12,'全唐诗/poet.song.47000.json','["白日行空闊，青燈耿夜闌。"]'),
('e5f0d132-595c-43d6-bd32-25c2b6857813','句  其一','李斯立','宋','宋诗','song-poetry','','[]','巌溜連雲凍，溪梅带雪香。',12,'全唐诗/poet.song.47000.json','["巌溜連雲凍，溪梅带雪香。"]'),
('14ec2a79-f191-484a-971c-e975e53bf8d0','句  其二','李斯立','宋','宋诗','song-poetry','','[]','有意峰巒千嶂出，無名花草百般香。',16,'全唐诗/poet.song.47000.json','["有意峰巒千嶂出，無名花草百般香。"]'),
('ce1db284-ed99-4a5b-a7c8-58cd10585926','上蘇子瞻','釋仲淵','宋','宋诗','song-poetry','','[]','文章落落昌黎老，風物蕭蕭李謫仙。',32,'全唐诗/poet.song.47000.json','["文章落落昌黎老，風物蕭蕭李謫仙。", "二子本來爲獨擅，使君才力已雙全。"]'),
('5360970a-35f9-4913-99c5-f23270ca2dce','題大慈塢祖塔院','釋惠覺','宋','宋诗','song-poetry','','[]','谷口兩三家，平田一望賒。',48,'全唐诗/poet.song.47000.json','["谷口兩三家，平田一望賒。", "春深多遇雨，夜靜獨鳴蛙。", "雲暗未通月，林香始辨花。", "誰驚孤枕曉，濤白捲江沙。"]'),
('620544bd-5b05-45da-ad79-eb1bd3722625','句','釋惠覺','宋','宋诗','song-poetry','','[]','瀾深魚自躍，風暖客還來。',12,'全唐诗/poet.song.47000.json','["瀾深魚自躍，風暖客還來。"]'),
('a2927a0c-ccc4-4dd8-bb4f-3445b16a777b','句','李伯祥','宋','宋诗','song-poetry','','[]','夜過修竹院，醉打老僧門。',12,'全唐诗/poet.song.47000.json','["夜過修竹院，醉打老僧門。"]'),
('436b8fed-0743-4721-ab0c-6da46b3c7f50','詩一首','陳少章','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十里荷開菡萏初，我公初至有西湖。',32,'全唐诗/poet.song.47000.json','["十里荷開菡萏初，我公初至有西湖。", "却將公事湖中了，見說官閑事也無。"]'),
('47c343e7-9bcd-4ded-a079-8705c3fdf1d2','成都運司西園亭詩 西園','許將','宋','宋诗','song-poetry','','[]','高牙負北郭，芳園路西轉。',48,'全唐诗/poet.song.47000.json','["高牙負北郭，芳園路西轉。", "鳥鳴戀故木，蘭茁歸新畹。", "坐延花景深，行倚筇枝軟。", "翳然思林木，會心不在遠。"]'),
('1c621fb4-62f0-456c-90b3-a06f6504434d','成都運司西園亭詩 玉溪堂','許將','宋','宋诗','song-poetry','','[]','朱堂俯玉溪，玉溪清且幽。',48,'全唐诗/poet.song.47000.json','["朱堂俯玉溪，玉溪清且幽。", "從公暫偃息，撫景空夷猶。", "浮雲冠圓島，白日回方流。", "抵此有光碧，何必崑崙洲。"]'),
('0d367f17-b537-4e05-98d1-7c3330b8b41b','成都運司西園亭詩 雪峰樓','許將','宋','宋诗','song-poetry','','[]','重樓起城陰，乘高望四極。',48,'全唐诗/poet.song.47000.json','["重樓起城陰，乘高望四極。", "列峰橫青天，飛雪千里積。", "疑是空素山，冬夏海中白。", "莫怪頻東向，上有思歸客。"]'),
('e3ab6e17-8628-4517-b24c-031b1cdfabfa','成都運司西園亭詩 海棠軒','許將','宋','宋诗','song-poetry','','[]','海棠冠蜀花，此軒花尤冠。',48,'全唐诗/poet.song.47000.json','["海棠冠蜀花，此軒花尤冠。", "紅雲簇蕊細，淥水照葉嫩。", "倚粧宮粉聚，疊綺霞光散。", "雨淚點春風，應懷上林怨。"]'),
('cdd17133-da2c-40ab-a862-e12194b0adcb','成都運司西園亭詩 月臺','許將','宋','宋诗','song-poetry','','[]','蜀地山四維，益州平如掌。',48,'全唐诗/poet.song.47000.json','["蜀地山四維，益州平如掌。", "纍臺鬰臨風，坐看月宵上。", "稍出叢木末，始發衆籟爽。", "茲焉暫遊目，一覽天地廣。"]'),
('19c7f64e-da60-4f3a-a931-d58f1898b525','成都運司西園亭詩 翠錦亭','許將','宋','宋诗','song-poetry','','[]','闌干竇溜長，䆗窱空埃靜。',48,'全唐诗/poet.song.47000.json','["闌干竇溜長，䆗窱空埃靜。", "修林密總翠，盡得錦城景。", "雲舒青青色，風散騷騷影。", "未爲夜行人，共此晝夜永。"]'),
('820bcb9c-942d-4005-8909-66d88b6b5809','成都運司西園亭詩 潺玉亭','許將','宋','宋诗','song-poetry','','[]','引泉注清渠，潺潺潄寒玉。',48,'全唐诗/poet.song.47000.json','["引泉注清渠，潺潺潄寒玉。", "側出閬風遲，驟驚江雨速。", "飛瀨乍揚白，樛木細涵綠。", "晝夜聲不止，肯效楚人哭。"]'),
('46c4662b-dad2-4a5f-8052-23cced9468e6','成都運司西園亭詩 茅庵','許將','宋','宋诗','song-poetry','','[]','茅茨以爲庵，環顧蕭然虛。',48,'全唐诗/poet.song.47000.json','["茅茨以爲庵，環顧蕭然虛。", "內樂苟自足，容人即有餘。", "旁依修竹密，上翳青松株。", "勿言此中陋，中有君子居。"]'),
('dedce80f-35b0-4e84-b800-9a492582ff69','成都運司西園亭詩 水閣','許將','宋','宋诗','song-poetry','','[]','飛閣出方池，修竹見空莽。',48,'全唐诗/poet.song.47000.json','["飛閣出方池，修竹見空莽。", "低臨花塢近，平覺春波長。", "返景澄餘暉，夕陰带浮爽。", "從容觀魚樂，不減游濠上。"]'),
('466cc1af-9517-4b5c-be8f-9bc18b741ede','成都運司西園亭詩 小亭','許將','宋','宋诗','song-poetry','','[]','翩然溝上亭，左右相映带。',48,'全唐诗/poet.song.47000.json','["翩然溝上亭，左右相映带。", "修柟列翠幄，長松偃高蓋。", "地褊景逾寬，處約志彌泰。", "誰知坐嘯間，心遊萬物外。"]'),
('63d6a6a4-4d3a-4242-951a-9b92ac66a8d3','遊東山和程大卿師孟','許將','宋','宋诗','song-poetry','','[]','東山十里復溪流，遠客時時騁望愁。',64,'全唐诗/poet.song.47000.json','["東山十里復溪流，遠客時時騁望愁。", "泉近榴花深洞口，亭開獅子舊峰頭。", "一州旂色天邊出，三館芸香海上留。", "南北共歌公所憩，獨嗟無計共英游。"]'),
('f44a7d42-ff0e-4406-ab7d-701de3acf92c','東山碧巌亭','許將','宋','宋诗','song-poetry','','[]','舊室曾留古岸邊，新亭同賞碧巌前。',64,'全唐诗/poet.song.47000.json','["舊室曾留古岸邊，新亭同賞碧巌前。", "日生獅子峰頭樹，烟伴榴花洞口泉。", "黄葉入秋山出地，白雲臨曉海乘天。", "飄然蹤跡今何定，別去江湖又一年。"]'),
('093f3101-766d-4569-9643-13b8d22dcda1','留題徐真君祠堂東西二室','許將','宋','宋诗','song-poetry','','[]','上得山來過石門，謁靈特地乞真言。',32,'全唐诗/poet.song.47000.json','["上得山來過石門，謁靈特地乞真言。", "再三許我前程事，敢不留詩荷聖恩。"]'),
('f8778d18-8c88-45e4-a856-a392746430ff','留題積善院','許將','宋','宋诗','song-poetry','','[]','爲愛山居樂，居山又憶家。',48,'全唐诗/poet.song.47000.json','["爲愛山居樂，居山又憶家。", "菊黄來日蕊，梅白去時花。", "水闊離情遠，霜晴別恨賒。", "前程回首望，空指暮天霞。"]'),
('c6bde5b5-0a35-4e00-b2d2-e7a9e0652021','真珠','許將','宋','宋诗','song-poetry','','[]','蔌蔌圓英淡粉粧，肯隨桃杏媚韶光。',32,'全唐诗/poet.song.47000.json','["蔌蔌圓英淡粉粧，肯隨桃杏媚韶光。", "金刀不到春風外，草密林深只自香。"]'),
('86e6b24f-aedc-4461-9361-58cd83d56c78','端午帖子','許將','宋','宋诗','song-poetry','','[]','江中今日成龍鑑，苑外多年廢鷺坡。',32,'全唐诗/poet.song.47000.json','["江中今日成龍鑑，苑外多年廢鷺坡。", "合照乾坤共作鏡，放生河海盡爲池。"]'),
('ae3bc52e-29fa-41ac-b835-20584a84abbe','觀瀾亭','許將','宋','宋诗','song-poetry','','[]','危亭高處倚岩隈，西望蒲菖海浪回。',48,'全唐诗/poet.song.47000.json','["危亭高處倚岩隈，西望蒲菖海浪回。", "山戴鰲頭天外出，水浮鰍穴地中來。", "千重側崦扶摇沒，萬里分流混沌開。"]'),
('13a11567-7850-4bc4-aa7b-37e7d3ccbbc7','能仁禪寺','許將','宋','宋诗','song-poetry','','[]','峭壁半寒空，叢林甲海東。',48,'全唐诗/poet.song.47000.json','["峭壁半寒空，叢林甲海東。", "蕩深無過雁，湫小有游龍。", "屏石高三面，樓峰更一重。", "客心留不得，歸聽曉霜鐘。"]'),
('0cc351e5-a642-4fe5-9352-8abebab75303','句  其一','許將','宋','宋诗','song-poetry','','[]','昨夜虎入我園，明年我作狀元。',14,'全唐诗/poet.song.47000.json','["昨夜虎入我園，明年我作狀元。"]'),
('ec700d6e-b0c7-47d2-8fb8-77dc608f355a','句  其二','許將','宋','宋诗','song-poetry','','[]','三素雲飛依北極，九農星正見南方。',16,'全唐诗/poet.song.47000.json','["三素雲飛依北極，九農星正見南方。"]'),
('19c53592-4c9a-4dd0-9fd0-61c3b3ffc4c7','句  其三','許將','宋','宋诗','song-poetry','','[]','樓臺隨地盡，江海與天浮。',12,'全唐诗/poet.song.47000.json','["樓臺隨地盡，江海與天浮。"]'),
('ed8f2529-6782-421f-a2ed-345c7b011506','吳王城','吳居厚','宋','宋诗','song-poetry','','[]','吳王宮殿作飛塵，野鳥幽花各自春。',32,'全唐诗/poet.song.47000.json','["吳王宮殿作飛塵，野鳥幽花各自春。", "料得寒溪暄笑日，也曾驚動武昌人。"]'),
('ed10fd8a-4f53-4caf-85f5-152e444115e4','九曲亭','吳居厚','宋','宋诗','song-poetry','','[]','山上盤旋九曲亭，春江滿目與天平。',32,'全唐诗/poet.song.47000.json','["山上盤旋九曲亭，春江滿目與天平。", "青蘋白鷺漁家屋，幾幅輕綃畫得成。"]'),
('d952cce3-5e73-4a22-91a8-df0f094721bc','梅山二首  其一','吳居厚','宋','宋诗','song-poetry','','[]','尋溪小徑多盤詰，車馬初來路欲迷。',32,'全唐诗/poet.song.47000.json','["尋溪小徑多盤詰，車馬初來路欲迷。", "千古英雄漢天子，桑麻今已遍標題。"]'),
('68c14cdb-b2d6-4932-b698-d1b756044113','梅山二首  其二','吳居厚','宋','宋诗','song-poetry','','[]','連雲絕壁山無路，濺石潺湲水有花。',32,'全唐诗/poet.song.47000.json','["連雲絕壁山無路，濺石潺湲水有花。", "試問昔時畬粟麥，何如今日種桑麻。"]'),
('a5d14737-8f97-4595-9544-04f3486d8e32','與部使同遊司空山','吳居厚','宋','宋诗','song-poetry','','[]','王官身已達，所悅多紛華。',120,'全唐诗/poet.song.47000.json','["王官身已達，所悅多紛華。", "區區朝與市，輕暖事窮奢。", "我公味沖澹，止樂山水嘉。", "肩輿靡厭尋，謝興無津涯。", "杖藜適意遊，野徑穿迂斜。", "回憶挂冠時，息此避喧譁。", "骨相有神仙，得道成全家。", "遺蹟富覽觀，高步淩煙霞。", "靜中白日長，玉宇清風賒。", "睹茲神聖蹟，喟然興歎嗟。"]'),
('ed733d54-6234-4d12-9d2c-543a2e9c3fc6','句','吳居厚','宋','宋诗','song-poetry','','[]','步尋斜徑到寒溪。',8,'全唐诗/poet.song.47000.json','["步尋斜徑到寒溪。"]'),
('d7618b89-4ada-4d57-a224-93b5fa59f850','送程給事知越州','朱肱','宋','宋诗','song-poetry','','[]','四官江左皆才選，去愛存懷率在民。',64,'全唐诗/poet.song.47000.json','["四官江左皆才選，去愛存懷率在民。", "使者今持丹鳳詔，使君新駕兩朱輪。", "舊時再訪鍾陵草，和氣重舒澤國春。", "解橐莫爲遲久計，甘泉延閣待名臣。"]'),
('d9d4f712-3a15-4909-b6d1-b08d47a18ab2','南池','陳丕','宋','宋诗','song-poetry','','[]','雜樹疏陰覆小亭，池塘流水自泠泠。',64,'全唐诗/poet.song.47000.json','["雜樹疏陰覆小亭，池塘流水自泠泠。", "殘荷猶結高秋綠，深柳遍含斜日清。", "宇內誰堪千古在，眼中吾已二毛侵。", "舊時游侶晨星似，牆角啼蛩不可聽。"]'),
('42130fcd-49e8-4896-a7fd-7ce9487d7366','句','陳丕','宋','宋诗','song-poetry','','[]','春禽得意千般語，澗草無名百種香。',16,'全唐诗/poet.song.47000.json','["春禽得意千般語，澗草無名百種香。"]'),
('2a55283e-84cd-425f-ad15-7a710cf042c6','送宋承旨歸覲大母劉太夫人','薛似宗','宋','宋诗','song-poetry','','[]','遠衝風雪渡錢塘，欲趁春風到故鄉。',64,'全唐诗/poet.song.47000.json','["遠衝風雪渡錢塘，欲趁春風到故鄉。", "百歲報劉知日短，一身許國喜心長。", "才名磊落傳金馬，旌蓋輝煌出玉堂。", "豈若他人思陟岵，無憂靡盬不遑將。"]'),
('7f14a656-63da-46a6-831a-1203de5b03f7','戲題團扇自寫山水','薛似宗','宋','宋诗','song-poetry','','[]','拂將團扇點江春，難與班姬咏並珍。',32,'全唐诗/poet.song.47000.json','["拂將團扇點江春，難與班姬咏並珍。", "非爲墨池雲霧好，自來不以筆干人。"]'),
('1d886955-e4c6-4712-89ae-7071d948a441','題梅山','張景端','宋','宋诗','song-poetry','','[]','作尉南昌日，投書北闕頻。',240,'全唐诗/poet.song.47000.json','["作尉南昌日，投書北闕頻。", "忠言不悟主，直節恥爲臣。", "漢室多災異，吳門念隠淪。", "掛冠忘寵辱，蒙袂出埃塵。", "虹屈英雄氣，鷗羣自在身。", "永懷三洞訣，高謝九江春。", "擇地開仙館，看雲翦壽巾。", "玄臺秋步月，虛室夜凝真。", "無夢生芳草，留年養大椿。", "碧茸香不斷，青鳥性偏馴。", "太液刀圭就，中黄道路新。", "武夷空墜馬，郁木竟棲神。", "絳節雖朝帝，靈波尚濟民。", "一名傳舊史，千古事嚴禋。", "瑞氣生仙藥，清風付羽人。", "壇遺金鼎像，井鎖玉華津。", "地接洪崖府，溪通劍水濱。", "鶴歸雲抖擻，龍起石鱗皴。", "已悟身爲患，元期德有鄰。", "青山不忘我，今日是天親。"]'),
('6d722b61-d27c-44e1-9db8-831aec25ba49','挽劉南溪','李潛','宋','宋诗','song-poetry','','[]','今年人苦旱蝗饑，正需平糶無南溪。',102,'全唐诗/poet.song.47000.json','["今年人苦旱蝗饑，正需平糶無南溪。", "今年江南梅不開，正恨南溪詩不來。", "李悝不作雖堪傷，不過饑民雷轉腸。", "少陵不作世懔懔，乾坤萬象無題品。", "蒼天蒼天能令南溪迹成古，不信收得詩名和迹去。", "吁嗟笏筆千丈强，風淡淡兮煙蒼蒼。"]'),
('23aa131e-6507-4a13-bc0b-5e53287e0c72','挽羅斯立','李潛','宋','宋诗','song-poetry','','[]','金玉不論富，癯然學孟軻。',48,'全唐诗/poet.song.47000.json','["金玉不論富，癯然學孟軻。", "兩番新貢士，半世老監河。", "發粟歲無歉，橫橋春不波。", "陰功寫難盡，留與邑人歌。"]'),
('345f596e-4468-45a0-b53b-041df4eee009','宗教院','劉鑄','宋','宋诗','song-poetry','','[]','雨過江山麗，春深筍蕨肥。',24,'全唐诗/poet.song.47000.json','["雨過江山麗，春深筍蕨肥。", "扶藜蒼蘚破，移榻亂雲飛。"]'),
('a8f5a6a3-2790-403b-9445-c0f1c61ddcb9','題竹軒','方洵武','宋','宋诗','song-poetry','','[]','勁節孤根得地深，清虛誰識子猷心。',32,'全唐诗/poet.song.47000.json','["勁節孤根得地深，清虛誰識子猷心。", "當時不是琅玕種，月下何由聽鳳琴。"]'),
('de54012b-0e4d-464a-8232-451cede3302c','題寧國院十全堂','方洵武','宋','宋诗','song-poetry','','[]','盧扁不世出，死生非在人。',120,'全唐诗/poet.song.47000.json','["盧扁不世出，死生非在人。", "草木孕妙理，金玉潜至神。", "用之固有序，品制非君臣。", "世之挾術者，不啻空中塵。", "悉以利自售，幽枉何由伸。", "韞公藥之師，所得無非真。", "構堂備觀寂，榜墨如堆雲。", "再味維摩言，深憫芭蕉身。", "我病衆生病，當推病之因。", "諸幻起諸妄，勿藥常欣欣。"]'),
('6387d99a-9d4f-4d74-9907-bd7dc29cf18b','海棠','張冕','宋','宋诗','song-poetry','','[]','海棠栽植遍塵寰，未必成都欲咏難。',320,'全唐诗/poet.song.47000.json','["海棠栽植遍塵寰，未必成都欲咏難。", "山木瓜開千顆顆，水林檎發一攢攢。", "初疑紅豆爭頭綴，忽覺燕脂衆手丸。", "西蜀僧家根撥小，南荆官舍樹支寬。", "高穿羣木無因蔽，平倚危樓最好看。", "十畝園林渾似火，數方池面悉如丹。", "錦袍萬丈仍連袂，珠被齊光更合歡。", "風嫋細腰妝正罷，露晞銅雀淚新乾。", "晨曦遠借彤雲暖，秋魄微侵甲帳寒。", "會讌豈勞供幄幕，採香應見費龍檀。", "穠燒游女青絲髮，殷染妖姬白玉冠。", "賓席半移隈茜綬，使車多熱簇雕鞍。", "層層排朵縈飛蝶，密密交柯宿翠翰。", "詩客早慚矜鏤管，畫工誰敢衒霜紈。", "本期相伴千場醉，可忍輕邀百卉殘。", "川路尚移隨迅瀨，蕃船猶折出長瀾。", "飄零絳雪深盈尺，收拾晴霞散結團。", "時去獨應賢者識，色空前有達人觀。", "譜爲僊子終須美，實作寒梅況不酸。", "五六年來離別恨，春宵頻夢石臺盤。"]'),
('39ec7436-83b9-4d3b-b53f-98a7ab0bc56f','西園海棠','張冕','宋','宋诗','song-poetry','','[]','丹葩翠葉競妖濃，蜂蝶翻翻弄暖風。',64,'全唐诗/poet.song.47000.json','["丹葩翠葉競妖濃，蜂蝶翻翻弄暖風。", "濯雨正疑宮錦爛，媚晴先奪曉霞紅。", "芬菲劍外從來勝，歡賞天涯爲爾同。", "却想鄉關足塵土，只應能見畫圖中。"]'),
('f55dee66-3465-4f02-81fd-c4e608bd14a3','貧居','張景脩','宋','宋诗','song-poetry','','[]','茅檐月有千金稅，稻飯年無一粒租。',32,'全唐诗/poet.song.47000.json','["茅檐月有千金稅，稻飯年無一粒租。", "生事蕭條人問我，水芭蕉與石菖蒲。"]'),
('8f8ddf90-16c7-4d2d-aec1-6ec369122fbb','送朱天錫童子','張景脩','宋','宋诗','song-poetry','','[]','黄金滿籯富有餘，一經教子金不如。',160,'全唐诗/poet.song.47000.json','["黄金滿籯富有餘，一經教子金不如。", "君家有兒不肯娛，口誦七經隨卷舒。", "渥洼從來産龍駒，鸑鷟乃是真鳳雛。", "一朝過我父子俱，自稱窮苦世爲儒。", "雪窗夜映孫康書，春隴晝荷兒寬鋤。", "翻然西入天子都，出門慷慨曳長裾。", "神童之科今有無，談經射策皆壯夫。", "古來取士凡數塗，但願一一令吹竽。", "甘羅相秦理不誣，世人看取掌中珠。", "折腰未便賦歸歟，待君釋褐還鄉閭。"]'),
('c38e6789-39ba-4fb5-aaaa-dca75c889020','睡香花','張景脩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','曾向廬山睡裏聞，香風占斷世間春。',32,'全唐诗/poet.song.47000.json','["曾向廬山睡裏聞，香風占斷世間春。", "竊花莫撲枝頭蝶，驚覺南窗半夢人。"]'),
('94be42bd-308b-434e-91b4-7e3cc9a0814a','宿清溪安樂山','張景脩','宋','宋诗','song-poetry','','[]','映窗猶剩雪餘痕，瓶裏梅花枕上聞。',64,'全唐诗/poet.song.47000.json','["映窗猶剩雪餘痕，瓶裏梅花枕上聞。", "一椀鐙寒聽夜雨，半牀氈暖卧春雲。", "詩成始覺茶銷睡，香盡翻嫌酒带醺。", "我是掛冠林下客，山中安樂合平分。"]'),
('ea71227c-2c6f-4387-bfd9-4bb4bf045445','過桐廬邑二首  其一','張景脩','宋','宋诗','song-poetry','','[]','隠君無姓字，何代至今存。',48,'全唐诗/poet.song.47000.json','["隠君無姓字，何代至今存。", "數里山爲宅，兩株桐是孫。", "人煙半峰碧，溪水带潮渾。", "多少來游客，茫茫蹋藥根。"]'),
('317ffa57-43f8-4af5-98f0-9cc99dd04053','過桐廬邑二首  其二','張景脩','宋','宋诗','song-poetry','','[]','三載江南客，還吳東復西。',48,'全唐诗/poet.song.47000.json','["三載江南客，還吳東復西。", "潮貪兩溪盡，雲截衆山齊。", "舟楫無空日，樓臺半上梯。", "桐廬隠君子，應笑只留題。"]'),
('81175a5b-576e-45fc-a5be-e19c1229385e','釣臺','張景脩','宋','宋诗','song-poetry','','[]','羊裘東漢客，歸隠釣魚灘。',48,'全唐诗/poet.song.47000.json','["羊裘東漢客，歸隠釣魚灘。", "天子不能屈，先生非苟難。", "雲藏古石在，風激世人寒。", "祠下青青竹，何妨把釣竿。"]'),
('8ed6b35d-5358-4392-a013-367b15281e5f','清芬閣','張景脩','宋','宋诗','song-poetry','','[]','嚴子釣臺畔，猶聞吟嘯聲。',48,'全唐诗/poet.song.47000.json','["嚴子釣臺畔，猶聞吟嘯聲。", "榮華付諸弟，蕭灑繼先生。", "自製茶槍嫩，新開酒面清。", "紅塵不拋擺，那得白雲名。"]'),
('3b875133-6da2-4581-b538-0aaff6557a29','題永慶覽勝亭','張景脩','宋','宋诗','song-poetry','','[]','衙城直上有煙巒，亭在懸崖絕壁間。',64,'全唐诗/poet.song.47000.json','["衙城直上有煙巒，亭在懸崖絕壁間。", "幾箇白頭忘歲月，一生青眼看江山。", "秋風落木樓臺出，暮雨籠沙鷗鷺閒。", "珍重京西繡衣使，作書題榜許追攀。"]'),
('039298f4-d625-44aa-a3a9-d76d601185e6','題北山松軒','張景脩','宋','宋诗','song-poetry','','[]','雪天蒼翠暑天風，珍重僧軒十八公。',32,'全唐诗/poet.song.47000.json','["雪天蒼翠暑天風，珍重僧軒十八公。", "不是時人少吟咏，世閒花草易爲工。"]'),
('e2723a78-deb3-4b20-a828-3a9a461812ac','題竹軒','張景脩','宋','宋诗','song-poetry','','[]','種竹纔添十數竿，題詩已僅百餘篇。',64,'全唐诗/poet.song.47000.json','["種竹纔添十數竿，題詩已僅百餘篇。", "有時碎影摇金地，盡日清風伴玉泉。", "不與愛魚人把釣，肯教騎馬客求鞭。", "平生最喜此君子，一灑何當聽雨眠。"]'),
('571fb7ad-c1d7-47f3-9eb0-5b4643c188d5','題玉泉','張景脩','宋','宋诗','song-poetry','','[]','長疑數尺玉，乃是一方泉。',48,'全唐诗/poet.song.47000.json','["長疑數尺玉，乃是一方泉。", "粉色和雲汲，茶香带石煎。", "鑑來誠美矣，聞處合鏗然。", "白首惠山客，也須吟此篇。"]'),
('e5dff683-bff7-4fa0-b8db-3df6db686224','遊栖霞宮','張景脩','宋','宋诗','song-poetry','','[]','偶先諸邑過栖霞，恰費盧仝七碗茶。',32,'全唐诗/poet.song.47000.json','["偶先諸邑過栖霞，恰費盧仝七碗茶。", "此會果然□邂逅，轉相尋覓到仙家。"]'),
('3eed21b2-c261-4e83-ba9e-3b444b338e89','題寧國縣十全堂','張景脩','宋','宋诗','song-poetry','','[]','醫莫以人試，藥能生死人。',120,'全唐诗/poet.song.47000.json','["醫莫以人試，藥能生死人。", "十失爲一次，望而知謂神。", "嘗聞秦醫和，診君知其臣。", "豈無肘後方，埋沒隨埃塵。", "韞師以愈疾，猶如臂屈伸。", "華佗醫之良，思邈醫之真。", "誰能不服藥，一一如朱雲。", "斯堂名十全，全人亦全身。", "方公諳藥性，勇退蓋此因。", "金玉不足寶，人生繫悲忻。"]'),
('083f6ccb-00e2-4168-8003-6eea6e15afe0','寄題開福院白蓮堂','張景脩','宋','宋诗','song-poetry','','[]','玉色荷花自是仙，道人更慕遠公賢。',32,'全唐诗/poet.song.47000.json','["玉色荷花自是仙，道人更慕遠公賢。", "此生欲結東林社，求取新詩十八篇。"]'),
('213a85d5-7c31-4459-bd29-7a80e9c338ca','題無垢寺','張景脩','宋','宋诗','song-poetry','','[]','禪房閉深花，錫杖生古蘚。',48,'全唐诗/poet.song.47000.json','["禪房閉深花，錫杖生古蘚。", "秋山翡翠寒，春水玻瓈軟。", "無嫌牆太低，但恐路不遠。", "何人坐長松，令我思韋偃。"]'),
('76fe7bfc-556a-4d22-973e-2249cb811d75','福應山','張景脩','宋','宋诗','song-poetry','','[]','南亭不減北邙高，美景因公見一朝。',64,'全唐诗/poet.song.47000.json','["南亭不減北邙高，美景因公見一朝。", "已看溪山如在畫，更傳風雅似聞韶。", "栽桃定有仙家住，種竹寧無隠者招。", "秀氣當爲多士福，未應都放與漁樵。"]'),
('cc160200-c1cc-47a6-b17d-2abb0f698bd9','三賢堂','張景脩','宋','宋诗','song-poetry','','[]','如是國清寺，宜乎天下聞。',48,'全唐诗/poet.song.47000.json','["如是國清寺，宜乎天下聞。", "水聲常夜雨，山氣即朝雲。", "今古三賢隠，仙凡兩路分。", "唐人書畫在，明日更慇懃。"]'),
('5a295bbf-9a73-43e6-b101-ad5a14749ed5','崇教寺筠軒','張景脩','宋','宋诗','song-poetry','','[]','碧玉窗欞三四閒，一溪流水伴君閒。',32,'全唐诗/poet.song.47000.json','["碧玉窗欞三四閒，一溪流水伴君閒。", "雪中惜取青青節，不用開林自見山。"]'),
('7653a66c-4fde-4ed8-ac6b-a88fea54dc43','石橋','張景脩','宋','宋诗','song-poetry','','[]','天與晴來抵萬金，更逢詩伯共登臨。',64,'全唐诗/poet.song.47000.json','["天與晴來抵萬金，更逢詩伯共登臨。", "輟公一夜楞嚴講，慰我十年方廣心。", "白雪陽春雖寡和，高山流水有知音。", "石橋天下無雙景，好盡平生得處吟。"]'),
('1d6b6d46-af74-40df-858d-c7b3a50e4702','醉眠亭','張景脩','宋','宋诗','song-poetry','','[]','樽前從客笑，夢裏任花飛。',48,'全唐诗/poet.song.47000.json','["樽前從客笑，夢裏任花飛。", "野鳥喚不醒，家童扶未歸。", "有榮還有辱，無是即無非。", "萬事藏於酒，先生亦見機。"]'),
('6e8454bc-93b2-4b7e-839c-8de769c2a672','寄湖南憲請祠葉公','張景脩','宋','宋诗','song-poetry','','[]','聞說年來請洞霄，江湖奉使久勤勞。',64,'全唐诗/poet.song.47000.json','["聞說年來請洞霄，江湖奉使久勤勞。", "有神仙處閒方得，用老成時退更高。", "借宅但知新種竹，尋真想見舊栽桃。", "浮梁居士塵埃甚，鬚髮而今已二毛。"]'),
('bc7b92fb-2e86-4a67-91d3-4791a28ce8e1','遊九鎖山','張景脩','宋','宋诗','song-poetry','','[]','九鎖山中多隠仙，洞門終古掩雲煙。',64,'全唐诗/poet.song.47000.json','["九鎖山中多隠仙，洞門終古掩雲煙。", "茶生東塢偏迎日，松老西巌不記年。", "翠箬久藏千歲藥，碧池深納半山泉。", "蒼崖縱使秦驅得，未信能移一柱天。"]'),
('763556cd-a845-4d5f-804a-9f8cc8398808','九月望夜與詩僧可久泛西湖','張景脩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山風獵獵釀寒威，林下山僧見亦稀。',32,'全唐诗/poet.song.47000.json','["山風獵獵釀寒威，林下山僧見亦稀。", "怪得題詩無俗語，十年肝鬲湛清輝。"]'),
('469e647f-e135-4089-a3d2-46bfbfb83247','湖州覺海彌陀閣','張景脩','宋','宋诗','song-poetry','','[]','仙潭覺海唐興善，像設璝琦古至今。',64,'全唐诗/poet.song.47000.json','["仙潭覺海唐興善，像設璝琦古至今。", "殿柱倒書雷部火，市橋橫渡木觀音。", "窗前竹影摇金翠，風外蓮香散水沉。", "况有彌陀新建閣，動人無限往生心。"]'),
('a20747db-7bfe-439f-96bc-b85ce7d1addd','更高亭','張景脩','宋','宋诗','song-poetry','','[]','稚子山妻伴老翁，重陽尋遍菊花叢。',32,'全唐诗/poet.song.47000.json','["稚子山妻伴老翁，重陽尋遍菊花叢。", "明年把酒知何處，却憶高亭是夢中。"]'),
