('0aa84717-34f3-4d45-86db-62e57d903e32','句','黄康民','宋','宋诗','song-poetry','','[]','三山寶剎棲禪地，萬戶青簾賣酒家。',16,'全唐诗/poet.song.47000.json','["三山寶剎棲禪地，萬戶青簾賣酒家。"]'),
('7a012311-f07a-4867-a1ed-19982a1b5c15','成都運司園亭十首 西園','楊怡','宋','宋诗','song-poetry','','[]','池臺密相望，曾是故侯宅。',48,'全唐诗/poet.song.47000.json','["池臺密相望，曾是故侯宅。", "賞心知幾人，喬木已百尺。", "低花拂烏帽，古蘚駮蒼石。", "欲問昔豪華，秋風掃無迹。"]'),
('7f2ea50e-a754-411b-bf81-227db5e3f4bb','成都運司園亭十首 玉谿堂','楊怡','宋','宋诗','song-poetry','','[]','虛堂已深窈，那復要營室。',48,'全唐诗/poet.song.47000.json','["虛堂已深窈，那復要營室。", "使君寂無事，閉閤卧終日。", "臨池狎清泚，養竹聽簫瑟。", "不爲省春耕，軺車肯輕出。"]'),
('69feaa37-39e3-401d-8b56-77a0810f8447','成都運司園亭十首 雪峰樓','楊怡','宋','宋诗','song-poetry','','[]','翛翛樓下竹，㶁㶁竹間水。',48,'全唐诗/poet.song.47000.json','["翛翛樓下竹，㶁㶁竹間水。", "樓高雖不見，清響長在耳。", "晨光露西崦，積玉照窗紙。", "崑閬亦何人，當從跨金鯉。"]'),
('67f9d5d4-28b3-4a25-b345-4c40d9031f74','成都運司園亭十首 海棠軒','楊怡','宋','宋诗','song-poetry','','[]','花如窈窕人，宛在水中沚。',48,'全唐诗/poet.song.47000.json','["花如窈窕人，宛在水中沚。", "當軒有餘妍，終日玩芳蘤。", "池清藻壓枝，波動魚爭蕊。", "錦帳想含春，歸心浩然起。"]'),
('6f9d6fb2-9c47-46e2-8826-5bb4b190558a','成都運司園亭十首 月臺','楊怡','宋','宋诗','song-poetry','','[]','嘉木密交陰，月夕苦薈翳。',48,'全唐诗/poet.song.47000.json','["嘉木密交陰，月夕苦薈翳。", "高臺出林杪，遠目望天際。", "不厭清露寒，秪恐輕雲蔽。", "可但少陵翁，能思斫仙桂。"]'),
('352fb093-9b3a-41c1-b926-63b74a5902d8','成都運司園亭十首 翠錦亭','楊怡','宋','宋诗','song-poetry','','[]','峨峨碧油幢，矗矗羽葆蓋。',48,'全唐诗/poet.song.47000.json','["峨峨碧油幢，矗矗羽葆蓋。", "燕居不廢嚴，環竦布亭外。", "穠陰生晝寒，微吹發天籟。", "隠几對凝香，衣冠嗒如蛻。"]'),
('d5329ee3-0412-4e49-8e8f-2526e0c65372','成都運司園亭十首 潺玉亭','楊怡','宋','宋诗','song-poetry','','[]','使君漱流心，官府未始忘。',48,'全唐诗/poet.song.47000.json','["使君漱流心，官府未始忘。", "亭下玉谿水，撲碎白玉璫。", "清耳不待洗，高懷自滄浪。", "安得援瑶琴，寫此聲琅琅。"]'),
('5d2661e0-5caa-44c7-9210-9d7cefaef558','成都運司園亭十首 茅庵','楊怡','宋','宋诗','song-poetry','','[]','緝茅如蝸廬，容膝纔一丈。',48,'全唐诗/poet.song.47000.json','["緝茅如蝸廬，容膝纔一丈。", "規圓無四隅，空廓含萬象。", "繩牀每宴坐，不與物俯仰。", "惟許歲寒君，虛心環几杖。"]'),
('b60172e2-a51d-470b-9679-40a9d527734b','成都運司園亭十首 水閣','楊怡','宋','宋诗','song-poetry','','[]','小閣平池陽，危橋屬花嶼。',48,'全唐诗/poet.song.47000.json','["小閣平池陽，危橋屬花嶼。", "杖履樂幽閑，龜魚蔭深阻。", "刻柱記新漲，弄水滌煩暑。", "物我久相忘，珍禽近人語。"]'),
('f1c28366-3cdc-4e42-a5dc-75da8b746888','成都運司園亭十首 小亭','楊怡','宋','宋诗','song-poetry','','[]','方亭惟四柱，對峙花竹間。',48,'全唐诗/poet.song.47000.json','["方亭惟四柱，對峙花竹間。", "下有雪嶺水，淙流日潺潺。", "宛如雙綵舸，纜向春波灣。", "欲起江湖心，而奈風濤艱。"]'),
('4ec3d44f-56b3-4991-aa94-b77ac8a6e0bc','句','羅尚友','宋','宋诗','song-poetry','','[]','人間酒客兼詩客，天上文星與將星。',16,'全唐诗/poet.song.47000.json','["人間酒客兼詩客，天上文星與將星。"]'),
