('a3433835-dbdb-4b1c-b90f-6bb56cb6463a','自紫極觀過天柱','陳良','宋','宋诗','song-poetry','','[]','道在吾身宇宙寬，朝踰雲岫暮雲關。',32,'全唐诗/poet.song.47000.json','["道在吾身宇宙寬，朝踰雲岫暮雲關。", "丹靈不服春風轉，欲度世人那得閒。"]'),
('01787588-bb76-4f11-b451-9c34b8ba7dc5','雪中浴冷泉示諸友','陳良','宋','宋诗','song-poetry','','[]','風鼓空林雪蔽山，身如鐵石不知寒。',32,'全唐诗/poet.song.47000.json','["風鼓空林雪蔽山，身如鐵石不知寒。", "塵埃豈是相隨物，付與溪流出世閒。"]'),
('3b913ce3-df7c-4f14-815e-cbc0333bc7de','瓊花','陳良','宋','宋诗','song-poetry','','[]','淮海春深照月長，靈祠佳樹擅孤芳。',64,'全唐诗/poet.song.47000.json','["淮海春深照月長，靈祠佳樹擅孤芳。", "人迷三月天山雪，風逗千門漢殿香。", "上苑菁葱思舊賞，金閨回旋入新章。", "後庭遺韵歌聲好，試折瓊枝薦一觴。"]'),
('de2e87d5-b0f4-41f1-b578-be8c9cc46529','詩一首','陳良','宋','宋诗','song-poetry','','[]','父子聯榮世所希，予家何幸竊恩輝。',32,'全唐诗/poet.song.47000.json','["父子聯榮世所希，予家何幸竊恩輝。", "自慚不及吾兒甚，得向親前謝綠衣。"]'),
('ae5b6ae7-2cce-430d-a75d-9f277cf4040e','珍珠簾','陳祥道','宋','宋诗','song-poetry','','[]','東風飄拂雨纖纖，吹向空中草木霑。',32,'全唐诗/poet.song.47000.json','["東風飄拂雨纖纖，吹向空中草木霑。", "記得傳喧三殿日，恍疑天半撒珠簾。"]'),
('fd5f8876-9604-4ed0-a0a4-aef3cafd666e','新月','胡時中','宋','宋诗','song-poetry','','[]','星珠錯落飛破鏡，玉斧應須及時整。',64,'全唐诗/poet.song.47000.json','["星珠錯落飛破鏡，玉斧應須及時整。", "雖然光細輪未安，猶得山河半邊影。", "幾人矯首望嬋娟，三五二八清光圓。", "光被四表千萬年，不獨長挂西南天。"]'),
('e0b33b5b-5732-43eb-9164-4a2be6d1892f','清明行','胡時中','宋','宋诗','song-poetry','','[]','憶昔父母康健時，清明携我上丘壠。',64,'全唐诗/poet.song.47000.json','["憶昔父母康健時，清明携我上丘壠。", "如今清明我獨來，却將小兒拜先冢。", "凝情東風淚滿衣，江山雖是昔人非。", "兒兒問我悲何事，此意他年汝自知。"]'),
('29ab041a-f180-4623-8356-3cb308d60655','濉江','謝詗','宋','宋诗','song-poetry','','[]','雨過濉江宿靄收，粼粼澄碧凈涵秋。',64,'全唐诗/poet.song.47000.json','["雨過濉江宿靄收，粼粼澄碧凈涵秋。", "雙橋夾鎖虹垂岸，練疋長拖玉作流。", "白鳥孤飛天外沒，青螺倒浸鏡中浮。", "朝宗東去知何極，願一乘槎探盡頭。"]'),
('a5c13e97-b192-4cb1-b62e-6663dadd1ede','題梵天寺','釋守詮','宋','宋诗','song-poetry','','[]','落日寒蟬鳴，獨歸林下寺。',36,'全唐诗/poet.song.47000.json','["落日寒蟬鳴，獨歸林下寺。", "松扉竟未掩，片月隨行屨。", "時聞犬吠聲，更入青蘿去。"]'),
('d0313d10-39a3-4fb8-b7c6-8956d278f3bd','醉眠亭三首  其一','韓宗文','宋','宋诗','song-poetry','','[]','萬慮中來攪不眠，醉時一覺自陶然。',32,'全唐诗/poet.song.47000.json','["萬慮中來攪不眠，醉時一覺自陶然。", "冥冥固已忘天地，豈向杯中覓聖賢。"]'),
('4ee474a6-99a6-40c4-bbc5-c684caae82c6','醉眠亭三首  其二','韓宗文','宋','宋诗','song-poetry','','[]','得酒休論飲得仙，醉中遺物爲神全。',32,'全唐诗/poet.song.47000.json','["得酒休論飲得仙，醉中遺物爲神全。", "世閒反覆無窮事，吏部難忘抱甕眠。"]'),
('0ac32c9d-4a5c-435d-af10-9a829a01ecf7','醉眠亭三首  其三','韓宗文','宋','宋诗','song-poetry','','[]','昔有遺賢世所憐，滄浪亭下醉時眠。',32,'全唐诗/poet.song.47000.json','["昔有遺賢世所憐，滄浪亭下醉時眠。", "松江變酒終難待，却對殘燈理短編。"]'),
('2018175b-acb6-4544-9d95-3770f56de2a0','醉眠亭四首  其一','晁端佐','宋','宋诗','song-poetry','','[]','瀟灑松陵江上亭，醉來一夢傲雲屏。',32,'全唐诗/poet.song.47000.json','["瀟灑松陵江上亭，醉來一夢傲雲屏。", "生前笑語君須惜，世事紛紛不用醒。"]'),
('74913b03-bfd4-4431-8404-5289d756d71e','醉眠亭四首  其二','晁端佐','宋','宋诗','song-poetry','','[]','盤石幽亭樂未央，是非窮達兩相忘。',32,'全唐诗/poet.song.47000.json','["盤石幽亭樂未央，是非窮達兩相忘。", "塵寰下望知何許，爛醉高眠自有鄉。"]'),
('80a8573e-f324-4007-a6b2-ed6e03cef8ff','醉眠亭四首  其三','晁端佐','宋','宋诗','song-poetry','','[]','塵埃收得一身閑，飲盡春瓶曝背眠。',32,'全唐诗/poet.song.47000.json','["塵埃收得一身閑，飲盡春瓶曝背眠。", "醉耳猶嫌山鳥聒，夢魂終日上高天。"]'),
('b0b21f07-a902-41fa-80cc-b9d958f6c201','醉眠亭四首  其四','晁端佐','宋','宋诗','song-poetry','','[]','一枕雙湖意浩然，狂歌酒盡即高眠。',32,'全唐诗/poet.song.47000.json','["一枕雙湖意浩然，狂歌酒盡即高眠。", "吾生久與時相棄，好逐君歸作二仙。"]'),
('b3cf232d-e8b0-4df0-a58c-c5f800d906c2','白雲','管師復','宋','宋诗','song-poetry','','[]','入寺層層百級梯，野堂更與白雲齊。',32,'全唐诗/poet.song.47000.json','["入寺層層百級梯，野堂更與白雲齊。", "平觀碧落星辰近，俯見紅塵世界低。"]'),
('286658b6-f163-4386-8600-c278abf217c4','句','管師復','宋','宋诗','song-poetry','','[]','滿塢白雲耕不破，一潭明月釣無痕。',16,'全唐诗/poet.song.47000.json','["滿塢白雲耕不破，一潭明月釣無痕。"]'),
('54c2ce3f-2998-458c-bd71-6033db697c40','題小雁屏二首  其一','陳氏','宋','宋诗','song-poetry','','[]','蓼淡蘆敧曲水通，幾雙容與對西風。',32,'全唐诗/poet.song.47000.json','["蓼淡蘆敧曲水通，幾雙容與對西風。", "扁舟阻向江鄉去，却喜相逢一枕中。"]'),
('2068136b-50ea-4e4b-b9f5-6d89378b18ff','題小雁屏二首  其二','陳氏','宋','宋诗','song-poetry','','[]','曲屏誰畫小瀟湘，雁落秋風蓼半黄。',32,'全唐诗/poet.song.47000.json','["曲屏誰畫小瀟湘，雁落秋風蓼半黄。", "雲澹雨疏孤嶼遠，會令清夢到高唐。"]'),
('e5efeb26-c76d-4880-ac67-3f2e0e904279','秋月二首  其一','孔文仲','宋','宋诗','song-poetry','','[]','孤枕夜何永，破窗秋已寒。',48,'全唐诗/poet.song.47000.json','["孤枕夜何永，破窗秋已寒。", "雨聲衝夢斷，霜氣襲衣單。", "利劍摧鋒鍔，蒼鸇縮羽翰。", "平生衝斗氣，變作淚汍瀾。"]'),
('d207f39f-031d-410f-8b1f-9e173e3b8168','秋月二首  其二','孔文仲','宋','宋诗','song-poetry','','[]','秋夜不可晨，悲歌聊自永。',48,'全唐诗/poet.song.47000.json','["秋夜不可晨，悲歌聊自永。", "頫聽一掀簾，星河光烱烱。", "霜浮萬瓦寂，月滿四山靜。", "壯心隨北風，吹入單于境。"]'),
('d1706ebf-3a3f-42a8-b457-0ec8163768b3','次錢穆父新凉可喜','孔文仲','宋','宋诗','song-poetry','','[]','商飆結新寒，草木起餘怨。',120,'全唐诗/poet.song.47000.json','["商飆結新寒，草木起餘怨。", "翩翩前庭葉，追逐已千萬。", "斜陽背西壁，迤邐落藤蔓。", "安得金滿堂，聊換酒家券。", "追隨雙鴻鵠，擺脫舊籠圈。", "胡爲汗流赭，日與蠅爭飯。", "常恐計不就，更以詩屢勸。", "江湖秋水高，百尺風帆健。", "何當開竹溪，玉腕互酬獻。", "左手持蟹螯，平昔固有願。"]'),
('a10deb39-e4fc-4b09-a213-94e2bd983b6e','四月三十日慈孝寺山亭席上口占送子敦都運待制赴河北','孔文仲','宋','宋诗','song-poetry','','[]','送客城南寺，蕭然雲水秋。',96,'全唐诗/poet.song.47000.json','["送客城南寺，蕭然雲水秋。", "客意在萬里，聊作須臾遊。", "昨夜過新雨，清風滿梁州。", "簪裳合俊彥，河圖並天球。", "古來功名人，未就不肯休。", "譬如鑿空使，尚致安石榴。", "矧今南畝氓，往往東西流。", "君能安輯之，千倉與萬輈。"]'),
('8415d4a8-ce1c-4651-b9c4-b0511a68f30e','將至南都途中感舊二首寄錢穆父  其一','孔文仲','宋','宋诗','song-poetry','','[]','北風吹雪滿皇州，携手同爲落魄遊。',64,'全唐诗/poet.song.47000.json','["北風吹雪滿皇州，携手同爲落魄遊。", "霄漢路歧騰萬里，江湖塵土積千憂。", "世情共逐飛蓬轉，人事都如激浪流。", "只待清談慰愁病，月明幾度促歸舟。"]'),
('7c28488c-e87d-4138-a615-cfc5485fa4fd','將至南都途中感舊二首寄錢穆父  其二','孔文仲','宋','宋诗','song-poetry','','[]','苒苒星霜七換年，故人已上碧雲天。',64,'全唐诗/poet.song.47000.json','["苒苒星霜七換年，故人已上碧雲天。", "書憑去雁雖無便，路出名都亦有緣。", "秋晚樓臺風作雪，雨餘碕岸柳生煙。", "應煩北道開樽俎，又費公庖幾萬錢。"]'),
('f7152f55-aa6a-441c-9270-4e4a681ad804','次韵穆父見戲','孔文仲','宋','宋诗','song-poetry','','[]','當年同望赭袍光，萬事爭先落彩鋩。',64,'全唐诗/poet.song.47000.json','["當年同望赭袍光，萬事爭先落彩鋩。", "一別已經陵谷變，再來方覺路岐長。", "黄金久壓腰間重，白筆纔容柱下藏。", "唯願山林息枹鼓，免教鴟隼嚇鴛凰。"]'),
('6956b2d7-cacb-4a1b-b62d-1f0c545883f5','天官顓面正朝','孔文仲','宋','宋诗','song-poetry','','[]','天官惟將相，位號著璇霄。',72,'全唐诗/poet.song.47000.json','["天官惟將相，位號著璇霄。", "所處皆顓面，攸司共正朝。", "極星安正宁，列宿儷羣僚。", "號令三光動，吹噓二氣調。", "何參方輔漢，稷契正裨堯。", "盛旦羣龍進，乾符已上昭。"]'),
('639e9b0d-8919-470d-b0f0-60c51143f621','置章御座','孔文仲','宋','宋诗','song-poetry','','[]','聖皇勤政治，虛己納忠良。',72,'全唐诗/poet.song.47000.json','["聖皇勤政治，虛己納忠良。", "拱手居宸扆，留神置諫章。", "孜孜收國論，密密邇天光。", "中昃常游息，焦勞慎作荒。", "至言規漢后，無逸戒周王。", "默處巖廊邃，洪基可世長。"]'),
('0e56f4be-4a90-48ee-a24e-7610ad3ecac4','玉燭','孔文仲','宋','宋诗','song-poetry','','[]','聖王臻大治，四海屬休戈。',72,'全唐诗/poet.song.47000.json','["聖王臻大治，四海屬休戈。", "遂致陰陽順，均如玉燭和。", "德威周遠邇，民俗被漸摩。", "品物皆蕃殖，昌辰絕札瘥。", "氣充諸夏潤，祥應太平多。", "華旦今如此，庸才願詠歌。"]'),
('e7954ef0-5789-4d4b-aeae-d5ab1a371b03','早行','孔文仲','宋','宋诗','song-poetry','','[]','客興謂已旦，出視見落月。',120,'全唐诗/poet.song.47000.json','["客興謂已旦，出視見落月。", "瘦馬入荒陂，霜花重如雪。", "海風吹萬里，兩耳凍幾脫。", "歲晏已苦寒，近北尤凜冽。", "況當清曉行，遡此原野闊。", "笠飛带繞頸，指强不得結。", "農家烟火微，炙手粗可熱。", "豈能迂我留，而就苟且活。", "仰頭視四宇，夜氣亦漸豁。", "苦心待正晝，白日想不缺。"]'),
('5f46c6aa-625c-4658-aa3e-fdfc9728db22','次韵瀛倅鄧慎思見寄','孔文仲','宋','宋诗','song-poetry','','[]','官是麟臺却佐州，蓬瀛俱稱列仙遊。',64,'全唐诗/poet.song.47000.json','["官是麟臺却佐州，蓬瀛俱稱列仙遊。", "憶分曉色趨天闕，想對春風倚郡樓。", "書付塞鴻應易到，人如隴水正分流。", "江湖未有歸耕處，何日相逢說旅愁。"]'),
('e8781737-1d6f-48e2-a0a5-024f3797d4d3','題顯孝南山寺','孔文仲','宋','宋诗','song-poetry','','[]','尋盡城中山，又訪江外寺。',120,'全唐诗/poet.song.47000.json','["尋盡城中山，又訪江外寺。", "蘭舟涉澄漪，隼旌入疏翠。", "樓臺初日升，巖谷宿露墜。", "飛泉百禽鳴，怪石萬蛇躓。", "絕庵皆步登，佳木留客醉。", "洞天生晝寒，桃源發春意。", "烟霞暫深闊，宇宙忽殊異。", "海國遇昇平，鈴齋無俗事。", "潁川擅才敏，康樂足情意。", "只恐新詩多，鎸鑱費年祀。"]'),
('b814a113-61fe-4963-adec-dead06afd177','句','孔文仲','宋','宋诗','song-poetry','','[]','一莖青竹初出水，數箇黄蜂占作窠。',16,'全唐诗/poet.song.47000.json','["一莖青竹初出水，數箇黄蜂占作窠。"]'),
('8d99e1ef-49fc-4ca4-b810-a09ba36d890f','落雁亭','張璪','宋','宋诗','song-poetry','','[]','千古南譙炳地靈，穿雲雁塔自層層。',32,'全唐诗/poet.song.47000.json','["千古南譙炳地靈，穿雲雁塔自層層。", "殘煙落日荒墟上，父老相傳落雁亭。"]'),
('e35880ec-b267-4780-94d3-b3cc935fc672','瓊花','張璪','宋','宋诗','song-poetry','','[]','此花已去不須嗟，亡國亡家總爲他。',32,'全唐诗/poet.song.47000.json','["此花已去不須嗟，亡國亡家總爲他。", "父老不知前日事，逢人口口道瓊花。"]'),
('814b90ea-ea7e-4fc3-aca9-b3331e851a54','句','董敦逸','宋','宋诗','song-poetry','','[]','鬰江清徹底，十里郡城南。',12,'全唐诗/poet.song.47000.json','["鬰江清徹底，十里郡城南。"]'),
('fca661df-a327-4e74-b709-2bcda43c2150','此君亭歌','毛漸','宋','宋诗','song-poetry','','[]','玉堂視草儒林翁，暫憑熊軾來江東。',228,'全唐诗/poet.song.47000.json','["玉堂視草儒林翁，暫憑熊軾來江東。", "政成暇日開宴席，選勝共詣金仙宮。", "幽亭虛敞竹森聳，低徊映日清陰重。", "靜坐愛此君，乃知雅尚人情同。", "屏山疊石色蒼翠，我疑巨靈掣斷岷峨峰。", "繁霜摧枯木，飛葉穿疏櫳。", "芳筵列時果，璀璨間青紅。", "羊肋細軟蟹螯豐，兵厨酒美琥珀濃。", "褫带就坐約煩禮，幅巾相向聊從容。", "晤言與心契，至樂非絲桐。", "高懷詎比晉七子，徒以散誕相誇雄。", "飲餘寓意對棋局，萬事不足縈心胸。", "人生天地間，寧異浮萍相值江湖中。", "偶然會合復離散，東西南北隨飄風。", "須知此會不易得，爲公更釂黄金鍾。"]'),
('c3c77310-f7e1-41d8-ae61-baedc26998a4','桃源洞','毛漸','宋','宋诗','song-poetry','','[]','洞門流水日潺潺，桃塢依然枕水邊。',32,'全唐诗/poet.song.47000.json','["洞門流水日潺潺，桃塢依然枕水邊。", "春色年年花自好，遊人誰復遇嬋娟。"]'),
('bdac2283-996f-46c3-9fe0-862af357c9d9','着棋臺','游師雄','宋','宋诗','song-poetry','','[]','石橋跨兩岫，野叟嘗遠蹠。',24,'全唐诗/poet.song.47000.json','["石橋跨兩岫，野叟嘗遠蹠。", "旁有枰棋處，云是仙人奕。"]'),
('a42924d5-582d-492b-85a4-f15134f0a0e6','汲泉烹茶寄葉君康直','游師雄','宋','宋诗','song-poetry','','[]','清甘一派古祠邊，昨日親烹小鳳團。',32,'全唐诗/poet.song.47000.json','["清甘一派古祠邊，昨日親烹小鳳團。", "却恨竟陵無品目，煩君粗鑒爲嘗看。"]'),
('58ddd592-1c7a-4aae-a0e7-f27daa496127','過九成宮舊址二首  其一','游師雄','宋','宋诗','song-poetry','','[]','今古市朝已變，隋唐樓殿成空。',28,'全唐诗/poet.song.47000.json','["今古市朝已變，隋唐樓殿成空。", "惟有山頭明月，夜來猶照荒宮。"]'),
