('003395bd-0254-48e3-9906-d3548b7d9973','句  其四','溫益','宋','宋诗','song-poetry','','[]','潮迴畫楫三千隻，春滿紅樓十萬家。',16,'全唐诗/poet.song.47000.json','["潮迴畫楫三千隻，春滿紅樓十萬家。"]'),
('1889e615-a3fe-4cde-9b28-fe73bcb5400a','呈王荆公','郟亶','宋','宋诗','song-poetry','','[]','十里松陰蔣子山，暮煙收盡梵宮寬。',64,'全唐诗/poet.song.47000.json','["十里松陰蔣子山，暮煙收盡梵宮寬。", "夜深更向紫微宿，坐久始知凡骨寒。", "一派石泉流沆瀣，數庭霜竹顫琅玕。", "大鵬汎有摶風便，還許鷦鷯附羽翰。"]'),
('510a054c-c5e1-465c-8752-22f72e2ded7e','失鶴','郟亶','宋','宋诗','song-poetry','','[]','久鎖沖天鶴，金籠忽自開。',48,'全唐诗/poet.song.47000.json','["久鎖沖天鶴，金籠忽自開。", "無心戀池沼，有意出塵埃。", "鼓翼離幽砌，凌雲上紫臺。", "應陪鸞鳳侶，仙島任徘徊。"]'),
('ad1252bc-2012-4116-8702-1b1a1d8a1d0b','太倉隆福寺創觀音院以詩百韵寄妙觀大師且呈鄉中諸親舊','郟亶','宋','宋诗','song-poetry','','[]','珍重妙觀師，書來再三讀。',288,'全唐诗/poet.song.47000.json','["珍重妙觀師，書來再三讀。", "不蒙促歸計，乃憂曠箋牘。", "疑師未相知，待我尚塵俗。", "竊聞構新殿，東畔建廊屋。", "聖像已完布，舍利應祈祝。", "其餘雖未備，想亦漸周足。", "凡事在臻牢，慎勿尚遄速。", "堂基不厭高，磉窠須剩築。", "閒架莫求大，却須擇良木。", "椽桷貴稠直，楣栱要恒篤。", "但得規摹成，不憂無人續。", "五年縱未就，十年亦未蹙。", "今生不能了，後世亦修復。", "中庭要寬廣，從舍須團簇。", "堂前種杉檜，方丈植慈竹。", "冬青繞周遭，夏初香馥郁。", "松篁又次之，瀟灑快胸腹。", "園中開數徑，晚步散踡跼。", "沿階種藥苗，乘閒采盈掬。", "川芎并地黄，幽蘭間甘菊。", "泡水須麥門，熬湯要鶑粟。", "蘘莪并狗杞，可以備蔬蔌。", "葵藿及雞冠，可以悅心目。", "橘柚耀金苞，鎗旗資茗粥。"]'),
('89eed122-5199-4488-b66e-f323d0e53504','題江干初雪圖','韓忠彥','宋','宋诗','song-poetry','','[]','諸公當日聚巖廊，半謫南荒半已亡。',32,'全唐诗/poet.song.47000.json','["諸公當日聚巖廊，半謫南荒半已亡。", "唯有紫樞黄閣老，再開圖畫看瀟湘。"]'),
('a16d07da-985d-4956-b0c1-8b1d37d6d6a5','駕幸太學','韓忠彥','宋','宋诗','song-poetry','','[]','恢崇儒教頓生光，天子親來幸上庠。',64,'全唐诗/poet.song.47000.json','["恢崇儒教頓生光，天子親來幸上庠。", "星弁煌煌環帝座，霜袍密密綴周行。", "廟祠稽首尊先聖，書義終篇勸嗣王。", "學道深慚非入室，此辰榮事亦升堂。"]'),
('1312a5c7-e3f5-4dda-8804-c2d5102ac0b0','句','韓忠彥','宋','宋诗','song-poetry','','[]','風開笑頰輕桃艷，雨带啼痕白玉容。',32,'全唐诗/poet.song.47000.json','["風開笑頰輕桃艷，雨带啼痕白玉容。", "蝶舞只疑殘雪壓，月明惟覺異香濃。"]'),
('6e3f8fa9-1ed8-4e3e-8da6-cdb06f981f7b','和蘇子瞻觀百步洪原韵','舒煥','宋','宋诗','song-poetry','','[]','先生何人堪並席，李郭相逢上舟日。',128,'全唐诗/poet.song.47000.json','["先生何人堪並席，李郭相逢上舟日。", "殘霞明滅日脚沈，水面浮空天一色。", "磷磷石若鐵林兵，翻激奔衝精甲白。", "岸頭旌旗簇五馬，一櫓飛艎信東下。", "入夜寒生波浪間，汗衣如逐秋風乾。", "相忘河魚互出沒，得性沙鳥鳴關關。", "委蛇二龍乃神物，游樂諸溪誠爲難。", "築亭種柳恐不暇，天下龍雨須公還。"]'),
('00df2443-dfdc-4e2a-8165-4a9029c93252','苦學涪翁夜過其家戲作','舒煥','宋','宋诗','song-poetry','','[]','先生堂前雪月苦，弟子讀書喧兩廡。',32,'全唐诗/poet.song.47000.json','["先生堂前雪月苦，弟子讀書喧兩廡。", "撞門入室書縱橫，蠟紙燈籠似雲母。"]'),
('e7421c9a-0bda-419a-aee9-d093370e1c5a','送程給事知越州','韓鐸','宋','宋诗','song-poetry','','[]','青瑣身榮故國遥，除書催下紫宸朝。',64,'全唐诗/poet.song.47000.json','["青瑣身榮故國遥，除書催下紫宸朝。", "金籝舊學辭仙殿，玉帳新兵擁使橈。", "閣上雲山圍畫壁，軍中鼓角戰江潮。", "珠璣滿篋群賢什，瓦礫誰收亦謾飄。"]'),
('96307fe2-8e8b-4dfd-902f-b316fe6253dd','句','李承之','宋','宋诗','song-poetry','','[]','珠鞍昔御恩猶在，玉輦親扶事已非。',16,'全唐诗/poet.song.47000.json','["珠鞍昔御恩猶在，玉輦親扶事已非。"]'),
('183414c5-7759-46e1-8d7f-4941d62d4608','登東峰亭','劉琦','宋','宋诗','song-poetry','','[]','凱還幾度宴東峰，新構危亭接梵宮。',64,'全唐诗/poet.song.47000.json','["凱還幾度宴東峰，新構危亭接梵宮。", "勢入青冥橫絕壁，路盤空曲壓高松。", "臨流自笑功名薄，對酒忻逢景色重。", "飄泊却慚歸未得，日斜坐聽暮雲鐘。"]'),
('eb6c0b26-2c17-4d23-a11d-19d2d6ffe67e','題滴水巖','鮮于師中','宋','宋诗','song-poetry','','[]','巖前山溜灑如傾，三峽都無此景清。',64,'全唐诗/poet.song.47000.json','["巖前山溜灑如傾，三峽都無此景清。", "坐對秦宮垂箔影，靜聞鮫室落盤聲。", "好追祓禊蘭亭會，疑到神仙洞府行。", "每羨渝南二千石，頻來幽境駐雙旌。"]'),
('4317910f-a1c4-4f5f-a328-a8f68ab7aac7','送程給事知越州','鍾浚','宋','宋诗','song-poetry','','[]','過鄉晝錦剖符雄，海上蓬萊第一宮。',64,'全唐诗/poet.song.47000.json','["過鄉晝錦剖符雄，海上蓬萊第一宮。", "自古勝遊矜物外，于今藩閫壓江東。", "湖山清賞絕塵境，風月高吟虛訟筩。", "促詔歸來如漢典，出分千里入三公。"]'),
('f0253ed8-e600-4309-af1c-60441fe634c8','絕句','呂希哲','宋','宋诗','song-poetry','','[]','禮儀三百復三千，酬酢天機理必然。',32,'全唐诗/poet.song.47000.json','["禮儀三百復三千，酬酢天機理必然。", "寒即加衣饑即食，孰爲末節孰爲先。"]'),
('89f8d843-5efb-4b33-bc8b-42b4a07ed28d','絕句二首  其一','呂希哲','宋','宋诗','song-poetry','','[]','水晶宮殿玉花零，點綴空槐卧素屏。',32,'全唐诗/poet.song.47000.json','["水晶宮殿玉花零，點綴空槐卧素屏。", "特敕下簾延墨客，不因風雪廢談經。"]'),
('f361eb3a-a36a-45d0-9833-f5710ed0d8d7','絕句二首  其二','呂希哲','宋','宋诗','song-poetry','','[]','强記師承道古先，無窮新意出陳編。',32,'全唐诗/poet.song.47000.json','["强記師承道古先，無窮新意出陳編。", "一言有補天顔動，全勝三軍賀凱還。"]'),
('062b7169-abc2-43a6-b3e1-bce376b64e68','和堯夫打乖吟','呂希哲','宋','宋诗','song-poetry','','[]','先生不是閉關人，高趣逍遥混世塵。',64,'全唐诗/poet.song.47000.json','["先生不是閉關人，高趣逍遥混世塵。", "得志須爲天下雨，放懷聊占洛陽春。", "家無甔石賓常滿，論極錙銖意始新。", "任使終身卧安樂，一毫何費養天真。"]'),
('6ed72576-e842-4e60-a8d1-e8fde616de26','絕句','呂希哲','宋','宋诗','song-poetry','','[]','老讀文書興易闌，須知養病不如閑。',32,'全唐诗/poet.song.47000.json','["老讀文書興易闌，須知養病不如閑。", "行林瓦枕虛堂上，卧看江南雨後山。"]'),
('5e205d0a-30c9-4fef-b7bc-d5415f3b4159','登單州城樓','呂希哲','宋','宋诗','song-poetry','','[]','斷霞孤鶩欲寒天，無復青山礙目前。',32,'全唐诗/poet.song.47000.json','["斷霞孤鶩欲寒天，無復青山礙目前。", "世路崎嶇飽經歷，始知平地是神仙。"]'),
('b54a7043-b68b-4be0-81ed-fd941029e28f','句  其一','呂希哲','宋','宋诗','song-poetry','','[]','將謂清風全掃地，世間今復有盧鴻。',16,'全唐诗/poet.song.47000.json','["將謂清風全掃地，世間今復有盧鴻。"]'),
('81a2b03d-6ec5-4fe1-9868-384733ef14f7','句  其二','呂希哲','宋','宋诗','song-poetry','','[]','他日稍成毛義志，再求師友究淵源。',16,'全唐诗/poet.song.47000.json','["他日稍成毛義志，再求師友究淵源。"]'),
('27ac1c1c-f794-4591-b691-6b3d00290175','句  其三','呂希哲','宋','宋诗','song-poetry','','[]','獨抱遺經唐處士，差强人意漢將軍。',16,'全唐诗/poet.song.47000.json','["獨抱遺經唐處士，差强人意漢將軍。"]'),
('bbcd6876-18f5-4087-ab45-c02615f603c1','句  其四','呂希哲','宋','宋诗','song-poetry','','[]','除却借書沽酒外，更無一事擾公私。',16,'全唐诗/poet.song.47000.json','["除却借書沽酒外，更無一事擾公私。"]'),
('f5c429dc-2e70-452c-b395-02b1e92d759c','寄兄','呂希純','宋','宋诗','song-poetry','','[]','江南江北來，昨夜同枝宿。',24,'全唐诗/poet.song.47000.json','["江南江北來，昨夜同枝宿。", "平明一聲起，回顧已極目。"]'),
('dc3ad9dd-8c98-4536-aa40-c176be956e70','見學院諸生作詩因和','呂希純','宋','宋诗','song-poetry','','[]','騏驥方騰踏，蚊虻敢撲緣。',24,'全唐诗/poet.song.47000.json','["騏驥方騰踏，蚊虻敢撲緣。", "明年小期集，請看十廬鞭。"]'),
('de2865d7-7020-425f-9dd1-2e6dcc4d31bd','詩一首','呂希純','宋','宋诗','song-poetry','','[]','夢寐西山結草廬，逝將臨水詠游魚。',32,'全唐诗/poet.song.47000.json','["夢寐西山結草廬，逝將臨水詠游魚。", "何人見卵求時夜，更著閒言問紫姑。"]'),
('e989189e-ce8a-4c80-aa29-7d2080ab7bf4','千峰榭','呂希純','宋','宋诗','song-poetry','','[]','古郡千山裏，高臺六月凉。',120,'全唐诗/poet.song.47000.json','["古郡千山裏，高臺六月凉。", "開軒背城市，伏檻即林塘。", "白佛當平遠，烏龍插昊蒼。", "水風生枕簟，嵐翠撲衣裳。", "欲雨高峰暗，新晴瀑布長。", "稻塍分錦繡，松嶺奏笙簧。", "自昔多賢守，於今載雅章。", "承流叨繼踵，主諾粗提綱。", "夙樂阿蘭若，端居最上方。", "南津有禪侶，默坐正相望。"]'),
('67986298-0d2f-4c69-844d-fe7363f6b7cc','紫翠樓','呂希純','宋','宋诗','song-poetry','','[]','予臨瀟灑郡，終日坐樓中。',84,'全唐诗/poet.song.47000.json','["予臨瀟灑郡，終日坐樓中。", "樓上闢四門，門開面面風。", "南榮看馬目，北檻對烏龍。", "夕暝瞰兜率，朝霞望高峰。", "峰巒一相望，紫翠千萬重。", "中宵若笙篁，天籟起長松。", "直疑列仙侶，駕鶴相過從。"]'),
('750aa4f0-bf4f-4832-a753-79542fef74ed','趙清獻賞春亭','呂希純','宋','宋诗','song-poetry','','[]','遺直兼遺愛，居今見古人。',48,'全唐诗/poet.song.47000.json','["遺直兼遺愛，居今見古人。", "殿中收白簡，江上擁朱輪。", "棟宇才函丈，琴尊喜對賓。", "繞亭佳水在，長與物爲春。"]'),
('a7e2ca73-04ef-4e81-ae93-c981c076e70b','烏龍寺','呂希純','宋','宋诗','song-poetry','','[]','秀嶺奇峰接釣臺，烏龍直北更崔嵬。',64,'全唐诗/poet.song.47000.json','["秀嶺奇峰接釣臺，烏龍直北更崔嵬。", "萬松合處虛亭敞，千佛光中梵宇開。", "林外瀑泉飛朔雪，雲間寶藏轉春雷。", "攀藤更入西庵路，一聽支郎語劫灰。"]'),
('ae925d49-63eb-4fd2-86a6-935ebee6359a','承天思范軒','呂希純','宋','宋诗','song-poetry','','[]','范公當日守江濱，本是西清獻納臣。',64,'全唐诗/poet.song.47000.json','["范公當日守江濱，本是西清獻納臣。", "瀟灑溪山瀟灑郡，太平天子太平民。", "棠郊遺愛今仍在，竹榭高吟迹已陳。", "還憶開元宋開府，相望彷彿見精神。"]'),
('f7bcfd6d-fdc2-49cf-91b7-6f37f6c8e899','陳尊宿庵','呂希純','宋','宋诗','song-poetry','','[]','尊宿芳名盛，庵巖迹未頹。',48,'全唐诗/poet.song.47000.json','["尊宿芳名盛，庵巖迹未頹。", "織蒲隨日用，儋版喚人回。", "臨濟親推出，雲門手托開。", "于今兩禪派，俱自睦州來。"]'),
('42a1dd09-0c03-4225-a99b-6ab2f0123e06','靈香閣','呂希純','宋','宋诗','song-poetry','','[]','昔聞僧道開，清浄本求佛。',120,'全唐诗/poet.song.47000.json','["昔聞僧道開，清浄本求佛。", "談經悟教藏，施藥蠲衆疾。", "臨嶂起重閣，最上構禪室。", "靈香邈可繼，壯麗固已軼。", "桐廬瀟灑郡，茲閣更奇崛。", "峰巒互掩映，松竹富蒙密。", "我來一伏檻，紫翠競森出。", "塵襟與羈幘，中坐怳已失。", "清風來甚遠，沖氣久彌逸。", "東軒視蟠桃，仙路如彷彿。"]'),
('b3f5b0e3-5621-4b02-86ba-20f60234628e','瀟灑亭','呂希純','宋','宋诗','song-poetry','','[]','郡因賢守得佳名，水態山光會此亭。',64,'全唐诗/poet.song.47000.json','["郡因賢守得佳名，水態山光會此亭。", "雲外僧歸穿竹塢，日邊鷗下集沙汀。", "浮梁倒影橫雌霓，寶塔張燈疊萬星。", "不獨班春行田野，重緣香火叩禪扃。"]'),
('32e217b4-553b-431e-8e54-3c51bd08488a','高峰庵','呂希純','宋','宋诗','song-poetry','','[]','予嘗登高峰，近瞰碧溪塢。',120,'全唐诗/poet.song.47000.json','["予嘗登高峰，近瞰碧溪塢。", "老松如卧龍，夾道忽騰翥。", "危梯過百折，直下看雲雨。", "善導有遺蹤，十佛從口吐。", "歲久缺其三，塵埃誰復數。", "佛壽倘能續，佛像諒可補。", "繞山行道迹，會轉坦無阻。", "中休有磐石，蔽日多林莽。", "安得德山流，來爲此峰主。", "結茅孤頂上，端坐訶佛祖。"]'),
('c5a5a0bc-cd4e-4920-b784-715b53179e09','玉泉庵','呂希純','宋','宋诗','song-poetry','','[]','瀑布巖東轉畫旗，拂雲穿石上霏微。',64,'全唐诗/poet.song.47000.json','["瀑布巖東轉畫旗，拂雲穿石上霏微。", "抱溪修竹通千个，夾道喬松過十圍。", "簷外一潭泓翠碧，窗間萬斛濺珠璣。", "使君不用笙歌擁，潄玉聲中岸幘歸。"]'),
('ee5c4a61-e4f6-4adb-a970-2e4743296b6f','江氏園','呂希純','宋','宋诗','song-poetry','','[]','北渚南津路不遥，鳴騶喜過定川橋。',64,'全唐诗/poet.song.47000.json','["北渚南津路不遥，鳴騶喜過定川橋。", "竹間水榭涵虛碧，林外山堂對泬㵳。", "地占上游真塽塏，門通禪苑離塵囂。", "游人未嘆尋芳歇，石磴山松正後彫。"]'),
('cc06db26-941e-4727-8d0e-73e4df324992','民表圓同庵','呂希純','宋','宋诗','song-poetry','','[]','翠竹庵前久不疑，雨花巖畔更忘機。',32,'全唐诗/poet.song.47000.json','["翠竹庵前久不疑，雨花巖畔更忘機。", "何人得似江居士，在定時多出定稀。"]'),
('f2f68e8d-b886-45af-9141-9e9e06fbc487','定川門','呂希純','宋','宋诗','song-poetry','','[]','江如丁字湊城隈，長畏蛟龍鼓浪來。',64,'全唐诗/poet.song.47000.json','["江如丁字湊城隈，長畏蛟龍鼓浪來。", "門表奠川聊致禱，職當求瘼愧非才。", "兩灘漲定沙痕白，七里山晴霧雨開。", "放出庾家樓上月，却留賓從少徘徊。"]'),
('04f8f810-09b0-4218-b074-6782d01740a9','王氏亭池','呂希純','宋','宋诗','song-poetry','','[]','城外溪山知幾重，獨憐池館占城中。',64,'全唐诗/poet.song.47000.json','["城外溪山知幾重，獨憐池館占城中。", "亭花不動波瀾細，徑石相連島嶼通。", "床下繫舟同醉傅，尊前垂釣似仙翁。", "王家最數烏衣巷，莫廢江南舊士風。"]'),
('8d71fa6c-24d0-4069-bce1-031f7e557f38','朱氏園','呂希純','宋','宋诗','song-poetry','','[]','十里游山興盡回，重留車騎款郊扉。',64,'全唐诗/poet.song.47000.json','["十里游山興盡回，重留車騎款郊扉。", "中橋駕石臨清港，危榭開軒挹翠微。", "夾道松風吹酒面，滿庭花氣襲人衣。", "殷勤更謝華亭鶴，引吭高聲送我歸。"]'),
('b1f1cb28-f80a-4876-b50d-c288ef62c0f5','元夕  其一','呂希純','宋','宋诗','song-poetry','','[]','何處元宵好，迎鑾冊府西。',48,'全唐诗/poet.song.47000.json','["何處元宵好，迎鑾冊府西。", "簫聲雲外起，扇影日邊低。", "秘禁威容肅，名流步武齊。", "舜瞳回左顧，真欲過金閨。"]'),
('6d1b788e-54af-4a91-a43f-9d6d6b241ae8','元夕  其二','呂希純','宋','宋诗','song-poetry','','[]','何處元宵好，雙林宴坐僧。',48,'全唐诗/poet.song.47000.json','["何處元宵好，雙林宴坐僧。", "戒圓三五夜，心耀百千燈。", "茅舍門常掩，繩床几謾憑。", "世間娛樂事，一念不曾興。"]'),
('58e63d65-cc23-4cd0-bd0f-8b5016ad3c1c','句  其一','呂希純','宋','宋诗','song-poetry','','[]','何處孤城號秭歸。',8,'全唐诗/poet.song.47000.json','["何處孤城號秭歸。"]'),
('f9029bf9-0526-4dca-8127-0a866b28bae8','句  其二','呂希純','宋','宋诗','song-poetry','','[]','久矣摳衣闕過庭。',8,'全唐诗/poet.song.47000.json','["久矣摳衣闕過庭。"]'),
('2b500f15-652c-437f-9e42-5abf9d9e51bb','詩一首','賈公望','宋','宋诗','song-poetry','','[]','倏忽向六十，萍蓬無奈何。',48,'全唐诗/poet.song.47000.json','["倏忽向六十，萍蓬無奈何。", "丹心猶奮迅，白首分蹉跎。", "正直士流少，傾邪朋類多。", "陽光一銷鑠，不復見妖魔。"]'),
('2e073713-f92b-4e82-8f18-2bfbab6950fa','送僧歸護國寺','錢景臻','宋','宋诗','song-poetry','','[]','天台多勝概，落日亂山青。',24,'全唐诗/poet.song.47000.json','["天台多勝概，落日亂山青。", "不似三峰好，樓臺入翠屏。"]'),
('cd5cdb14-9fbd-4b9a-bb73-7addcbb35a87','公堂置酒羣彥咸集作詩呈學中諸先輩且用敘別','朱長文','宋','宋诗','song-poetry','','[]','漢有郡文學，儒宮所宗師。',288,'全唐诗/poet.song.47000.json','["漢有郡文學，儒宮所宗師。", "稚圭雖嘆滯，鄧禹猶願爲。", "聖朝興庠序，內外振新規。", "嗟余介且拙，性與丘壑宜。", "青衫起泮水，六見開辛夷。", "經術聊辨惑，文章非振奇。", "羣英何濟濟，屈就董生帷。", "講習良可樂，斆學交相資。", "但觀芹藻長，不卹顔鬢衰。", "忽傳太學命，飛詔下天涯。", "自省草茅賤，豈稱廊廟知。", "親友頗敦迫，黽勉趨官期。", "生平好古心，或冀伸此時。", "偶茲春奠畢，將與諸生辭。", "濁酒多如澠，頒貺自守麾。", "鄉飲久不講，禮意猶可追。", "高閣矗丹檻，公堂煥雲楣。", "裒衣二百衆，齒髮敘尊卑。", "籩豆儼在列，鵷鴻來有儀。", "珍饔薦瑶觴，雖醉尚肅祗。", "式燕固云喜，有行尤愴離。", "勉旃重勉旃，脩業戒荒嬉。", "黼繡在德義，金玉惟書詩。", "豫章生拱把，羣木共葳蕤。"]'),
('13d10eb4-c82d-4091-973d-34997e65e416','佳雨應祈因思昔年諸友作詩今再敘舊','朱長文','宋','宋诗','song-poetry','','[]','晏侯昔爲州，歲旱慶霖雨。',288,'全唐诗/poet.song.47000.json','["晏侯昔爲州，歲旱慶霖雨。", "夫君與方子，吟思共清苦。", "不才輒繼聲，玉石愧同處。", "賡酬自邦君，高歌遍幕府。", "開編讀英辭，風義恨修阻。", "歷年屈指八，閱守今已五。", "溫溫劉蘇州，揚仁美風土。", "篇章極清新，操行到淳古。", "去年掌膠庠，幸此廕德宇。", "遇君來自西，暫作皋橋旅。", "並游盍簪裾，良宴陪樽俎。", "辱顧眼俱青，言詩多見與。", "近當庚伏間，不雨病禾黍。", "田乾如龜裂，一溉勞遠取。", "如惔沴氣生，望歲羣心沮。", "園居雖閒曠，何處逃藴暑。", "使君憂憫深，雩祀以時舉。", "精誠禱祠下，若與神告語。", "隨車油雲飛，闔境膏澤溥。", "槁苗興膴原，涸轍通別浦。", "萬輪水可汲，千笠草務去。", "秈禾與稏稻，指期入我庾。", "清暉登溪山，餘潤滿林圃。", "中吳垂白叟，買酒相抃舞。"]'),
('5410daf7-bbd8-4e70-811b-b6cf2f177be3','次韵送毛正仲太博赴召','朱長文','宋','宋诗','song-poetry','','[]','馬周起布衣，一日見紫宸。',276,'全唐诗/poet.song.47000.json','["馬周起布衣，一日見紫宸。", "獻言中機會，數歲持衡鈞。", "嘆息慕前哲，誰能繼清塵。", "毛公東南美，迥掩竹箭珍。", "高才與精識，卓爾出天真。", "論政明得失，談兵到幾神。", "天戈討梅山，婉畫昔已伸。", "一官遇賢守，相與康吳民。", "孰云芙蓉幕，久卧五色麟。", "聖君馭羣材，功業圖日新。", "旌麾頗牧用，帷幄良平臻。", "奇士求即至，當世有偉人。", "君今赴明詔，亨會在此辰。", "夕發碧江外，秋過清汴津。", "彤庭敞神麗，文陛高嶙峋。", "良籌上意合，深策廟謨親。", "功名立少壯，富貴將迫身。", "我亦有志者，卧疾松陵濱。", "耰鋤代長鋏，韋带比華紳。", "高懷未遐棄，荒徑枉朱輪。", "纚纚聽君語，懦夫氣益振。", "病騮觀逸驥，舉首嘶鳴頻。", "尚期居要路，迴光及幽淪。"]'),
('59380549-afbd-41fc-8488-5bf9a6ff8372','轉運少卿生日','朱長文','宋','宋诗','song-poetry','','[]','昔在章聖朝，先君爲名臣。',276,'全唐诗/poet.song.47000.json','["昔在章聖朝，先君爲名臣。", "入陪儒林老，出擁使者輪。", "忠謨與休烈，萬世永不泯。", "惜哉未大任，天意昌後人。", "公生韞俊德，磊落幼絕倫。", "深林有條梅，不揉自可珍。", "外隅正以方，中府粹且仁。", "沛然施之事，迅若般之斤。", "自聯金閨彥，頡頏三十春。", "牙籌析經費，龍節綏遠民。", "朅來天畿東，威譽薄海垠。", "羣情無遁照，衆理日益勤。", "吏徑皆敞闢，敝根悉鋤耘。", "惸惸舊鰥寡，今也皆不貧。", "闔部數百城，膏澤一以均。", "正月方再浹，是日爲生申。", "東人競祝公，百福叢于身。", "同宗復荷德，善禱久所陳。", "况公方耆艾，百行享明神。", "俾公永且康，筆端扶化鈞。", "俾公熾而大，膝下森華紳。", "近得舉之躅，前望伯虎塵。", "先閥期益顯，蹇品庶可親。"]'),
('6ac0b175-aedc-4f59-bc74-1211e4bea325','送魏君致遠之吳興兼寄祝修中','朱長文','宋','宋诗','song-poetry','','[]','庠中今多材，燦若荆岫玉。',168,'全唐诗/poet.song.47000.json','["庠中今多材，燦若荆岫玉。", "琢磨觀粹美，尤愛魏與祝。", "二子幼相友，共學橫山麓。", "抱書來泮宮，美質異碌碌。", "文辭堪適用，光瑩輕縑幅。", "前年掇高選，麗賦人爭錄。", "吳興太守賢，好善下白屋。", "貽書勤聘禮，掃榻待英躅。", "伯樂過冀北，所顧皆驥騄。", "翩翩告別去，舟泛苕溪淥。", "南陔急親養，聊以奉水菽。", "愧我不能留，嗈嗈想鴻鵠。", "良辰振六翮，一舉聳羣目。", "雲漢期高翔，稻粱非所欲。"]'),
('ef797801-90c4-4549-98dd-f483063ef0f9','少章過吳門寵示淳夫子瞻唱和并惠山寄少游之什俾余繼作輒次二公韵以寄之','朱長文','宋','宋诗','song-poetry','','[]','懷友對華月，身如匏繫何。',168,'全唐诗/poet.song.47000.json','["懷友對華月，身如匏繫何。", "遥聆金玉音，悵望江湖波。", "憂來誦三篇，調饑餉嘉禾。", "蘇范天下賢，閱士歲月多。", "憐君似蘭芷，長育瑶山阿。", "良工得寶璧，韞櫝加琢磨。", "發爲驚人語，九曲傾洪河。", "蟠蜿寄短章，浩蕩寫長歌。", "一官得武林，萬景盡包羅。", "又如彈響泉，餘韵清且和。", "籍湜師韓文，其則在伐柯。", "俯視枳棘間，翔鸞豈蹉跎。", "聖朝頌聲作，周雝與商那。", "二公且大用，豈得歸岷沱。"]'),
('867d1aa8-3396-4abd-ab2c-c4e827a3541e','詠齋偶書呈子通無隠','朱長文','宋','宋诗','song-poetry','','[]','夙志在蕭閒，獲此遁幽迹。',120,'全唐诗/poet.song.47000.json','["夙志在蕭閒，獲此遁幽迹。", "喬林無冬春，蒼靄異晨夕。", "旁窺疑好峰，俯瞰驚峭壁。", "浩然溪山興，盡在陶潛宅。", "杖藜行水邊，萍際湛空碧。", "良魚不輕游，弱羽猶自惜。", "吟髭不禁霜，曉鑑見早白。", "古人已深嘆，信是林園客。", "遣累假禪鋒，陶情任詩格。", "寄聲招友人，來看亭前柏。"]'),
('d416308c-bc22-42dc-8243-dd5c2c05bd59','次韵李子功留別之作','朱長文','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','采蘭無復養，嬰此終天悲。',120,'全唐诗/poet.song.47000.json','["采蘭無復養，嬰此終天悲。", "家空弱妹長，恐失桃夭時。", "翠蔓倚長松，之子得所隨。", "銜杯款相遇，摻袂傷暫離。", "洞庭春風高，楊柳綠江湄。", "柴門歸獨掩，桂楫暮何之。", "眷眷厚有餘，佳什猶在茲。", "散帙渴精論，言詩佇良規。", "惜哉片帆去，快若駟馬馳。", "東皋多樂事，歸計勿遲遲。"]'),
('8914433f-84de-4537-91b9-347e2d2b4abb','謝虎丘祖印相訪','朱長文','宋','宋诗','song-poetry','','[]','支嶺高風遠，杼山佳句稀。',96,'全唐诗/poet.song.47000.json','["支嶺高風遠，杼山佳句稀。", "雲巖有開士，詩理到精微。", "不知蓬戶隘，未倦凎鐶飛。", "忘形任談笑，敷衽評是非。", "近師宣城老，遠慕蘇州韋。", "我亦有吟癖，古人思與歸。", "願聞碧雲篇，所得如珠璣。", "漁樵未晚出，乘興叩禪扉。"]'),
('b18aedf6-b599-4ede-87be-32af636179c4','謁郭道沖唐師德登臺偶作','朱長文','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','衝寒步郊原，煙水照林薄。',96,'全唐诗/poet.song.47000.json','["衝寒步郊原，煙水照林薄。", "雪餘山色佳，浦浚湖波落。", "靜可釣綸垂，清欲塵纓濯。", "相逢兩俊友，辭義富金臒。", "携手登高臺，談笑有真樂。", "寸眸周遠近，幽思騰寥廓。", "逝將飛片帆，直泛洞庭脚。", "縶維阻並遊，搔首向城郭。"]'),
('39733dcd-b1a8-4f2e-b4de-545cd118f94b','春秋終講伏蒙知府諫議臨視學舍宴勞諸生謹成小詩敘謝','朱長文','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山先生久冥寞，世把春秋束高閣。',320,'全唐诗/poet.song.47000.json','["泰山先生久冥寞，世把春秋束高閣。", "腐儒退隠三十年，獨玩遺經思筆削。", "濫居師席愧匪才，日演微言更歲籥。", "欲遵廣路視堂奧，誓闢浮雲窺碧落。", "茲辰講解告終篇，敢屈邦君親視學。", "邦君舊是補衮才，忠論嘉謨動宸幄。", "密爲福澤遍寰瀛，暫得麾符出京洛。", "愛民如子不忍傷，政用中和屏威虐。", "深惟教本在庠序，力助儒風止姦惡。", "羣材儻得就長育，百堵何爲憚興作。", "躭躭黌舍盡修嚴，翼翼公堂驟清廓。", "已欣華構將落成，肯枉雙旌率僚幕。", "清晨初謁二公祠，重道嚴師致恭恪。", "更忘煩暑臨講席，自降威容聽揚搉。", "羜肥酒釃宴諸生，金印煌煌對褒博。", "傳聞長幼相告語，爭誦詩書親教約。", "歡聲四出屏陰沴，雲霧俄收日華爍。", "文翁化蜀士皆成，魯侯修泮民思樂。", "自慚傳道竟何補，祿食充饑免藜藿。", "幸逢賢守善承流，喜與吳人醉優渥。"]'),
('e4b64b14-9289-43ed-82d0-cc00e8339f8c','雪夕林亭小酌因成拙詩四十韵以貽坐客昔歐陽公與人詠雪先戒勿用梨梅練絮白舞鵝鶴等字今篇中輒守此戒但愧不工伏惟采覽','朱長文','宋','宋诗','song-poetry','','[]','極望鋪千頃，平觀徹九霄。',288,'全唐诗/poet.song.47000.json','["極望鋪千頃，平觀徹九霄。", "縱橫隨物象，合散委天飆。", "灑竹聲微動，粧松勢不摇。", "庭空飛鳥影，窗失遠山椒。", "釣罷盈孤嶼，行稀覆小橋。", "爭先籠碧瓦，騁巧綴柔條。", "片片誰裁製，團團似琢琱。", "丘陵平坎險，草木起枯焦。", "皎潔那容染，輕清祗自飄。", "匊來便幼稚，披去羨漁樵。", "篷冷孤舟泊，蹄輕逸驥驕。", "危樓明皓皓，虛室靜蕭蕭。", "餘霰霏殘夜，層冰結霽朝。", "界疑華藏見，境入洞天遥。", "嚮晦終難掩，居高却晚銷。", "潤滋甘井脈，寒減暮江潮。", "思婦啼紅袖，征夫擁皂貂。", "履穿愁踐足，心悟任齊腰。", "就映猶開卷，頻餐愈病痟。", "袁公當强起，謝女尚能謠。", "旋取茶鐺泛，多收藥匕調。", "任令埋蠟屐，直欲鼓蘭橈。", "掃處迷三徑，吟餘凍一瓢。", "因思良友至，急奔牧童邀。"]'),
('9cc45c3d-3513-4281-aa4d-62c3e314a272','仲春上丁知府金部躬率僚寀釋奠于先聖既而升公堂命學官講書竊惟中庸之篇自安定先生常以是誨人閱歲既久嗣音者希某孤陋無似竊慕前哲其啟講也今龍閣黄公嘗臨之其終講也金部使君又臨之郡儒在列咸與榮觀輒成五言律詩二十韵敘謝','朱長文','宋','宋诗','song-poetry','','[]','天意紹斯文，成書在聖孫。',240,'全唐诗/poet.song.47000.json','["天意紹斯文，成書在聖孫。", "一篇窮妙理，萬古誦微言。", "美行敷華葉，精誠固本根。", "並明參日月，幽贊極乾坤。", "奧義誰鑽仰，真儒善討論。", "披雲觀泰華，行水自崑崙。", "庠序非才處，詩書素志敦。", "崇朝羞倚席，暇日廢窺園。", "辨惑開羣聽，潛心到大原。", "意將追往哲，學豈爲專門。", "盛府連稱治，耆英繼典藩。", "始終臨講席，前後枉高軒。", "全帳羅金鼎，盈庭倒玉樽。", "旌旗來有慶，衿佩寂無喧。", "士識師資貴，民知道義尊。", "僖公史官頌，鄭校相君存。", "芹藻歡欣意，陵阿長育恩。", "中材多杞梓，寶器列瑶琨。", "五紀登朝盛，羣英著籍繁。", "美哉文正學，遺澤洽元元。"]'),
('14e85229-d44b-4fbb-a55e-a8c050d258eb','奉送中散使君提舉崇禧觀','朱長文','宋','宋诗','song-poetry','','[]','方面威名久，朝端聞望隆。',240,'全唐诗/poet.song.47000.json','["方面威名久，朝端聞望隆。", "需章祈玉陛，寶詔與琳宮。", "睿奬均勞逸，高情保始終。", "他年黄髮老，清世紫芝翁。", "迹放風波外，心安夢幻中。", "身輕隨壽鶴，目極送冥鴻。", "祖帳羣公集，啼嬰萬俗同。", "何緣留召父，無路達堯聰。", "誇里金龜重，榮先密印崇。", "高堂羅俎豆，幽徑鏟蒿蓬。", "趁健歌歸去，因閑味道沖。", "謝庭常有慶，越橐任令空。", "醉帽欹華月，吟髭動好風。", "翠虬喬木老，錦障海棠紅。", "平昔高軒過，深嗟陋巷窮。", "噓枯言不絕，推轂賜嘗蒙。", "載酒要彭澤，名鄉表鄭公。", "量材如斷木，荷德重維崧。", "耆俊方圖任，明廷正納忠。", "劇藩如擇將，猶恐起宗工。"]'),
('15925302-ecdb-4bd2-b711-0d5a6a876ee3','光祿生日','朱長文','宋','宋诗','song-poetry','','[]','卿寺方森棘，侯邦屢建旂。',120,'全唐诗/poet.song.47000.json','["卿寺方森棘，侯邦屢建旂。", "才鋒周物理，智燭見神機。", "壽遠眉毫秀，身康鬢雪稀。", "翠筠高挺節，古柏暗增圍。", "雲陛朝升對，銅符夕佩歸。", "灌苗潛致茂，針瘼坐令肥。", "召杜名方重，松喬志所希。", "非才學詩禮，多幸奉庭闈。", "葉載神龜穩，雛隨彩鳳飛。", "晨昏趨膝下，永着老萊衣。"]'),
('e45cad9e-cab8-4e76-bb4d-3e966f96a073','送知府滕光祿','朱長文','宋','宋诗','song-poetry','','[]','榜登龍虎亞倫魁，一紀橫飛長憲臺。',160,'全唐诗/poet.song.47000.json','["榜登龍虎亞倫魁，一紀橫飛長憲臺。", "謨議軒昂開日月，辭章雄偉鼓風雷。", "朝端已慶明良會，廟論咸推將相才。", "一跌雲衢成老大，幾遷方面嘆邅迴。", "致君事業看霜鬢，經國風猷付玉杯。", "驅弩屢驚園令出，引章還喜買臣來。", "展墳乍覺青松長，視學追懷絳帳開。", "榮滿江山增氣象，仁霑里閈舞兒鮐。", "齊雲晚詠難留白，綠野新居欲繼裴。", "淮海巨藩雖重寄，傅巖須起作鹽梅。"]'),
('64d2d627-4827-47fd-bf77-2b9493ac7d26','喜雪上太守','朱長文','宋','宋诗','song-poetry','','[]','築壇精禱意通神，零雨先期澤此民。',160,'全唐诗/poet.song.47000.json','["築壇精禱意通神，零雨先期澤此民。", "驟作六花猶及臘，更遲一日即回春。", "斜飄燕寢初驚密，平壓高樓漸喜勻。", "千里山河忘險穢，十門坊市絕埃塵。", "謝庭賀燕凌晨集，郢曲歌聲遇景新。", "細入吟窗粘凍筆，輕隨舞袖落花茵。", "膠舟漸進危檣遠，汲井彌甘短綆伸。", "遍壅枯根蘇杞柳，巧粧寒葉活松筠。", "終朝訟息延佳客，幾度年豐達紫宸。", "力可回天消旱暵，爲霖豈獨傅巖人。"]'),
('6e9fbd54-81af-4633-a7b5-b4b97f163db8','上運使陳兵部','朱長文','宋','宋诗','song-poetry','','[]','屈指西州當世英，我公傑出久知名。',160,'全唐诗/poet.song.47000.json','["屈指西州當世英，我公傑出久知名。", "自從揚馬奇才後，又得岷峨靈氣清。", "剛者近仁今始見，惠而能政古難并。", "胸羅萬象縱橫有，目悅羣情黑白明。", "已借牙籌安右輔，尚留金節壓東瀛。", "片章馳上雲霄動，一檄飛前草木驚。", "斷割劇繁如簡易，針砭瘦瘠使豐盈。", "此時阜俗資良策，匪夕疇庸在老成。", "竊愧衰姿毗太府，幸逢雅量庇寒生。", "欲祈陰施增仙算，幾見蟠桃結子榮。"]');
